import type { Verse } from '../types';

// Capítulos reais deste livro. Segue o mesmo formato de src/bible/genesis.ts:
// { n: <capítulo>: [ { n: <versículo>, text: '<texto>' }, ... ] }
export const NUMBERS_CHAPTERS: Record<number, Verse[]> = {
  1: [
    { n: 1, text: 'Yehovha a vulavula na Moxe emananga ya Sinayi, etabernakeleni ya nhlanganiso, hi siku ro sungula ra n’weti wa vumbirhi, hi lembe ra vumbirhi endzhaku ka ku huma ka vona etikweni ra Egipta, a ku:' },
    { n: 2, text: '“Tekani ntsengo wa nhlengeletano hinkwayo ya vana va Israyele, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, xinuna hinkwaxo hi ku landza tinhloko ta vona;”' },
    { n: 3, text: '“Ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini eIsrayele; wena na Aroni mi ta va hlayela hi ku landza mavandla ya vona.”' },
    { n: 4, text: '“Ku ta va na n’wina wanuna un’we wa nyimba yin’wana ni yin’wana; un’wana ni un’wana a ri nhloko ya yindlu ya vatata wa yena.”' },
    { n: 5, text: '“Lawa hi wona mavito ya vavanuna lava nga ta yima na n’wina: Eka Ruveni: Elizuru, n’wana wa Xedeyure;”' },
    { n: 6, text: '“Eka Ximeyoni: Xelumiyele, n’wana wa Zurixadayi;”' },
    { n: 7, text: '“Eka Yuda: Naxoni, n’wana wa Aminadaba;”' },
    { n: 8, text: '“Eka Isakara: Netanele, n’wana wa Zuara;”' },
    { n: 9, text: '“Eka Zebuloni: Eliyabu, n’wana wa Heloni;”' },
    { n: 10, text: '“Eka vana va Yosefa: eka Efrayimi: Elixama, n’wana wa Amihudu; eka Manase: Gamaliyele, n’wana wa Pedasuri;”' },
    { n: 11, text: '“Eka Benjamini: Abidani, n’wana wa Gideyoni;”' },
    { n: 12, text: '“Eka Dani: Ahiyezeri, n’wana wa Amixadayi;”' },
    { n: 13, text: '“Eka Axere: Pagiyele, n’wana wa Okrani;”' },
    { n: 14, text: '“Eka Gadi: Eliyasafu, n’wana wa Dewele;”' },
    { n: 15, text: '“Eka Naftali: Ahira, n’wana wa Enani.”' },
    { n: 16, text: '“Lava hi vona lava vitaniweke va nhlengeletano, varhangeri va tinyimba ta vatata wa vona; a va ri tinhloko ta magidi ya Israyele.”' },
    { n: 17, text: 'Moxe na Aroni va teka vavanuna lava, lava vitaniweke hi mavito;' },
    { n: 18, text: 'Va hlengeleta nhlengeletano hinkwayo hi siku ro sungula ra n’weti wa vumbirhi, naswona va tsarisa tinxaka ta vona hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hi ku landza tinhloko ta vona.' },
    { n: 19, text: 'Hilaha Yehovha a leriseke Moxe hakona, u va hlayele emananga ya Sinayi.' },
    { n: 20, text: 'Vana va Ruveni, mativula ya Israyele, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, hi ku landza tinhloko ta vona, xinuna hinkwaxo ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 21, text: 'Lava hlayiweke va nyimba ya Ruveni a va ri makhume ya mune ni tsevu wa magidi ni ntlhanu wa madzana.' },
    { n: 22, text: 'Eka vana va Ximeyoni, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, lava hlayiweke va vona, hi ku landza nhlayo ya mavito, hi ku landza tinhloko ta vona, xinuna hinkwaxo ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 23, text: 'Lava hlayiweke va nyimba ya Ximeyoni a va ri makhume ya ntlhanu na kaye wa magidi ni nharhu wa madzana.' },
    { n: 24, text: 'Eka vana va Gadi, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 25, text: 'Lava hlayiweke va nyimba ya Gadi a va ri makhume ya mune ni ntlhanu wa magidi ni tsevu wa madzana ni makhume ya ntlhanu.' },
    { n: 26, text: 'Eka vana va Yuda, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 27, text: 'Lava hlayiweke va nyimba ya Yuda a va ri makhume ya ntlhanu na timbirhi makhume ya ntlhanu na ntsandza wa magidi ni mune wa madzana. (Makhume nkombo na mune wa magidi ni tsevu wa madzana).' },
    { n: 28, text: 'Eka vana va Isakara, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 29, text: 'Lava hlayiweke va nyimba ya Isakara a va ri makhume ya ntlhanu na mune wa magidi ni mune wa madzana.' },
    { n: 30, text: 'Eka vana va Zebuloni, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 31, text: 'Lava hlayiweke va nyimba ya Zebuloni a va ri makhume ya ntlhanu na nkombo wa magidi ni mune wa madzana.' },
    { n: 32, text: 'Eka vana va Yosefa: eka vana va Efrayimi, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 33, text: 'Lava hlayiweke va nyimba ya Efrayimi a va ri makhume ya mune wa magidi ni ntlhanu wa madzana.' },
    { n: 34, text: 'Eka vana va Manase, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 35, text: 'Lava hlayiweke va nyimba ya Manase a va ri makhume manharhu na timbirhi wa magidi ni mazana mambirhi.' },
    { n: 36, text: 'Eka vana va Benjamini, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 37, text: 'Lava hlayiweke va nyimba ya Benjamini a va ri makhume manharhu ni ntlhanu wa magidi ni mune wa madzana.' },
    { n: 38, text: 'Eka vana va Dani, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 39, text: 'Lava hlayiweke va nyimba ya Dani a va ri makhume ya tsevu na timbirhi wa magidi ni nkombo wa madzana.' },
    { n: 40, text: 'Eka vana va Axere, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 41, text: 'Lava hlayiweke va nyimba ya Axere a va ri makhume ya mune ni xin’we wa magidi ni ntlhanu wa madzana.' },
    { n: 42, text: 'Eka vana va Naftali, tinxaka ta vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona, hi ku landza nhlayo ya mavito, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini;' },
    { n: 43, text: 'Lava hlayiweke va nyimba ya Naftali a va ri makhume ya ntlhanu na nharhu wa magidi ni mune wa madzana.' },
    { n: 44, text: 'Lava hi vona lava hlayiweke, lava Moxe na Aroni va va hlayeke, va ri na varhangeri va Israyele, vavanuna va khume na vambirhi; un’wana ni un’wana a a yimela yindlu ya vatata wa yena.' },
    { n: 45, text: 'Hinkwavo lava hlayiweke va vana va Israyele, hi ku landza tiyindlu ta vatata wa vona, ku sukela eka lava nga ni malembe ya makume mambirhi na ku tlhandlaka, hinkwavo lava nga kotaka ku ya enyimpini eIsrayele;' },
    { n: 46, text: 'Hinkwavo lava hlayiweke a va ri tsevu wa madzana ni nharhu wa magidi ni ntlhanu wa madzana ni makhume ya ntlhanu.' },
    { n: 47, text: 'Kambe Valevi, hi ku landza nyimba ya vatata wa vona, a va hlayiwanga exikarhi ka vona.' },
    { n: 48, text: 'Hikuva Yehovha a a vulavurile na Moxe, a ku:' },
    { n: 49, text: '“Ntsena nyimba ya Levi u nga yi hlayi, naswona u nga teki ntsengo wa vona exikarhi ka vana va Israyele;”' },
    { n: 50, text: '“Kambe wena veka Valevi ehenhla ka tabernakela ya vumbhoni, ni le henhla ka swibya hinkwaswo swa yona, ni le henhla ka hinkwaswo leswi nga swa yona; va ta rhwala tabernakela ni swibya hinkwaswo swa yona, va ta yi tirhela, naswona va ta dzima kampa kusuhi ni tabernakela.”' },
    { n: 51, text: '“Loko tabernakela yi famba, Valevi va ta yi pshatla; naswona loko tabernakela yi fanele ku dzimiwa, Valevi va ta yi dzima; muhlaluhi loyi a tshinelelaka kusuhi u ta dlayiwa.”' },
    { n: 52, text: '“Vana va Israyele va ta dzima mitenda ya vona, un’wana ni un’wana ekampeni ya yena, naswona un’wana ni un’wana kusuhi ni mujeko wa yena, hi ku landza mavandla ya vona.”' },
    { n: 53, text: '“Kambe Valevi va ta dzima kampa va rhendzela tabernakela ya vumbhoni, leswaku ku nga vi na vukarhi eka nhlengeletano ya vana va Israyele; naswona Valevi va ta hlayisa tabernakela ya vumbhoni.”' },
    { n: 54, text: 'Vana va Israyele va endla hilaha Yehovha a leriseke Moxe hakona; va endla tano hi ku helela.' }
  ],
  2: [
    { n: 1, text: 'Yehovha a vulavula na Moxe na Aroni, a ku:' },
    { n: 2, text: '“Vana va Israyele va ta dzima mitenda ya vona, un’wana ni un’wana kusuhi ni mujeko wa yena, kusuhi ni mimfungo ya tiyindlu ta vatata wa vona; va ta dzima va langutana ni tabernakela ya nhlanganiso ematlhelo hinkwawo.”' },
    { n: 3, text: '“Lava nga ta dzima etlhelweni ra le vuxeni, ku ya hi ku huma ka dyambu, i va kampa ya Yuda, hi ku landza mavandla ya vona; murhangeri wa vana va Yuda i Naxoni, n’wana wa Aminadaba.”' },
    { n: 4, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume nkombo na mune wa magidi ni tsevu wa madzana.”' },
    { n: 5, text: '“Lava nga ta dzima kusuhi na yena i nyimba ya Isakara; murhangeri wa vana va Isakara i Netanele, n’wana wa Zuara.”' },
    { n: 6, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya ntlhanu na mune wa magidi ni mune wa madzana.”' },
    { n: 7, text: '“Kusuhi na vona ku ta va nyimba ya Zebuloni; murhangeri wa vana va Zebuloni i Eliyabu, n’wana wa Heloni.”' },
    { n: 8, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya ntlhanu na nkombo wa magidi ni mune wa madzana.”' },
    { n: 9, text: '“Hinkwavo lava hlayiweke va kampa ya Yuda, hi ku landza mavandla ya vona, a va ri dzana ni makhume ya nhungu ni tsevu wa magidi ni tsevu wa madzana. Lava hi vona va nga ta rhangela emahlweni eku fambeni.”' },
    { n: 10, text: '“Etlhelweni ra le dzongeni ku ta va ni mujeko wa kampa ya Ruveni, hi ku landza mavandla ya vona; murhangeri wa vana va Ruveni i Elizuru, n’wana wa Xedeyure.”' },
    { n: 11, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya mune ni tsevu wa magidi ni ntlhanu wa madzana.”' },
    { n: 12, text: '“Lava nga ta dzima kusuhi na yena i nyimba ya Ximeyoni; murhangeri wa vana va Ximeyoni i Xelumiyele, n’wana wa Zurixadayi.”' },
    { n: 13, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya ntlhanu na kaye wa magidi ni nharhu wa madzana.”' },
    { n: 14, text: '“Kusuhi na vona ku ta va nyimba ya Gadi; murhangeri wa vana va Gadi i Eliyasafu, n’wana wa Rewele.”' },
    { n: 15, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya mune ni ntlhanu wa magidi ni tsevu wa madzana ni makhume ya ntlhanu.”' },
    { n: 16, text: '“Hinkwavo lava hlayiweke va kampa ya Ruveni, hi ku landza mavandla ya vona, a va ri dzana ni makhume ya ntlhanu na xin’we wa magidi ni mune wa madzana ni makhume ya ntlhanu. Va ta famba hi ku va va vumbirhi.”' },
    { n: 17, text: '“Endzhaku ka sweswo tabernakela ya nhlanganiso yi ta famba, kampa ya Valevi yi ri exikarhi ka tikampa hinkwato; hilaha va dzimaka hakona mitenda, hi leriya ndlela leyi va nga ta famba ha yona, un’wana ni un’wana endhawini ya yena, hi ku landza mijeko ya vona.”' },
    { n: 18, text: '“Etlhelweni ra le vupela-dyambu ku ta va ni mujeko wa kampa ya Efrayimi, hi ku landza mavandla ya vona; murhangeri wa vana va Efrayimi i Elixama, n’wana wa Amihudu.”' },
    { n: 19, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya mune wa magidi ni ntlhanu wa madzana.”' },
    { n: 20, text: '“Kusuhi na yena ku ta va nyimba ya Manase; murhangeri wa vana va Manase i Gamaliyele, n’wana wa Pedasuri.”' },
    { n: 21, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume manharhu na timbirhi wa magidi ni madzana mambirhi.”' },
    { n: 22, text: '“Kusuhi na vona ku ta va nyimba ya Benjamini; murhangeri wa vana va Benjamini i Abidani, n’wana wa Gideyoni.”' },
    { n: 23, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume manharhu ni ntlhanu wa magidi ni mune wa madzana.”' },
    { n: 24, text: '“Hinkwavo lava hlayiweke va kampa ya Efrayimi, hi ku landza mavandla ya vona, a va ri dzana ni nhungu wa magidi ni dzana rin’we. Va ta famba hi ku va va vunharhu.”' },
    { n: 25, text: '“Etlhelweni ra n’walungu ku ta va ni mujeko wa kampa ya Dani, hi ku landza mavandla ya vona; murhangeri wa vana va Dani i Ahiyezeri, n’wana wa Amixadayi.”' },
    { n: 26, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya tsevu na timbirhi wa magidi ni nkombo wa madzana.”' },
    { n: 27, text: '“Lava nga ta dzima kusuhi na yena i nyimba ya Axere; murhangeri wa vana va Axere i Pagiyele, n’wana wa Okrani.”' },
    { n: 28, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya mune na xin’we wa magidi ni ntlhanu wa madzana.”' },
    { n: 29, text: '“Kusuhi na vona ku ta va nyimba ya Naftali; murhangeri wa vana va Naftali i Ahira, n’wana wa Enani.”' },
    { n: 30, text: '“Vandla ra yena, na lava hlayiweke va vona, a va ri makhume ya ntlhanu na nharhu wa magidi ni mune wa madzana.”' },
    { n: 31, text: '“Hinkwavo lava hlayiweke va kampa ya Dani a va ri dzana ni makhume ya ntlhanu na nkombo wa magidi ni tsevu wa madzana. Va ta famba endzhaku ku landza mijeko ya vona.”' },
    { n: 32, text: '“Lava hi vona lava hlayiweke va vana va Israyele, hi ku landza tiyindlu ta vatata wa vona; hinkwavo lava hlayiweke va tikampa, hi ku landza mavandla ya vona, a va ri tsevu wa madzana ni nharhu wa magidi ni ntlhanu wa madzana ni makhume ya ntlhanu.”' },
    { n: 33, text: '“Kambe Valevi a va hlayiwanga exikarhi ka vana va Israyele, hilaha Yehovha a leriseke Moxe hakona.”' },
    { n: 34, text: '“Vana va Israyele va endla hilaha Yehovha a leriseke Moxe hakona; va dzima mitenda hi ku landza mijeko ya vona, naswona va famba un’wana ni un’wana hi ku landza ndyangu wa yena, hi ku landza yindlu ya vatata wa yena.”' }
  ],
  3: [
    { n: 1, text: 'Loyi i ntsengo wa tinxaka ta Aroni na Moxe, hi siku leri Yehovha a vulavuleke na Moxe entshaveni ya Sinayi.' },
    { n: 2, text: 'Mavito ya vana va Aroni hi lawa: Nadabi, loyi a nga mativula, na Abihu, na Eliyazara, na Itamara.' },
    { n: 3, text: 'Lawa hi wona mavito ya vana va Aroni, vaprista lava totiweke, lava hlawuriweke ku tirha ntirho wa vuprista.' },
    { n: 4, text: 'Kambe Nadabi na Abihu va fela mahlweni ka Yehovha, loko va nyikela ndzilo lowu nga riki wa nchumu mahlweni ka Yehovha emananga ya Sinayi, naswona a va nga ri na vana; Eliyazara na Itamara va tirha ntirho wa vuprista mahlweni ka Aroni, tata wa vona.' },
    { n: 5, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 6, text: '“Tisa nyimba ya Levi, u va yisa mahlweni ka Aroni muprista, leswaku va n’wi tirhela.”' },
    { n: 7, text: '“Va ta hlayisa mintirho ya yena, ni mintirho ya nhlengeletano hinkwayo mahlweni ka tabernakela ya nhlanganiso, va tirha ntirho wa tabernakela;”' },
    { n: 8, text: '“Va ta hlayisa swibya hinkwaswo swa tabernakela ya nhlanganiso, ni ku hlayisa mintirho ya vana va Israyele, va endla ntirho wa tabernakela.”' },
    { n: 9, text: '“U ta nyika Valevi eka Aroni ni le ka vana va yena; va nyikiwe yena hi ku helela ku suka eka vana va Israyele.”' },
    { n: 10, text: '“Wena u ta veka Aroni ni vana va yena, va ta hlayisa vuprista bya vona; muhlaluhi loyi a tshinelelaka kusuhi u ta dlayiwa.”' },
    { n: 11, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 12, text: '“Mina, tlhantlha, ndzi tekile Valevi exikarhi ka vana va Israyele ematshan’wini ya mativula hinkwawo lawa pfulaka mbeleko exikarhi ka vana va Israyele; hikwalaho Valevi va ta va va mina;”' },
    { n: 13, text: '“Hikuva mativula hinkwawo i ya mina; hi siku leri ndzi dlayeke mativula hinkwawo etikweni ra Egipta, ndzi tiandzisele mativula hinkwawo ya Israyele, ku suka eka munhu ku fikela eka xifuwo; i ya mina; hi mina Yehovha.”' },
    { n: 14, text: 'Yehovha a vulavula na Moxe emananga ya Sinayi, a ku:' },
    { n: 15, text: '“Hlayela vana va Levi hi ku landza tiyindlu ta vatata wa vona, hi ku landza mindyangu ya vona; u ta hlayela xinuna hinkwaxo ku sukela eka n’weti un’we ni ku tlhandlaka.”' },
    { n: 16, text: 'Moxe a va hlayela hi ku landza rito ra Yehovha, hilaha a leriseke hakona.' },
    { n: 17, text: 'Lawa hi wona mavito ya vana va Levi hi ku landza mavito ya vona: Gerixoni, na Kohata, na Merari.' },
    { n: 18, text: 'Mavito ya vana va Gerixoni hi ku landza mindyangu ya vona: Libni na Ximeyi.' },
    { n: 19, text: 'Vana va Kohata hi ku landza mindyangu ya vona: Amrami, na Izihari, na Hebroni, na Uziyele.' },
    { n: 20, text: 'Vana va Merari hi ku landza mindyangu ya vona: Mahli na Muxi. Leyi hi yona mindyangu ya Valevi, hi ku landza tiyindlu ta vatata wa vona.' },
    { n: 21, text: 'Eka Gerixoni ku huma ndyangu wa Valibni, ni ndyangu wa Vaximeyi; leyi hi yona mindyangu ya Vagerixoni.' },
    { n: 22, text: 'Lava hlayiweke va vona, hi ku landza nhlayo ya xinuna hinkwaxo ku sukela eka n’weti un’we ni ku tlhandlaka, lava hlayiweke va vona a va ri nkombo wa magidi ni ntlhanu wa madzana.' },
    { n: 23, text: 'Mindyangu ya Vagerixoni a yi dzima mitenda ya yona endzhaku ka tabernakela, etlhelweni ra le vupela-dyambu.' },
    { n: 24, text: 'Murhangeri wa yindlu ya vatata wa Vagerixoni a a ri Eliyasafu, n’wana wa Layele.' },
    { n: 25, text: 'Ntirho wa vana va Gerixoni etabernakeleni ya nhlanganiso a ku ri ku hlayisa tabernakela, ni tende, ku funengeta ka rona, ni xisirhelelo xa nyangwa ya tabernakela ya nhlanganiso,' },
    { n: 26, text: 'Ni swisirhelelo xa luvandze, ni xisirhelelo xa nyangwa ya luvandze, lexi nga kusuhi ni tabernakela ni le kusuhi ni alitari ematlhelo hinkwawo, ni tingoti ta yona hikwalaho ka ntirho wa yona hinkwaro.' },
    { n: 27, text: 'Eka Kohata ku huma ndyangu wa Vaamrami, ni ndyangu wa Vaizihari, ni ndyangu wa Vahebroni, ni ndyangu wa Vauziyele; leyi hi yona mindyangu ya Vakohata.' },
    { n: 28, text: 'Hi ku landza nhlayo ya xinuna hinkwaxo ku sukela eka n’weti un’we ni ku tlhandlaka, a va ri nhungu wa magidi ni tsevu wa madzana, lava hlayiseke ntirho wa ndhawu yo kwetsima.' },
    { n: 29, text: 'Mindyangu ya vana va Kohata a yi dzima mitenda ya yona etlhelweni ra le dzongeni ra tabernakela.' },
    { n: 30, text: 'Murhangeri wa yindlu ya vatata wa mindyangu ya Vakohata a a ri Elizafana, n’wana wa Uziyele.' },
    { n: 31, text: 'Ntirho wa vona a ku ri areka, ni tafula, ni xo tlhoma mavoni, ni tialitari, ni swibya swa ndhawu yo kwetsima leswi va tirhaka ha swona, ni xisirhelelo, ni ntirho wa yona hinkwaro.' },
    { n: 32, text: 'Eliyazara, n’wana wa Aroni muprista, a a ri murhangeri lonkulu wa varhangeri va Valevi; u hlayise lava khomaka ntirho wa ndhawu yo kwetsima.' },
    { n: 33, text: 'Eka Merari ku huma ndyangu wa Vamahli, ni ndyangu wa Vamuxi; leyi hi yona mindyangu ya Vamerari.' },
    { n: 34, text: 'Lava hlayiweke va vona, hi ku landza nhlayo ya xinuna hinkwaxo ku sukela eka n’weti un’we ni ku tlhandlaka, a va ri tsevu wa magidi ni mazana mambirhi.' },
    { n: 35, text: 'Murhangeri wa yindlu ya vatata wa mindyangu ya Merari a a ri Zuriyele, n’wana wa Abihayili; va dzima mitenda ya vona etlhelweni ra le n’walungwini ra tabernakela.' },
    { n: 36, text: 'Ntirho lowu nyikiweke vana va Merari a ku ri ku hlayisa makonzo ya tabernakela, ni tikhatso ta yona, ni timhandzi ta yona, ni swiseketelo swa yona, ni swibya hinkwaswo swa yona, ni ntirho wa yona hinkwaro;' },
    { n: 37, text: 'Ni timhandzi ta luvandze ematlhelo hinkwawo, ni swiseketelo swa tona, ni swipikiri swa tona, ni tingoti ta tona.' },
    { n: 38, text: 'Lava nga ta dzima mitenda ya vona mahlweni ka tabernakela, etlhelweni ra le vuxeni, mahlweni ka tabernakela ya nhlanganiso ku ya hi ku huma ka dyambu, a a ri Moxe na Aroni ni vana va yena, va khoma ntirho wa ndhawu yo kwetsima hikwalaho ka ntirho wa vana va Israyele; muhlaluhi loyi a tshinelelaka kusuhi u ta dlayiwa.' },
    { n: 39, text: 'Hinkwavo lava hlayiweke va Valevi, lava Moxe na Aroni va va hlayeke hi ku landza rito ra Yehovha, hi ku landza mindyangu ya vona, xinuna hinkwaxo ku sukela eka n’weti un’we ni ku tlhandlaka, a va ri makhume mambirhi na timbirhi wa magidi.' },
    { n: 40, text: 'Yehovha a ku eka Moxe: “Hlayela mativula hinkwawo ya xinuna ya vana va Israyele ku sukela eka n’weti un’we ni ku tlhandlaka, u teka nhlayo ya mavito ya vona.”' },
    { n: 41, text: '“U ta teka Valevi eka mina (hi mina Yehovha) ematshan’wini ya mativula hinkwawo ya vana va Israyele, ni swifuwo swa Valevi ematshan’wini ya mativula hinkwawo ya swifuwo swa vana va Israyele.”' },
    { n: 42, text: 'Moxe a hlayela mativula hinkwawo ya vana va Israyele, hilaha Yehovha a n’wi leriseke hakona.' },
    { n: 43, text: 'Mativula hinkwawo ya xinuna, hi ku landza nhlayo ya mavito, ku sukela eka n’weti un’we ni ku tlhandlaka, lava hlayiweke va vona, a va ri makhume mambirhi na timbirhi wa magidi ni mazana mambirhi ni makhume nkombo na nharhu.' },
    { n: 44, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 45, text: '“Teka Valevi ematshan’wini ya mativula hinkwawo ya vana va Israyele, ni swifuwo swa Valevi ematshan’wini ya swifuwo ya vona; Valevi va ta va va mina; hi mina Yehovha.”' },
    { n: 46, text: '“Tanihi mukutsulo wa lava mazana mambirhi ni makhume nkombo na nharhu ya mativula ya vana va Israyele, lava hundzaka nhlayo ya Valevi;”' },
    { n: 47, text: '“U ta teka ntlhanu wa tixekele eka un’wana ni un’wana hi ku landza nhloko; u ta ti teka hi xipimo xa vukwetsimi; tixekele ta makume mambirhi ti ta va gera yin’we;”' },
    { n: 48, text: '“U ta nyika Aroni ni vana va yena mali ya mukutsulo wa lava va hundzaka nhlayo ya vona.”' },
    { n: 49, text: 'Moxe a teka mali ya mukutsulo eka lava va hundzaka nhlayo ya lava va kutsuriweke hi Valevi;' },
    { n: 50, text: 'U teke mali eka mativula ya vana va Israyele, gidi ni mazana nharhu ni makhume tsevu ni ntlhanu wa tixekele, hi xipimo xa vukwetsimi;' },
    { n: 51, text: 'Moxe a nyika Aroni ni vana va yena mali ya mukutsulo hi ku landza rito ra Yehovha, hilaha Yehovha a leriseke Moxe hakona.' }
  ],
  4: [
    { n: 1, text: 'Yehovha a vulavula na Moxe na Aroni, a ku:' },
    { n: 2, text: '“Tekani ntsengo wa vana va Kohata exikarhi ka vana va Levi, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata va vona;”' },
    { n: 3, text: '“Ku sukela eka lava nga ni malembe ya makhume manharhu ni ku tlhandlaka ku fikela eka malembe ya makhume ntlhanu, hinkwavo lava nghenaka eku tirheni, leswaku va endla ntirho etabernakeleni ya nhlanganiso.”' },
    { n: 4, text: '“Loyi hi wona ntirho wa vana va Kohata etabernakeleni ya nhlanganiso, lowu khumbaka swilo leswo kwetsima swinene:”' },
    { n: 5, text: '“Loko kampa yi fanele ku famba, Aroni ni vana va yena va ta nghena, va pshatla xisirhelelo xa ku sirhelela, va funengeta areka ya vumbhoni ha xona;”' },
    { n: 6, text: '“Va ta veka xisirhelelo xa dzovo ra thaka ehenhla ka xona, va andlala lapi leri heleleke ra muvala wa wasi ehenhla, naswona va ta hoxa timhandzi ta yona.”' },
    { n: 7, text: '“Ehenhla ka tafula ra swinkwa swa mboniso va ta andlala lapi ra muvala wa wasi, va veka swibya ehenhla ka rona, ni swipunu, ni swibya leswikulu, ni swibya swa ku tshela ha swona; naswona swinkwa swa nkarhi hinkwaro swi ta va ehenhla ka rona;”' },
    { n: 8, text: '“Va ta andlala lapi ra muvala wa khahla eehenhla ka swilo leswi, va funengeta hi xisirhelelo xa dzovo ra thaka, naswona va ta hoxa timhandzi ta rona.”' },
    { n: 9, text: '“Va ta teka lapi ra wasi va funengeta xo tlhoma mavoni, ni mavoni ya xona, ni swikhanti swa xona, ni swibya swa xona swa mafurha, ni swibya hinkwaswo swa mafurha leswi va tirhaka ha swona;”' },
    { n: 10, text: '“Va ta xi veka xona ni swibya hinkwaswo swa xona endzeni ka xisirhelelo xa dzovo ra thaka, va xi veka ehenhla ka rhomba ra ku rhwala.”' },
    { n: 11, text: '“Ehenhla ka alitari ya nsuku va ta andlala lapi ra wasi, va yi funengeta hi xisirhelelo xa dzovo ra thaka, naswona va ta hoxa timhandzi ta yona;”' },
    { n: 12, text: '“Va ta teka swibya hinkwaswo swa ntirho, leswi va tirhaka ha swona endhawini yo kwetsima, va swi veka elapini ra wasi, va swi funengeta hi xisirhelelo xa dzovo ra thaka, va swi veka ehenhla ka rhomba ra ku rhwala;”' },
    { n: 13, text: '“Va ta susa nkuma eka alitari, va andlala lapi ra muvala wa purpura ehenhla ka yona;”' },
    { n: 14, text: '“Va ta veka ehenhla ka yona swibya hinkwaswo swa yona leswi va tirhaka ha swona: swikhanti swa ndzilo, ni swiforoko, ni mafoxolo, ni swibya swa ku tshela ha swona, swibya hinkwaswo swa alitari; va ta andlala xisirhelelo xa dzovo ra thaka ehenhla ka yona, va hoxa timhandzi ta yona.”' },
    { n: 15, text: '“Loko Aroni ni vana va yena va hete ku funengeta ndhawu yo kwetsima ni swibya hinkwaswo swa ndhawu yo kwetsima, loko kampa yi fanele ku famba; endzhaku ka sweswo vana va Kohata va ta ta va ta swi rhwala; kambe va nga tshuki va khumba nchumu lowu kwetsimaka, hikuva va nga fa. Swilo leswi hi swona leswi vana va Kohata va nga ta swi rhwala etabernakeleni ya nhlanganiso.”' },
    { n: 16, text: '“Ntirho wa Eliyazara, n’wana wa Aroni muprista, wu ta va mafurha ya rivoni, ni incense yo nuhwela, ni munyikelo wa swinkwa wa nkarhi hinkwaro, ni mafurha yo tota, ni ku hlayisa tabernakela hinkwayo, ni hinkwaswo leswi nga endzeni ka yona, ndhawu yo kwetsima, ni swibya swa yona.”' },
    { n: 17, text: 'Yehovha a vulavula na Moxe na Aroni, a ku:' },
    { n: 18, text: '“Mi nga pfumeli leswaku nyimba ya mindyangu ya Vakohata yi herisiwa exikarhi ka Valevi;”' },
    { n: 19, text: '“Kambe endli leswi eka vona, leswaku va hanya naswona va nga fi loko va tshinelela swilo leswo kwetsima swinene: Aroni ni vana va yena va ta nghena, va veka un’wana ni un’wana entirhweni wa yena ni le ka nchumu lowu a nga ta wu rhwala;”' },
    { n: 20, text: '“Kambe va nga ngheni va ta languta loko swilo leswo kwetsima swi funengetiwa, hikuva va nga fa.”' },
    { n: 21, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 22, text: '“Teka ntsengo wa vana va Gerixoni na vona, hi ku landza tiyindlu ta vatata wa vona, hi ku landza mindyangu ya vona;”' },
    { n: 23, text: '“Ku sukela eka lava nga ni malembe ya makhume manharhu ni ku tlhandlaka ku fikela eka malembe ya makhume ntlhanu u ta va hlayela; hinkwavo lava nghenaka eku tirheni leswaku va endla ntirho etabernakeleni ya nhlanganiso.”' },
    { n: 24, text: '“Loyi hi wona ntirho wa mindyangu ya Vagerixoni, eku tirheni ni le ku rhwaleni:”' },
    { n: 25, text: '“Va ta rhwala malapi ya tabernakela, ni tabernakela ya nhlanganiso, xisirhelelo xa yona, ni xisirhelelo xa dzovo ra thaka lexi nga ehenhla ka yona, ni xisirhelelo xa nyangwa ya tabernakela ya nhlanganiso,”' },
    { n: 26, text: '“Ni swisirhelelo xa luvandze, ni xisirhelelo xa nyangwa ya nghena luvandze, lexi nga kusuhi ni tabernakela ni le kusuhi ni alitari ematlhelo hinkwoho, ni tingoti ta tona, ni swibya hinkwaswo swa ntirho wa tona, ni hinkwaswo leswi endliweke hikwalaho ka tona; va ta tirha hi swona.”' },
    { n: 27, text: '“Ntirho hinkwaro wa vana va Vagerixoni wu ta va ehansi ka vurhangeri bya Aroni ni vana va yena, eku rhwaleni ka vona hinkwaro ni le ka ntirho wa vona hinkwaro; naswona mi ta va veka emintirhweni ya vona hinkwayo leyi va faneleke ku yi rhwala.”' },
    { n: 28, text: '“Loyi hi wona ntirho wa mindyangu ya vana va Gerixoni etabernakeleni ya nhlanganiso; naswona ntirho wa vona wu ta va ehansi ka voko ra Itamara, n’wana wa Aroni muprista.”' },
    { n: 29, text: '“Eka vana va Merari, u ta va hlayela hi ku landza mindyangu ya vona, hi tiyindlu ta vatata wa vona;”' },
    { n: 30, text: '“Ku sukela eka lava nga ni malembe ya makhume manharhu ni ku tlhandlaka ku fikela eka malembe ya makhume ntlhanu u ta va hlayela, hinkwavo lava nghenaka eku tirheni, leswaku va endla ntirho wa tabernakela ya nhlanganiso.”' },
    { n: 31, text: '“Loyi hi wona ntirho wa leswi va faneleke ku swi rhwala, hi ku landza ntirho wa vona hinkwaro etabernakeleni ya nhlanganiso: makonzo ya tabernakela, ni tikhatso ta yona, ni timhandzi ta yona, ni swiseketelo swa yona,”' },
    { n: 32, text: '“Ni timhandzi ta luvandze ematlhelo hinkwawo, ni swiseketelo swa tona, ni swipikiri swa tona, ni tingoti ta tona, ni swibya hinkwaswo swa tona, ni ntirho wa tona hinkwaro; naswona mi ta va hlayela hi mavito swibya swa ntirho lowu va faneleke ku wu rhwala.”' },
    { n: 33, text: '“Loyi hi wona ntirho wa mindyangu ya vana va Merari, hi ku landza ntirho wa vona hinkwaro etabernakeleni ya nhlanganiso, ehansi ka voko ra Itamara, n’wana wa Aroni muprista.”' },
    { n: 34, text: 'Moxe na Aroni ni varhangeri va nhlengeletano va hlayela vana va Vakohata hi ku landza mindyangu ya vona, hi tiyindlu ta vatata wa vona,' },
    { n: 35, text: 'Ku sukela eka lava nga ni malembe ya makhume manharhu ni ku tlhandlaka ku fikela eka malembe ya makhume ntlhanu, hinkwavo lava nghenaka eku tirheni, leswaku va tirha etabernakeleni ya nhlanganiso;' },
    { n: 36, text: 'Lava hlayiweke va vona hi ku landza mindyangu ya vona a va ri timbirhi wa magidi ni nkombo wa madzana ni makhume ntlhanu.' },
    { n: 37, text: 'Lava hi vona lava hlayiweke va mindyangu ya Vakohata, hinkwavo lava tirhaka etabernakeleni ya nhlanganiso, lava Moxe na Aroni va va hlayeke hi ku landza rito ra Yehovha leri humeke hi voko ra Moxe.' },
    { n: 38, text: 'Lava hlayiweke va vana va Gerixoni, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata wa vona,' },
    { n: 39, text: 'Ku sukela eka lava nga ni malembe ya makhume manharhu ni ku tlhandlaka ku fikela eka malembe ya makhume ntlhanu, hinkwavo lava nghenaka eku tirheni, leswaku va tirha etabernakeleni ya nhlanganiso,' },
    { n: 40, text: 'Lava hlayiweke va vona, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata wa vona, a va ri timbirhi wa magidi ni tsevu wa madzana ni makhume manharhu.' },
    { n: 41, text: 'Lava hi vona lava hlayiweke va mindyangu ya vana va Gerixoni, hinkwavo lava tirhaka etabernakeleni ya nhlanganiso, lava Moxe na Aroni va va hlayeke hi ku landza rito ra Yehovha.' },
    { n: 42, text: 'Lava hlayiweke va mindyangu ya vana va Merari, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata wa vona,' },
    { n: 43, text: 'Ku sukela eka lava nga ni malembe ya makhume manharhu ni ku tlhandlaka ku fikela eka malembe ya makhume ntlhanu, hinkwavo lava nghenaka eku tirheni, leswaku va tirha etabernakeleni ya nhlanganiso,' },
    { n: 44, text: 'Lava hlayiweke va vona, hi ku landza mindyangu ya vona, a va ri nharhu wa magidi ni mazana mambirhi.' },
    { n: 45, text: 'Lava hi vona lava hlayiweke va mindyangu ya vana va Merari, lava Moxe na Aroni va va hlayeke hi ku landza rito ra Yehovha leri humeke hi voko ra Moxe.' },
    { n: 46, text: 'Hinkwavo lava hlayiweke, lava Moxe na Aroni ni varhangeri va Israyele va va hlayeke eka Valevi, hi ku landza mindyangu ya vona, hi tiyindlu ta vatata wa vona,' },
    { n: 47, text: 'Ku sukela eka lava nga ni malembe ya makhume manharhu ni ku tlhandlaka ku fikela eka malembe ya makhume ntlhanu, hinkwavo lava nghenaka eku tirheni, leswaku va endla ntirho wa ku tirhela ni ntirho wa ku rhwala etabernakeleni ya nhlanganiso,' },
    { n: 48, text: 'Lava hlayiweke va vona a va ri nhungu wa magidi ni ntlhanu wa madzana ni makhume ya nhungu.' },
    { n: 49, text: 'Hi ku landza rito ra Yehovha va hlayeriwe hi voko ra Moxe, un’wana ni un’wana hi ku landza ntirho wa yena ni le ka leswi a nga ta swi rhwala; va hlayiwile hilaha Yehovha a leriseke Moxe hakona.' }
  ],
  5: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Lerisa vana va Israyele leswaku va humesa ekampeni un’wana ni un’wana la nga ni nhlokofatana, ni un’wana ni un’wana la humaka nchumu, ni un’wana ni un’wana la nga tengangiki hikwalaho ka mufi;”' },
    { n: 3, text: '“Xinuna ni xisati mi ta va humesa; mi va humesela ehandle ka kampa, leswaku va nga nyamisi kampa ya vona, leyi ndzi tshamaka exikarhi ka yona.”' },
    { n: 4, text: 'Vana va Israyele va endla tano, va va humesela ehandle ka kampa; hilaha Yehovha a vulavuleke na Moxe hakona, vana va Israyele va endla tano.' },
    { n: 5, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 6, text: '“Vulavula ni vana va Israyele: Loko wanuna kumbe wansati o tshuka a endle xidyoho hambi xi ri xihi lexi vanhu va xi endlaka, a tlula nawu mahlweni ka Yehovha, naswona munhu yoloye a ri ni nandzu;”' },
    { n: 7, text: '“U ta tivula xidyoho xa yena lexi a xi endleke, naswona u ta tlherisela ntsengo wa nandzu wa yena hi ku helela, a engetela xiyenge xa ntlhanu eka wona, a wu nyika loyi a n’wi dyoheleke.”' },
    { n: 8, text: '“Kambe loko munhu yoloye a nga ri na makwenu wa le kusuhi loyi va nga n’wi tlheriselaka ntsengo wa nandzu eka yena, ntsengo lowu tlheriseriwaka Yehovha wu ta va wa muprista, kusuhi ni xinyimpfu xa xinuna xa mukutsulo, lexi va nga ta n’wi endlela mukutsulo ha xona.”' },
    { n: 9, text: '“Naswona munyikelo hinkwaro wa swilo hinkwaswo leswo kwetsima swa vana va Israyele, leswi va swi tisaka eka muprista, wu ta va wa yena.”' },
    { n: 10, text: '“Swilo swo kwetsima swa un’wana ni un’wana swi ta va swa yena; hinkwaswo leswi un’wana a swi nyikaka muprista swi ta va swa yena.”' },
    { n: 11, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 12, text: '“Vulavula ni vana va Israyele, u ku eka vona: Loko wansati wa un’wana o tshuka a huma endleleni, a lwisana ni nuna wa yena;”' },
    { n: 13, text: '“Naswona wanuna un’wana a etlela na yena, a pfula mbeleko, naswona swi sirhelelekile emantlhanyeni ya nuna wa yena, swi tumbetiwile, naswona a nga tengangiki, ku nga ri na mbhoni yo lwisana na yena, naswona a nga khomiwangiki eku dyonheni;”' },
    { n: 14, text: '“Naswona moya wa ku nonon’hweriwa o tshuka wu n’wi nghena, a vambela wansati wa yena, naswona wansati a nga tengangiki; kumbe moya wa ku nonon’hweriwa wu n’wi nghena, a vambela wansati wa yena, kambe wansati u tengile;”' },
    { n: 15, text: '“Wanuna u ta tisa wansati wa yena eka muprista, naswona u ta tisa munyikelo wa yena hikwalaho ka yena, xiyenge xa khume xa efa ya flour ya maxalana; a nga fanelanga ku chela mafurha eka yona, kumbe ku veka incense ehenhla ka yona, hikuva i munyikelo wa ku nonon’hweriwa, munyikelo wa xitsundzuxo, lowu tsundzuxaka vuhomboloki.”' },
    { n: 16, text: '“Muprista u ta n’wi tshineta kusuhi, a n’wi yimisa mahlweni ka Yehovha;”' },
    { n: 17, text: '“Muprista u ta teka mati yo kwetsima endzeni ka xibya xa vumba; naswona muprista u ta teka ritshuri leri nga ehansi ka tabernakela, a ri hoxa ematini;”' },
    { n: 18, text: '“Muprista u ta yimisa wansati mahlweni ka Yehovha, a pfula misisi ya wansati, a veka munyikelo wa xitsundzuxo emavokweni ya yena, lowu nga munyikelo wa ku nonon’hweriwa; naswona muprista u ta khoma mati yo bava lawa ya tisaka mindzhukano;”' },
    { n: 19, text: '“Muprista u ta n’wi endla a hlambanya, a ku eka wansati: ‘Loko ku nga ri na wanuna loyi a etleleke na wena, naswona loko u nga humangiki endleleni u ya eka swilo swo kala ku tenga, u ri ehansi ka nuna wa wena, u nga hlaseriwi hi mati lawa yo bava lawa ya tisaka mindzhukano;’”' },
    { n: 20, text: '“‘Kambe loko u humile endleleni, u ri ehansi ka nuna wa wena, naswona u nga tengangiki, naswona wanuna un’wana a etleleke na wena handle ka nuna wa wena;’”' },
    { n: 21, text: '“Hi kona muprista a nga ta endla wansati a hlambanya hi xihlambanyo xa xindzhukano, muprista a ku eka wansati: ‘Yehovha a ku endle xindzhukano ni xihlambanyo exikarhi ka vanhu va ka n’wina, loko Yehovha a endla nenge wa wena wu dhowa, ni khuri ra wena ri kukuva;’”' },
    { n: 22, text: '“‘Naswona mati lawa ya tisaka xindzhukano ya ta nghena ematumbini ya wena, ya endla khuri ra wena ri kukuva, ni nenge wa wena wu dhowa.’ Wansati u ta ku: ‘Amen, Amen.’”' },
    { n: 23, text: '“Muprista u ta tsala mindzhukano leyi ematsalweni, a yi hlangula ematini yo bava;”' },
    { n: 24, text: '“U ta endla wansati a nwa mati yo bava lawa ya tisaka xindzhukano; naswona mati lawa ya tisaka xindzhukano ya ta nghena eka yena ya n’wi bavisela;”' },
    { n: 25, text: '“Muprista u ta teka munyikelo wa ku nonon’hweriwa emavokweni ya wansati, a n’wan’wasela munyikelo mahlweni ka Yehovha, a wu yisa ealitari;”' },
    { n: 26, text: '“Muprista u ta teka xandla xa munyikelo tanihi xitsundzuxo, a xi hisa ealitari, naswona endzhaku u ta endla wansati a nwa mati.”' },
    { n: 27, text: '“Loko a n’wise mati, swi ta va tano: Loko a nga tengangiki, a endlele nuna wa yena ku pfumala ku tshembeka, mati lawa ya tisaka xindzhukano ya ta nghena eka yena ya n’wi bavisela, khuri ra yena ri ta kukuva, ni nenge wa yena wu ta dhowa, naswona wansati u ta va xindzhukano exikarhi ka vanhu va ka vona.”' },
    { n: 28, text: '“Kambe loko wansati a nga dyohelangiki, a tengile, u ta nghena a hlayisekile, naswona u ta va ni vana.”' },
    { n: 29, text: '“Loyi hi wona nawu wa ku nonon’hweriwa, loko wansati, a ri ehansi ka nuna wa yena, o tshuka a humile endleleni, a nga tengi;”' },
    { n: 30, text: '“Kumbe loko moya wa ku nonon’hweriwa wu nghena wanuna, a vambela wansati wa yena; u ta yimisa wansati mahlweni ka Yehovha, naswona muprista u ta endla milawu leyi hinkwayo eka yena.”' },
    { n: 31, text: '“Wanuna u ta va la nga riki na vuhomboloki, kambe wansati yoloye u ta rhwala vuhomboloki xa yena.”' }
  ],
  6: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: Loko wanuna kumbe wansati o tshuka a endla xihlambanyo xo hlawuleka, xihlambanyo xa Munaziri, leswaku a tihlawulela Yehovha;”' },
    { n: 3, text: '“U ta tifambela kule ni vhinyo ni xihoko; a nga fanele ku nwa vhinyo yo bava kumbe xihoko xo bava, naswona a nga fanele ku nwa jusi ya vhinya, hambi ku ri ku dya madiribe yo tshama kumbe yo woma;”' },
    { n: 4, text: '“Hi masiku hinkwaswo ya vunasiri bya yena, a nga dlayi nchumu lowu endliweke hi nsinya wa vhinya, ku sukela eka tinyungu ku fikela eka mahanti;”' },
    { n: 5, text: '“Hi masiku hinkwaswo ya xihlambanyo xa vunasiri bya yena, xipula a xi nga fanele ku tsemeta misisi ya nhloko ya yena; ku fikela loko masiku ya ku tihlawulela Yehovha ya hela, u ta va la kwetsimaka, u ta tshika misisi ya nhloko ya yena yi kula;”' },
    { n: 6, text: '“Hi masiku hinkwaswo lawa a tihlawuleleke Yehovha ha wona, a nga fanele ku tshinela kusuhi ni mufi;”' },
    { n: 7, text: '“Hambi ku ri hikwalaho ka tata wa yena, kumbe mana wa yena, kumbe makwenu wa xinuna, kumbe wa xisati, a nga fanele ku tinyamisa loko va file, hikuva ku tihlawulela ka Xikwembu xa yena ku le henhla ka nhloko ya yena;”' },
    { n: 8, text: '“Hi masiku hinkwaswo ya vunasiri bya yena, u hlawuleriwile Yehovha.”' },
    { n: 9, text: '“Loko munhu o tshuka a fela kusuhi na yena hi xitshuketa, a nyamisa nhloko ya vunasiri bya yena, u ta tsemeta nhloko ya yena hi siku ra ku tenga ka yena; u ta yi tsemeta hi siku ra vunkombo;”' },
    { n: 10, text: '“Hi siku ra vunhungu u ta tisa switendele swimbirhi kumbe swivana swa swinjiva swimbirhi eka muprista, enyangweni ya tabernakela ya nhlanganiso;”' },
    { n: 11, text: '“Muprista u ta endla un’we a ri munyikelo wa xidyoho, loyi un’wana a ri munyikelo wo hisiwa, a n’wi endlela mukutsulo hikwalaho ka ku dyoha loku a ku endleke hi mufi; u ta kwetsimisa nhloko ya yena hi siku rero;”' },
    { n: 12, text: '“U ta thlela a tihlawulelela Yehovha hi masiku ya vunasiri bya yena, a tisa xinyimpfu xa xinuna xa lembe rin’we tanihi munyikelo wa nandzu; kambe masiku yo sungula ya ta hundza ya nga ri na nchumu, hikuva vunasiri bya yena byi nyamisiwile.”' },
    { n: 13, text: '“Loko hi wona nawu wa Munaziri, loko masiku ya vunasiri bya yena ya herile: u ta tisiwa enyangweni ya tabernakela ya nhlanganiso;”' },
    { n: 14, text: '“U ta nyikela munyikelo wa yena eka Yehovha: xinyimpfu xin’we xa xinuna xa lembe rin’we lexi nga riki na xisandzu tanihi munyikelo wo hisiwa, ni xinyimpfu xin’we xa xisati xa lembe rin’we lexi nga riki na xisandzu tanihi munyikelo wa xidyoho, ni khon’wana yin’we ya xinuna leyi nga riki na xisandzu tanihi munyikelo wa ku rhula;”' },
    { n: 15, text: '“Ni xirhundzu xa swinkwa swo kala mbyandzo swa flour leyinene, swingwa swa xirhendzevutana leswi mixingiweke ni mafurha, ni swipapana swo kala mbyandzo leswi totiweke mafurha, ni munyikelo wa vona wa swinkwa ni minyikelo ya vona ya swakunwa.”' },
    { n: 16, text: '“Muprista u ta swi tisa mahlweni ka Yehovha, a endla munyikelo wa yena wa xidyoho ni munyikelo wa yena wo hisiwa;”' },
    { n: 17, text: '“U ta endla khon’wana tanihi munyikelo wa ku rhula eka Yehovha, kusuhi ni xirhundzu xa swinkwa swo kala mbyandzo; muprista u ta endla na munyikelo wa yona wa swinkwa ni munyikelo wa yona wa swakunwa.”' },
    { n: 18, text: '“Munaziri u ta tsemeta nhloko ya vunasiri bya yena enyangweni ya tabernakela ya nhlanganiso, a teka misisi ya nhloko ya vunasiri bya yena, a yi hoxa endzilweni lowu nga ehansi ka munyikelo wa ku rhula.”' },
    { n: 19, text: '“Muprista u ta teka xipfala-ntshuri lexi tswiweke xa khon’wana, ni xingwa xin’we xo kala mbyandzo exirhundzwini, ni xipapana xin’we xo kala mbyandzo, a swi veka emavokweni ya Munaziri, endzhaku ka ku tsemeta ka yena misisi ya vunasiri bya yena;”' },
    { n: 20, text: '“Muprista u ta swi n’wan’wasela tanihi munyikelo wo n’wan’wasela mahlweni ka Yehovha; leyi i nchumu lowu kwetsimaka wa muprista, kusuhi ni xifuva xa ku n’wan’wasela ni nenge wa ku hlawuriwa; endzhaku ka sweswo Munaziri a nga nwa vhinyo.”' },
    { n: 21, text: '“Loyi i nawu wa Munaziri loyi a hlambanyeke, ni wa munyikelo wa yena eka Yehovha hikwalaho ka vunasiri bya yena, handle ka leswi a nga na swona evokweni ra yena; hi ku landza xihlambanyo xa yena lexi a xi endleke, u ta endla tano hi ku landza nawu wa vunasiri bya yena.”' },
    { n: 22, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 23, text: '“Vulavula na Aroni ni vana va yena, u ku: ‘Hi ndlela leyi mi ta katekisa vana va Israyele, mi ku eka vona:’”' },
    { n: 24, text: '“‘Yehovha a ku katekisa, a ku hlayisa;’”' },
    { n: 25, text: '“‘Yehovha a ku vangurisa xikandza xa yena eka wena, a ku rivalela;’”' },
    { n: 26, text: '“‘Yehovha a ku langutisa hi xikandza xa yena, a ku nyika ku rhula.’”' },
    { n: 27, text: '“Va ta veka vito ra mina ehenhla ka vana va Israyele, naswona mina ndzi ta va katekisa.”' }
  ],
  7: [
    { n: 1, text: 'Hi siku leri Moxe a heteke ku dzima tabernakela, u yi totile a yi kwetsimisa, ni swibya hinkwaswo swa yona, ni alitari ni swibya hinkwaswo swa yona, a swi tota a swi kwetsimisa;' },
    { n: 2, text: 'Varhangeri va Israyele, tinhloko ta tiyindlu ta vatata wa vona, lava va nga varhangeri va tinyimba (lava yimeke ehenhla ka lava hlayiweke), va nyikela;' },
    { n: 3, text: 'Va tisa minyikelo ya vona mahlweni ka Yehovha: swigolonyi swa tsevu leswi funengetiweke, ni tihon’wana ta khume na timbirhi; xigolonyi xin’we eka varhangeri vambirhi, ni khon’wana yin’we eka un’wana ni un’wana; va swi tisa mahlweni ka tabernakela.' },
    { n: 4, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 5, text: '“Teka swilo leswi eka vona, leswaku swi tirha entirhweni wa tabernakela ya nhlanganiso; u ta swi nyika Valevi, un’wana ni un’wana hi ku landza ntirho wa yena.”' },
    { n: 6, text: 'Moxe a teka swigolonyi ni tihon’wana, a swi nyika Valevi.' },
    { n: 7, text: 'Swigolonyi swimbirhi ni tihon’wana ta mune u swi nyike vana va Gerixoni, hi ku landza ntirho wa vona;' },
    { n: 8, text: 'Swigolonyi swa mune ni tihon’wana ta nhungu u swi nyike vana va Merari, hi ku landza ntirho wa vona, ehansi ka voko ra Itamara, n’wana wa Aroni muprista.' },
    { n: 9, text: 'Kambe vana va Kohata a nga va nyikanga nchumu, hikuva ntirho wa vona a ku ri ku hlayisa swilo leswo kwetsima, leswi va faneleke ku swi rhwala emagandzeni ya vona.' },
    { n: 10, text: 'Varhangeri va tisa munyikelo wa ku hlawuriwa ka alitari hi siku leri yi totiweke ha rona; varhangeri va tisa minyikelo ya vona mahlweni ka alitari.' },
    { n: 11, text: 'Yehovha a ku eka Moxe: “U ta endla leswaku varhangeri va tisa minyikelo ya vona, un’we hi siku, ku hlawuriwa ka alitari.”' },
    { n: 12, text: 'Loyi a tiseke munyikelo wa yena hi siku ro sungula a a ri Naxoni, n’wana wa Aminadaba, wa nyimba ya Yuda.' },
    { n: 13, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 14, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 15, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 16, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 17, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Naxoni, n’wana wa Aminadaba.' },
    { n: 18, text: 'Hi siku ra vumbirhi Netanele, n’wana wa Zuara, murhangeri wa Isakara, a tisa munyikelo;' },
    { n: 19, text: 'U tise munyikelo wa yena: mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 20, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 21, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 22, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 23, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Netanele, n’wana wa Zuara.' },
    { n: 24, text: 'Hi siku ra vunharhu Eliyabu, n’wana wa Heloni, murhangeri wa vana va Zebuloni, a tisa munyikelo;' },
    { n: 25, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 26, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 27, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 28, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 29, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Eliyabu, n’wana wa Heloni.' },
    { n: 30, text: 'Hi siku ra vumune Elizuru, n’wana wa Xedeyure, murhangeri wa vana va Ruveni, a tisa munyikelo;' },
    { n: 31, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 32, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 33, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 34, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 35, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Elizuru, n’wana wa Xedeyure.' },
    { n: 36, text: 'Hi siku ra vuntlhanu Xelumiyele, n’wana wa Zurixadayi, murhangeri wa vana va Ximeyoni, a tisa munyikelo;' },
    { n: 37, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 38, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 39, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 40, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 41, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Xelumiyele, n’wana wa Zurixadayi.' },
    { n: 42, text: 'Hi siku ra vutsevu Eliyasafu, n’wana wa Dewele, murhangeri wa vana va Gadi, a tisa munyikelo;' },
    { n: 43, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 44, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 45, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 46, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 47, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Eliyasafu, n’wana wa Dewele.' },
    { n: 48, text: 'Hi siku ra vunkombo Elixama, n’wana wa Amihudu, murhangeri wa vana va Efrayimi, a tisa munyikelo;' },
    { n: 49, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 50, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 51, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 52, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 53, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Elixama, n’wana wa Amihudu.' },
    { n: 54, text: 'Hi siku ra vunhungu Gamaliyele, n’wana wa Pedasuri, murhangeri wa vana va Manase, a tisa munyikelo;' },
    { n: 55, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 56, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 57, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 58, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 59, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Gamaliyele, n’wana wa Pedasuri.' },
    { n: 60, text: 'Hi siku ra vukaye Abidani, n’wana wa Gideyoni, murhangeri wa vana va Benjamini, a tisa munyikelo;' },
    { n: 61, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 62, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 63, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 64, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 65, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Abidani, n’wana wa Gideyoni.' },
    { n: 66, text: 'Hi siku ra vukhume Ahiyezeri, n’wana wa Amixadayi, murhangeri wa vana va Dani, a tisa munyikelo;' },
    { n: 67, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 68, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 69, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 70, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 71, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Ahiyezeri, n’wana wa Amixadayi.' },
    { n: 72, text: 'Hi siku ra khume na xin’we Pagiyele, n’wana wa Okrani, murhangeri wa vana va Axere, a tisa munyikelo;' },
    { n: 73, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 74, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 75, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 76, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 77, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Pagiyele, n’wana wa Okrani.' },
    { n: 78, text: 'Hi siku ra khume na timbirhi Ahira, n’wana wa Enani, murhangeri wa vana va Naftali, a tisa munyikelo;' },
    { n: 79, text: 'Munyikelo wa yena a ku ri mbita yin’we ya silivhere leyi tiko-vukulu ra yona a ku ri dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa silivhere xa makhume nkombo wa tixekele, hi xipimo xa vukwetsimi, swi mambirhi swi tele hi flour leyinene leyi mixingiweke ni mafurha tanihi munyikelo wa swinkwa;' },
    { n: 80, text: 'Xipunu xin’we xa nsuku xa khume ra tixekele, xi tele hi incense;' },
    { n: 81, text: 'Khon’wana yin’we ya xinuna, xinyimpfu xin’we xa xinuna, xinyimpfu xin’we xa xinuna xa lembe rin’we, tanihi munyikelo wo hisiwa;' },
    { n: 82, text: 'Mbuti yin’we ya xinuna tanihi munyikelo wa xidyoho;' },
    { n: 83, text: 'Ni hi ku landza munyikelo wa ku rhula: tihon’wana timbirhi, tinyimpfu ta xinuna ta ntlhanu, timbuti ta xinuna ta ntlhanu, tinyimpfu ta xinuna ta ntlhanu ta lembe rin’we. Loyi a a ri munyikelo wa Ahira, n’wana wa Enani.' },
    { n: 84, text: 'Loyi hi wona munyikelo wa ku hlawuriwa ka alitari, lowu humeke eka varhangeri va Israyele, hi siku leri yi totiweke ha rona: timbita ta silivhere ta khume na timbirhi, swibya swa silivhere ta khume na timbirhi, swipunu swa nsuku ta khume na timbirhi;' },
    { n: 85, text: 'Mbita yin’we ya silivhere a yi ri ni dzana ni makhume manharhu wa tixekele, ni xibya xin’we xa makhume nkombo; silivhere hinkwayo ya swibya leswi a yi ri timbirhi wa magidi ni mazana mune wa tixekele, hi xipimo xa vukwetsimi;' },
    { n: 86, text: 'Swipunu swa nsuku ta khume na timbirhi leswi teleke hi incense, khume ra tixekele xipunu xin’we, hi xipimo xa vukwetsimi; nsuku hinkwayo wa swipunu a wu ri dzana ni makhume mambirhi wa tixekele;' },
    { n: 87, text: 'Swifuwo hinkwaswo swa munyikelo wo hisiwa a ku ri: tihon’wana ta khume na timbirhi, tinyimpfu ta xinuna ta khume na timbirhi, tinyimpfu ta xinuna ta khume na timbirhi ta lembe rin’we, ni minyikelo ya tona ya swinkwa; ni timbuti ta xinuna ta khume na timbirhi tanihi munyikelo wa xidyoho;' },
    { n: 88, text: 'Ni swifuwo hinkwaswo swa munyikelo wa ku rhula a ku ri: tihon’wana ta makhume mambirhi na mune, tinyimpfu ta xinuna ta makhume tsevu, timbuti ta xinuna ta makhume tsevu, tinyimpfu ta xinuna ta makhume tsevu ta lembe rin’we. Loyi hi wona munyikelo wa ku hlawuriwa ka alitari, endzhaku ka ku totiwa ka yona.' },
    { n: 89, text: 'Loko Moxe a nghena endzeni ka tabernakela ya nhlanganiso leswaku a vulavula na Yena, u twile rito leri vulavulaka na yena ri huma ehenhla ka xipfalo xa mukutsulo lexi nga ehenhla ka areka ya vumbhoni, exikarhi ka makerubimi mambirhi; naswona u vulavurile na Yena.' }
  ],
  8: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula na Aroni, u ku eka yena: Loko u tlhoma mavoni, mavoni ya nkombo ya fanele ku vangurisa mahlweni ka xo tlhoma mavoni.”' },
    { n: 3, text: 'Aroni a endla tano; u tlhome mavoni ya xona leswaku ya vangurisa mahlweni ka xo tlhoma mavoni, hilaha Yehovha a leriseke Moxe hakona.' },
    { n: 4, text: 'Naswona ndlela leyi xo tlhoma mavoni xi endliweke ha yona a ku ri nsuku lowu furiweke; ku sukela eka nenge wa xona ku fikela eka swiluva swa xona, a ku ri nchumu lowu furiweke; hi ku landza xivumbeko lexi Yehovha a xi kombiseke Moxe, u endle xo tlhoma mavoni tano.' },
    { n: 5, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 6, text: '“Teka Valevi exikarhi ka vana va Israyele, u va basisa.”' },
    { n: 7, text: '“Hi ndlela leyi u ta va basisa: u ta va n’wan’wasela mati ya ku tenga, naswona va ta fambisa xipula ehenhla ka miri wa vona hinkwaro, va hlantswa tinguvu ta vona, va tibasisa.”' },
    { n: 8, text: '“Endzhaku va ta teka khon’wana ya xinuna, ni munyikelo wa yona wa swinkwa wa flour leyinene leyi mixingiweke ni mafurha; naswona khon’wana yin’wana ya xinuna u ta yi teka tanihi munyikelo wa xidyoho.”' },
    { n: 9, text: '“U ta tisa Valevi mahlweni ka tabernakela ya nhlanganiso, u hlengeleta nhlengeletano hinkwayo ya vana va Israyele;”' },
    { n: 10, text: '“U ta tisa Valevi mahlweni ka Yehovha, naswona vana va Israyele va ta veka mavoko ya vona ehenhla ka Valevi;”' },
    { n: 11, text: '“Aroni u ta nyikela Valevi mahlweni ka Yehovha tanihi munyikelo wo n’wan’wasela lowu humaka eka vana va Israyele, leswaku va endla ntirho wa Yehovha.”' },
    { n: 12, text: '“Valevi va ta veka mavoko ya vona ehenhla ka tinhloko ta tihon’wana; u ta nyikela yin’we tanihi munyikelo wa xidyoho, loyi yin’wana tanihi munyikelo wo hisiwa eka Yehovha, ku endlela Valevi mukutsulo.”' },
    { n: 13, text: '“U ta yimisa Valevi mahlweni ka Aroni ni mahlweni ka vana va yena, u va nyikela tanihi munyikelo wo n’wan’wasela eka Yehovha.”' },
    { n: 14, text: '“Hi ndlela leyi u ta hambanisa Valevi exikarhi ka vana va Israyele, naswona Valevi va ta va va mina.”' },
    { n: 15, text: '“Endzhaku ka sweswo Valevi va ta nghena va endla ntirho wa tabernakela ya nhlanganiso; u ta va basisa, u va nyikela tanihi munyikelo wo n’wan’wasela;”' },
    { n: 16, text: '“Hikuva va nyikiwe mina hi ku helela exikarhi ka vana va Israyele; ematshan’wini ya hinkwavo lava pfulaka mbeleko, mativula hinkwawo ya vana va Israyele, ndzi tiandzisele vona;”' },
    { n: 17, text: '“Hikuva mativula hinkwawo ya vana va Israyele i ya mina, ku suka eka munhu ku fikela eka xifuwo; hi siku leri ndzi dlayeke mativula hinkwawo etikweni ra Egipta, ndzi tiandzisele wona;”' },
    { n: 18, text: '“Kambe ndzi teke Valevi ematshan’wini ya mativula hinkwawo ya vana va Israyele.”' },
    { n: 19, text: '“Ndzi nyike Valevi tanihi nyiko eka Aroni ni le ka vana va yena exikarhi ka vana va Israyele, leswaku va endla ntirho wa vana va Israyele etabernakeleni ya nhlanganiso, ni ku endlela vana va Israyele mukutsulo; leswaku ku nga vi na rifu exikarhi ka vana va Israyele loko va tshinela kusuhi ni ndhawu yo kwetsima.”' },
    { n: 20, text: 'Moxe na Aroni ni nhlengeletano hinkwayo ya vana va Israyele va endlela Valevi tano; hi ku landza hinkwaswo leswi Yehovha a leriseke Moxe ehenhla ka Valevi, vana va Israyele va va endlela tano.' },
    { n: 21, text: 'Valevi va tibasisa, va hlantswa tinguvu ta vona; Aroni a va nyikela tanihi munyikelo wo n’wan’wasela mahlweni ka Yehovha, naswona Aroni a va endlela mukutsulo ku va basisa.' },
    { n: 22, text: 'Endzhaku ka sweswo Valevi va nghena va endla ntirho wa vona etabernakeleni ya nhlanganiso mahlweni ka Aroni ni mahlweni ka vana va yena; hilaha Yehovha a leriseke Moxe ehenhla ka Valevi, va va endlele tano.' },
    { n: 23, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 24, text: '“Loyi i nawu lowu khumbaka Valevi: ku sukela eka lava nga ni malembe ya makhume mambirhi ni ntlhanu ni ku tlhandlaka va ta nghena va endla ntirho etabernakeleni ya nhlanganiso;”' },
    { n: 25, text: '“Kambe ku sukela eka malembe ya makhume ntlhanu va ta tshika ntirho wa vona, naswona a va nga ha tirhi;”' },
    { n: 26, text: '“Va nga pfuneta vamakwavo etabernakeleni ya nhlanganiso, eku hlayiseni ka mintirho, kambe a va nga ha endli ntirho wa matimba. Hi ndlela leyi u ta va vekela Valevi emintirhweni ya vona.”' }
  ],
  9: [
    { n: 1, text: 'Yehovha a vulavula na Moxe emananga ya Sinayi, hi n’weti wo sungula wa lembe ra vumbirhi endzhaku ka ku huma ka vona etikweni ra Egipta, a ku:' },
    { n: 2, text: '“Vana va Israyele a va endle tano, va endla tlhantlha hi nkarhi wa yona lowu vekiweke.”' },
    { n: 3, text: '“Hi siku ra khume na mune ra n’weti lowu, hi nkarhi wa madyambu, mi ta yi endla hi nkarhi wa yona lowu vekiweke; mi ta yi endla hi ku landza milawu ya yona hinkwayo ni mikhuva ya yona hinkwayo.”' },
    { n: 4, text: 'Moxe a lerisa vana va Israyele leswaku va endla Paseka.' },
    { n: 5, text: 'Va endla Paseka hi n’weti wo sungula, hi siku ra khume na mune ra n’weti, hi nkarhi wa madyambu, emananga ya Sinayi; hi ku landza hinkwaswo leswi Yehovha a leriseke Moxe, vana va Israyele va endla tano.' },
    { n: 6, text: 'Kambe a ku ri ni vanhu lava a va nyamile hikwalaho ka mufi, lerova va nga swi koti ku endla Paseka hi siku rero; hikwalaho va tshinela mahlweni ka Moxe na Aroni hi siku rero;' },
    { n: 7, text: 'Vanhu volavo va ku eka yena: “Hina hi nyamile hikwalaho ka mufi; hikwalaho ka yini hi fanele ku tsoniwa ku tisa munyikelo wa Yehovha hi nkarhi wa wona lowu vekiweke exikarhi ka vana va Israyele?”' },
    { n: 8, text: 'Moxe a ku eka vona: “Yimanyana, ndzi ta twa leswi Yehovha a nga ta swi lerisa hikwalaho ka n’wina.”' },
    { n: 9, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 10, text: '“Vulavula ni vana va Israyele, u ku: ‘Loko un’wana ni un’wana wa n’wina kumbe wa vatukulu va n’wina o tshuka a nyamile hikwalaho ka mufi, kumbe a ri riendzweni ra le kule, u ta hambeta a endla Paseka eka Yehovha;’”' },
    { n: 11, text: '“‘Va ta yi endla hi n’weti wa vumbirhi, hi siku ra khume na mune, hi nkarhi wa madyambu; va ta yi dya ni swinkwa swo kala mbyandzo ni matluka yo bava;’”' },
    { n: 12, text: '“‘A va nga fanele ku siya nchumu wa yona ku fikela nimixo, hambi ku ri ku tshova rhamu ra yona; va ta yi endla hi ku landza milawu hinkwayo ya Paseka.’”' },
    { n: 13, text: '“‘Kambe munhu loyi a tengeke, a nga riki riendzweni, kambe a nga endli Paseka, munhu yoloye u ta dlayiwa exikarhi ka vanhu va ka vona; hikuva a nga tisanga munyikelo wa Yehovha hi nkarhi wa wona lowu vekiweke; munhu yoloye u ta rhwala xidyoho xa yena.’”' },
    { n: 14, text: '“‘Loko muhlaluhi o tshuka a tshama exikarhi ka n’wina, a lava ku endla Paseka eka Yehovha, u ta yi endla hi ku landza nawu wa Paseka ni mukhuva wa yona; mi ta va ni nawu wun’we, eka muhlaluhi ni le ka munhu wa le kaya.’”' },
    { n: 15, text: 'Hi siku leri tabernakela yi dzimiweke ha rona, nuvem yi funengeta tabernakela, ku nga tende ra vumbhoni; kasi hi nkarhi wa madyambu, a ku ri ni nchumu lowu fanaka ni ndzilo ehenhla ka tabernakela ku fikela nimixo.' },
    { n: 16, text: 'A swi tshama swi ri tano nkarhi hinkwaro: nuvem a yi yi funengeta ninhlikanhi, naswona ku fanaka ni ndzilo niusiku.' },
    { n: 17, text: 'Loko nuvem yi tlakuka ehenhla ka tende, endzhaku ka sweswo vana va Israyele a va famba; naswona endhawini leyi nuvem a yi tshama eka yona, vana va Israyele a va dzima mitenda ya vona.' },
    { n: 18, text: 'Hi ku landza rito ra Yehovha vana va Israyele a va famba, naswona hi ku landza rito ra Yehovha va dzima mitenda; hi masiku hinkwaswo lawa nuvem a yi tshama ehenhla ka tabernakela, va tshama va nga fambi.' },
    { n: 19, text: 'Hambi loko nuvem yi tshama masiku yo tala ehenhla ka tabernakela, vana va Israyele va hlayise rileriso ra Yehovha va nga fambi.' },
    { n: 20, text: 'Nkarhi wun’wana nuvem a yi tshama masiku ma nga ri mangasi ehenhla ka tabernakela; hi ku landza rito ra Yehovha va dzima mitenda, naswona hi ku landza rito ra Yehovha va famba.' },
    { n: 21, text: 'Nkarhi wun’wana nuvem a yi tshama ku suka hi nkarhi wa madyambu ku fikela nimixo; loko nuvem yi tlakuka nimixo, va famba; hambi ku ri ninhlikanhi kumbe niusiku, loko nuvem yi tlakuka, va famba.' },
    { n: 22, text: 'Hambi ku ri masiku mambirhi, kumbe n’weti, kumbe lembe, loko nuvem yi tshama ehenhla ka tabernakela, vana va Israyele va tshama va nga fambi; kambe loko yi tlakuka, va famba.' },
    { n: 23, text: 'Hi ku landza rito ra Yehovha va dzima mitenda, naswona hi ku landza rito ra Yehovha va famba; va hlayise rileriso ra Yehovha leri humeke hi voko ra Moxe.' }
  ],
  10: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Tiendlele timhalamhala timbirhi ta silivhere; u ta ti endla hi silivhere leyi furiweke, naswona ti ta ku tirhela ku hlengeleta nhlengeletano ni ku fambisa tikampa.”' },
    { n: 3, text: '“Loko ti tsimbiwa ti mambirhi, nhlengeletano hinkwayo yi ta hlengeletana eka wena enyangweni ya tabernakela ya nhlanganiso.”' },
    { n: 4, text: '“Kambe loko ku tsimbiwa yin’we ntsena, varhangeri, tinhloko ta magidi ya Israyele, va ta hlengeletana eka wena.”' },
    { n: 5, text: '“Loko mi tsimba hi rito ra ku tlhontlha, tikampa leti nga etlhelweni ra le vuxeni ti ta famba.”' },
    { n: 6, text: '“Loko mi tsimba hi rito ra ku tlhontlha ra vumbirhi, tikampa leti nga etlhelweni ra le dzongeni ti ta famba; va ta tsimba rito ra ku tlhontlha eku fambeni ka vona.”' },
    { n: 7, text: '“Kambe loko nhlengeletano yi fanele ku hlengeletana, mi ta tsimba, kambe mi nga tsimbi hi rito ra ku tlhontlha.”' },
    { n: 8, text: '“Vana va Aroni, vaprista, va ta tsimba timhalamhala; naswona lowu wu ta va nawu wa hilaha ku nga heriki eka n’wina hi ku landza tinxaka ta n’wina.”' },
    { n: 9, text: '“Loko mi ya enyimpini etikweni ra n’wina ku lwa ni nala loyi a mi xanisaka, mi ta tsimba rito ra ku tlhontlha hi timhalamhala; naswona mi ta tsundzukiwa mahlweni ka Yehovha Xikwembu xa n’wina, naswona mi ta ponisiwa eka valala va n’wina.”' },
    { n: 10, text: '“Hi siku ra ku tsaka ka n’wina, ni hi minkarhi ya n’wina leyi vekiweke, ni le masungulweni ya tin’weti ta n’wina, mi ta tsimba timhalamhala ehenhla ka minyikelo ya n’wina yo hisiwa, ni lehenhla ka magandzelo ya n’wina ya ku rhula; naswona ti ta va xitsundzuxo eka n’wina mahlweni ka Xikwembu xa n’wina; hi mina Yehovha Xikwembu xa n’wina.”' },
    { n: 11, text: 'Hi lembe ra vumbirhi, hi n’weti wa vumbirhi, hi siku ra makhume mambirhi ra n’weti, nuvem yi tlakuka ehenhla ka tabernakela ya vumbhoni.' },
    { n: 12, text: 'Vana va Israyele va famba va suka emananga ya Sinayi; nuvem yi tshama emananga ya Parani.' },
    { n: 13, text: 'Va rhanga va famba hi ku landza rito ra Yehovha leri humeke hi voko ra Moxe.' },
    { n: 14, text: 'Mujeko wa kampa ya vana va Yuda wu rhangile ku famba hi ku landza mavandla ya vona; murhangeri wa vandla ra yena a a ri Naxoni, n’wana wa Aminadaba.' },
    { n: 15, text: 'Ehenhla ka vandla ra nyimba ya vana va Isakara a ku ri Netanele, n’wana wa Zuara.' },
    { n: 16, text: 'Ehenhla ka vandla ra nyimba ya vana va Zebuloni a ku ri Eliyabu, n’wana wa Heloni.' },
    { n: 17, text: 'Loko tabernakela yi pshatliwa, vana va Gerixoni ni vana va Merari, lava a va rhwala tabernakela, va famba.' },
    { n: 18, text: 'Mujeko wa kampa ya Ruveni wu fambile hi ku landza mavandla ya vona; murhangeri wa vandla ra yena a a ri Elizuru, n’wana wa Xedeyure.' },
    { n: 19, text: 'Ehenhla ka vandla ra nyimba ya vana va Ximeyoni a ku ri Xelumiyele, n’wana wa Zurixadayi.' },
    { n: 20, text: 'Ehenhla ka vandla ra nyimba ya vana va Gadi a ku ri Eliyasafu, n’wana wa Dewele.' },
    { n: 21, text: 'Endzhaku Vakohata va famba va rhwele swilo leswo kwetsima; kasi lavanyana va dzima tabernakela va nga si fika.' },
    { n: 22, text: 'Mujeko wa kampa ya vana va Efrayimi wu fambile hi ku landza mavandla ya vona; murhangeri wa vandla ra yena a a ri Elixama, n’wana wa Amihudu.' },
    { n: 23, text: 'Ehenhla ka vandla ra nyimba ya vana va Manase a ku ri Gamaliyele, n’wana wa Pedasuri.' },
    { n: 24, text: 'Ehenhla ka vandla ra nyimba ya vana va Benjamini a ku ri Abidani, n’wana wa Gideyoni.' },
    { n: 25, text: 'Mujeko wa kampa ya vana va Dani, lowu a wu ri ntsengo wa tikampa hinkwato, wu fambile hi ku landza mavandla ya vona; murhangeri wa vandla ra yena a a ri Ahiyezeri, n’wana wa Amixadayi.' },
    { n: 26, text: 'Ehenhla ka vandla ra nyimba ya vana va Axere a ku ri Pagiyele, n’wana wa Okrani.' },
    { n: 27, text: 'Ehenhla ka vandla ra nyimba ya vana va Naftali a ku ri Ahira, n’wana wa Enani.' },
    { n: 28, text: 'Ndlela leyi vana va Israyele va fambeke ha yona hi ku landza mavandla ya vona hi yona leyi loko va famba.' },
    { n: 29, text: 'Moxe a ku eka Hobabu, n’wana wa Reguele wa Mumidiyani, n’wingi wa Moxe: “Hi le ku fambeni ku ya endhawini leyi Yehovha a vuleke a ku: ‘Ndzi ta mi nyika yona;’ tana na hina, naswona hi ta ku endlela leswinene, hikuva Yehovha u tshembise leswinene eka Israyele.”' },
    { n: 30, text: 'Kambe u ku eka yena: “Ndzi nga ka ndzi nga fambi; ndzi ta tlhelela etikweni ra mina ni le ka maxaka ya mina.”' },
    { n: 31, text: 'Moxe a ku: “Ndzi kombela u nga hi siyi, hikuva u tiva lomu hi nga dzimaka mitenda emananga, naswona u ta va mahlo ya hina.”' },
    { n: 32, text: '“Loko u famba na hina, swi ta va tano leswaku leswinene leswi Yehovha a nga ta hi endlela swona, hi ta ku endlela swona na wena.”' },
    { n: 33, text: 'Va famba va suka entshaveni ya Yehovha riendzo ra masiku manharhu; areka ya xinawu xa Yehovha yi fambile mahlweni ka vona riendzo ra masiku manharhu, ku va lavela ndhawu yo wisela.' },
    { n: 34, text: 'Nuvem ya Yehovha a yi ri ehenhla ka vona ninhlikanhi, loko va famba va suka ekampeni.' },
    { n: 35, text: 'Loko areka yi famba, Moxe a ku: “Pfuka, Yehovha, valala va wena va hangalasiwa, naswona lava va ku vengaka va tsutsuma mahlweni ka wena.”' },
    { n: 36, text: 'Loko yi wisela, u ku: “Tlhela, Yehovha, eka magidi ya magidi ya Israyele.”' }
  ],
  11: [
    { n: 1, text: 'Loko vanhu va n’unun’uta, swi tlhontlhe tindleve ta Yehovha; Yehovha a swi twa, ku hlunduka ka yena ku pfurha, ndzilo wa Yehovha wu pfurha exikarhi ka vona, wu herisa mahlalelo ya kampa.' },
    { n: 2, text: 'Vanhu va rilela Moxe; Moxe a khongela eka Yehovha, ndzilo wu miyela.' },
    { n: 3, text: 'A thya vito ra ndhawu yaleyo Tabera, hikuva ndzilo wa Yehovha wu pfurhile exikarhi ka vona.' },
    { n: 4, text: 'Ntshungu wa vahlaluhi lowu a wu ri exikarhi ka vona wu va ni ku navela lokukulu; vana va Israyele na vona va tlhela va rila, va ku: “I mani loyi a nga ta hi nyika nyama leswaku hi dya?”' },
    { n: 5, text: '“Hi tsundzuka tinhlampfi leti a hi ti dya eEgipta mahala; ni maganga, ni makatla, ni swinyala, ni swinyalana, ni swidlayana;”' },
    { n: 6, text: '“Kambe sweswi mimoya ya hina yi womile; a ku na nchumu, handle ka mana lowu ntsena mahlweni ka mahlo ya hina.”' },
    { n: 7, text: 'Mana a yi tano ku fana ni mbeu ya koriandere, naswona ku languteka ka yona a ku fana ni nchumu wa bedeliya.' },
    { n: 8, text: 'Vanhu a va hangalaka va yi hlengeleta, va yi sila hi masiyo kumbe va yi kandza hi mikandzo, va yi sweka hi timbita va endla swipapana ha yona; nantswo wa yona a wu fana ni nantswo wa mafurha lamantshwa.' },
    { n: 9, text: 'Loko mberha yi tsemeka ehenhla ka kampa niusiku, mana a yi tsemeka na yona.' },
    { n: 10, text: 'Moxe a twa vanhu va rila emindyangwini ya vona hinkwayo, un’wana ni un’wana enyangweni ya tende ra yena; ku hlunduka ka Yehovha ku pfurha swinene, naswona swi vangerile Moxe gome.' },
    { n: 11, text: 'Moxe a ku eka Yehovha: “Hikwalaho ka yini u xaniseke nandza wa wena? Hikwalaho ka yini ndzi nga kumangiki tintswalo emantlhanyeni ya wena, lerova u veka ndzhwalo wa vanhu lava hinkwavo eka mina?”' },
    { n: 12, text: '“Xana hi mina ndzi tshembiseke vanhu lava hinkwavo? Xana hi mina ndzi va tswaleke, lerova u ku eka mina: ‘Va rhwale exifuveni xa wena, tanihi n’wana loyi a an’wikiwa, u va yisa etikweni leri u hlambanyeleke vatata wa vona’?”' },
    { n: 13, text: '“Ndzi ta yi kuma kwihi nyama yo nyika vanhu lava hinkwavo? Hikuva va rila mahlweni ka mina, va ku: ‘Hi nyike nyama, hi dya!’”' },
    { n: 14, text: '“Ndzi nga ka ndzi nga swi koti ku rhwala vanhu lava hinkwavo ndzi ri ndzexe, hikuva va dunduma ngopfu eka mina.”' },
    { n: 15, text: '“Loko u ndzi endlela leswi, ndzi kombela u ndzi dlaya sweswi, loko ndzi kumile tintswalo emantlhanyeni ya wena; naswona ndzi nga tshuki ndzi vona khombo ra mina.”' },
    { n: 16, text: 'Yehovha a ku eka Moxe: “Ndzi hlengeletele makhume nkombo wa vavanuna exikarhi ka vakulukumba va Israyele, lava u va tivaka leswaku i vakulukumba va vanhu ni varhangeri va vona; u va tisa etabernakeleni ya nhlanganiso, va yima na wena kwalaho.”' },
    { n: 17, text: '“Ndzi ta fika ndzi vulavula na wena kwalaho; ndzi ta teka moya lowu nga eka wena ndzi wu veka eka vona; va ta rhwala ndzhwalo wa vanhu na wena, leswaku u nga wu rhwali u ri wexe.”' },
    { n: 18, text: '“U ta ku eka vanhu: ‘Tikwetsimiseni hi ku landza siku ra mundzuku, naswona mi ta dya nyama; hikuva mi rilile etindleveni ta Yehovha, mi ku: “I mani loyi a nga ta hi nyika nyama leswaku hi dya? Hikuva a hi tshamisekile eEgipta;” hikwalaho Yehovha u ta mi nyika nyama, naswona mi ta dya.’”' },
    { n: 19, text: '“‘Mi nga ka mi nga dyi siku rin’we ntsena, hambi ku ri masiku mambirhi, kumbe masiku ya ntlhanu, kumbe masiku ya khume, kumbe masiku ya makhume mambirhi;’”' },
    { n: 20, text: '“‘Kambe ku fikela n’weti hinkwayo, ku fikela loko yi huma hi tinhompfu ta n’wina, yi mi nyenyetsa; hikuva mi fularhele Yehovha loyi a nga exikarhi ka n’wina, naswona mi rilile mahlweni ka yena, mi ku: “Hikwalaho ka yini hi humile eEgipta?”’”' },
    { n: 21, text: 'Moxe a ku: “Vanhu lava ndzi nga exikarhi ka vona i makhume tsevu wa magidi ya vavanuna lava fambaka hi milenge; naswona wena u te: ‘Ndzi ta va nyika nyama, va dya n’weti hinkwayo!’”' },
    { n: 22, text: '“Xana ku ta dlayiwa ntlhambi wa tinyimpfu ni tihomu hikwalaho ka vona, leswaku swi va ringana? Kumbe tinhlampfi hinkwato ta lwandle ti ta hlengeletiwa hikwalaho ka vona, leswaku swi va ringana?”' },
    { n: 23, text: 'Yehovha a ku eka Moxe: “Xana voko ra Yehovha ri komile? Sweswi u ta vona loko rito ra mina ri ta endleka eka wena kumbe e-e.”' },
    { n: 24, text: 'Moxe a huma, a byela vanhu marito ya Yehovha; a hlengeleta makhume nkombo wa vavanuna exikarhi ka vakulukumba va vanhu, a va yimisa ematlhelo hinkwoho ya tende.' },
    { n: 25, text: 'Yehovha a fika hi nuvem, a vulavula na yena, a teka moya lowu a wu ri eka yena, a wu veka eka makhume nkombo wa vakulukumba; loko moya wu tshama eka vona, va sungula ku profeta, kambe a va ha thlelanga va endla tano.' },
    { n: 26, text: 'Kambe vavanuna vambirhi va salile ekampeni; vito ra un’wana a a ri Elidada, vito ra loyi un’wana a a ri Medada. Moya wu tshama eka vona; a va ri exikarhi ka lava va tsaleriweke, kambe a va nga yanga etendeni; va profeta ekampeni.' },
    { n: 27, text: 'Jaha rin’we ri tsutsuma ri byela Moxe, ri ku: “Elidada na Medada va profeta ekampeni.”' },
    { n: 28, text: 'Yoxuwa, n’wana wa Nuni, mutirheli wa Moxe ku sukela evuntshiseni bya yena, a hlamula a ku: “Hosi yanga Moxe, va tsimbe!”' },
    { n: 29, text: 'Kambe Moxe a ku eka yena: “Xana u na mavondzo hikwalaho ka mina? Kunene, hinkwavo vanhu va Yehovha a va ri vaprofeti, loko Yehovha a a veka moya wa yena ehenhla ka vona!”' },
    { n: 30, text: 'Moxe a tlhelela ekampeni, yena ni vakulukumba va Israyele.' },
    { n: 31, text: 'Mheho yi pfurha yi huma eka Yehovha, yi tisa swivandzana swa swicororana ku suka elwandle, yi swi wisela ehenhla ka kampa, kwalomu ka riendzo ra siku rin’we etlhelweni leri, ni riendzo ra siku rin’we etlhelweni lerini, ematlhelo hinkwoho ya kampa, naswona kwalomu ka timbiri ta swikonzo ku suka ehansi.' },
    { n: 32, text: 'Vanhu va pfuka hi siku rero hinkwaro, niusiku hinkwayo, ni siku leri landzeleke hinkwaro, va hlengeleta swivandzana swa swicororana; loyi a hlengeleteke ntsongo u hlengelete makhume ya homer; va swi andlalela hinkwako-hinkwako ematlhelo hinkwoho ya kampa.' },
    { n: 33, text: 'Loko nyama ya ha ri exikarhi ka meno ya vona, yi nga si dyeriwa, ku hlunduka ka Yehovha ku pfurha eka vanhu, Yehovha a lwa ni vanhu hi khombo lerikulu swinene.' },
    { n: 34, text: 'A thya vito ra ndhawu yaleyo Kibroti-Hatava, hikuva hi lomu va tlahleke vanhu lava a va ri ni ku navela lokukulu.' },
    { n: 35, text: 'Vanhu va suka eKibroti-Hatava va ya eHazeroti; naswona va tshama eHazeroti.' }
  ],
  12: [
    { n: 1, text: 'Miriame na Aroni va vulavula ku biha hi Moxe hikwalaho ka wansati wa le Kuxi loyi a n’wi tekeke; hikuva a a tekile wansati wa mukuxi.' },
    { n: 2, text: 'Va ku: “Xana Yehovha u vulavurile na Moxe ntsena ke? Xana na hina a nga vulavulanga na hina ke?” Yehovha a swi twa.' },
    { n: 3, text: 'Moxe a a ri munhu wo rhula swinene, ku tlula vanhu hinkwavo lava nga ehenhla ka misava.' },
    { n: 4, text: 'Hi nkarhi wolowo Yehovha a ku eka Moxe, na Aroni, na Miriame: “Humani mi famba mi ya etabernakeleni ya nhlanganiso, n’wina mi nharhu.” Va huma va ya va nharhu.' },
    { n: 5, text: 'Yehovha a fika hi nuvem, a yima enyangweni ya tende; a vitana Aroni na Miriame, va tshinela va vambirhi.' },
    { n: 6, text: 'A ku: “Yingisani marito ya mina: Loko ku ri ni muprofeti exikarhi ka n’wina, mina Yehovha ndzi ta tivekisa eka yena hi xivono, ndzi ta vulavula na yena hi norho.”' },
    { n: 7, text: '“Kambe a swi tano eka nandza wa mina Moxe; u tshembekile endlwini ya mina hinkwayo.”' },
    { n: 8, text: '“Ndzi vulavula na yena hi ku kongoma, hi ku n’wi kombisa swilo, ku nga ri hi swingolokolo; naswona u vona xivumbeko xa Yehovha. Hikwalaho ka yini mi nga chavangiki ku vulavula ku biha hi nandza wa mina Moxe?”' },
    { n: 9, text: 'Ku hlunduka ka Yehovha ku va pfurhela, a famba.' },
    { n: 10, text: 'Nuvem yi suka ehenhla ka tende; kutani Miriame a va ni lepra, a basa ku fana ni gamboko; Aroni a languta Miriame, a vona leswaku u ni lepra.' },
    { n: 11, text: 'Aroni a ku eka Moxe: “Oho hosi yanga, ndzi kombela u nga hi veki xidyoho lexi hi xi endleke hi vuphukuphuku ni hi ku dloha.”' },
    { n: 12, text: '“Ndzi kombela u nga n’wi tshiki a fana ni n’wana loyi a tswariweke a file, loyi nyama ya yena yi nga ha riki na xiphemu loko a huma khurini ra manana wakwe.”' },
    { n: 13, text: 'Moxe a tsemeka rito eka Yehovha, a ku: “Oho Xikwembu, ndzi kombela u n’wi hanyisa sweswi!”' },
    { n: 14, text: 'Yehovha a ku eka Moxe: “Loko tata wakwe a a n’wi thselele masiyo exihlandleni, xana a a nga ta khomiwa hi tingana masiku ya ntlhanu na mambirhi xana? A a hlayiseriwe ehandle ka kampa masiku ya ntlhanu na mambirhi, endzhaku ka sweswo a nga tlhela a amukeriwa.”' },
    { n: 15, text: 'Miriame a pfaleriwa ehandle ka kampa masiku ya ntlhanu na mambirhi; vanhu a va fambanga ku fikela loko Miriame a amukeriwa nakambe.' },
    { n: 16, text: 'Endzhaku ka sweswo vanhu va suka eHazeroti, va ya dzima mitenda emananga ya Parani.' }
  ],
  13: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Rhuma vavanuna leswaku va ya tlhasiya tiko ra Kanana, leri ndzi nga ta nyika vana va Israyele rona; u ta rhuma wanuna un’we wa nyimba yin’wana ni yin’wana ya vatata wa vona, un’wana ni un’wana a ri murhangeri exikarhi ka vona.”' },
    { n: 3, text: 'Moxe a va rhuma va suka emananga ya Parani hi ku landza rito ra Yehovha; vavanuna volavo hinkwavo a va ri tinhloko ta vana va Israyele.' },
    { n: 4, text: 'Mavito ya vona hi lawa: eka nyimba ya Ruveni a ku ri Xamuwa, n’wana wa Zakuru;' },
    { n: 5, text: 'eka nyimba ya Ximeyoni a ku ri Xafati, n’wana wa Hori;' },
    { n: 6, text: 'eka nyimba ya Yuda a ku ri Kalebe, n’wana wa Yefune;' },
    { n: 7, text: 'eka nyimba ya Isakara a ku ri Igali, n’wana wa Yosefa;' },
    { n: 8, text: 'eka nyimba ya Efrayimi a ku ri Hoxeya, n’wana wa Nuni;' },
    { n: 9, text: 'eka nyimba ya Benjamini a ku ri Paliti, n’wana wa Rafu;' },
    { n: 10, text: 'eka nyimba ya Zebuloni a ku ri Gadiyele, n’wana wa Sodi;' },
    { n: 11, text: 'eka nyimba ya Yosefa, ku nga ya nyimba ya Manase, a ku ri Gadi, n’wana wa Susi;' },
    { n: 12, text: 'eka nyimba ya Dani a ku ri Amiyele, n’wana wa Gemali;' },
    { n: 13, text: 'eka nyimba ya Axere a ku ri Seturu, n’wana wa Mikayele;' },
    { n: 14, text: 'eka nyimba ya Naftali a ku ri Nahebi, n’wana wa Vofisi;' },
    { n: 15, text: 'eka nyimba ya Gadi a ku ri Gewele, n’wana wa Maki.' },
    { n: 16, text: 'Mavito ya vavanuna lava Moxe a va rhumeke ku ya tlhasiya tiko hi lawa. Moxe a thya Hoxeya, n’wana wa Nuni, vito ra Yoxuwa.' },
    { n: 17, text: 'Loko Moxe a va rhuma ku ya tlhasiya tiko ra Kanana, a ku eka vona: “Tlakukani mi ya hi le dzongeni, mi ya fika entshaveni;”' },
    { n: 18, text: '“mi ya vona leswaku tiko ri tano, ni vanhu lava tshamaka eka rona, loko va ri ni matimba kumbe va tsanile, loko va ri vatsongo kumbe va tele;”' },
    { n: 19, text: '“ni leswaku tiko leri va tshamaka eka rona ri tano, loko ri ri rinene kumbe ro biha; ni miti leyi va tshamaka eka yona, loko yi ri emikampeni kumbe ekhokholweni;”' },
    { n: 20, text: '“ni leswaku misava yi tano, loko yi nonrile kumbe yi omile, loko ku ri ni mirhi eka yona kumbe e-e. Kombisani mbilu yo tshembeka, mi tisa mitsandzu ya tiko.” Nkarhi wolowo a ku ri nkarhi wa mitsandzu yo sungula ya vhinyo.' },
    { n: 21, text: 'Kutani va tlhandluka va ya tlhasiya tiko ku suka emananga ya Sini ku ya fika eRehobo, loko u ya eHamati.' },
    { n: 22, text: 'Va ya hi le dzongeni, va fika eHebroni, lomu ku nga na Ahimani, Xexayi na Talimayi, vana va Anaka. Hebroni a yi akiwile malembe ya nkombo mahlweni ka Sowani wa Egipta.' },
    { n: 23, text: 'Va fika enkoveni wa Exikolo, va tsema rhavi leri nga ni mitsandzu yin’we ya vhinyo, va yi rhwala hi mhandze va ri vambirhi; va tisa ni magaranada ni makuwa.' },
    { n: 24, text: 'Ndhawu yaleyo yi thyiwile nkoveni wa Exikolo hikwalaho ka mitsandzu ya vhinyo leyi vana va Israyele va yi tsemeke kwalaho.' },
    { n: 25, text: 'Endzhaku ka masiku ya makhume mambirhi na mambirhi, va tlhela va vuya hi ku ya tlhasiya tiko.' },
    { n: 26, text: 'Va famba va fika eka Moxe na Aroni ni le ka nhlengeletano hinkwayo ya vana va Israyele emananga ya Parani, eKadexi; va tisa rito eka vona ni le ka nhlengeletano hinkwayo, va va komba mitsandzu ya tiko.' },
    { n: 27, text: 'Va rungulela Moxe, va ku: “Hi fikile etikweni leri u hi rhumeke eka rona, hakunene ri khuluka ntswamba ni vulombe, naswona mitsandzu ya rona hi leyi.”' },
    { n: 28, text: '“Kambe vanhu lava tshamaka etikweni rero va ni matimba, naswona miti ya vona yi ni makhokholo lamakulu swinene; naswona hi vonile vana va Anaka kwalaho.”' },
    { n: 29, text: '“Vaamaleke va tshama etikweni ra le dzongeni; Vahete, Vayebusi na Vaamori va tshama entshaveni; kasi Vakanana va tshama elwandle ni le ntlhelo ka Yordani.”' },
    { n: 30, text: 'Kalebe a miyelisa vanhu mahlweni ka Moxe, a ku: “A hi tlhandlukeni sweswi hi ya fuma tiko rero, hikuva hi nga swi kota ku ri hlula.”' },
    { n: 31, text: 'Kambe vavanuna lava a va tlhandlukile na yena va ku: “A hi nge swi koti ku ya lwa ni vanhu volavo, hikuva va ni matimba ku tlula hina.”' },
    { n: 32, text: 'Va tisa rito ro biha ra tiko leri va yi tlhasayeke eka vana va Israyele, va ku: “Tiko leri hi hundzeke eka rona ku ya ri tlhasiya i tiko leri dlayaka vaaki va rona; naswona vanhu hinkwavo lava hi va voneke eka rona i vavanuna va swiyimo leswikulu.”' },
    { n: 33, text: '“Hi vone ni Vatsongonyana kwalaho, vana va Anaka lava humaka eka Vatsongonyana; emihlweni ya hina a hi fana ni tinjiya, naswona emihlweni ya vona a hi tano na hina.”' }
  ],
  14: [
    { n: 1, text: 'Nhlengeletano hinkwayo yi tlakusa rito ra yona yi tsemeka rito; vanhu va rila vusiku byebyo.' },
    { n: 2, text: 'Vana hinkwavo va Israyele va n’unun’utela Moxe na Aroni; nhlengeletano hinkwayo yi ku eka vona: “I khombo leswi hi nga fiki hi fela etikweni ra Egipta! Kumbe loko a hi file emananga lawa!”' },
    { n: 3, text: '“Hikwalaho ka yini Yehovha a hi tisa etikweni leri leswaku hi fela hi fumu, vavasati va hina ni vana va hina va va swivandzana? Xana a swi nga ri swinene eka hina ku tlhelela eEgipta?”' },
    { n: 4, text: 'Va vula un’wana ni un’wana eka un’wana, va ku: “A hi vekeni murhangeri, hi tlhelela eEgipta!”' },
    { n: 5, text: 'Kutani Moxe na Aroni va tiwisela hi swikandza swa vona ehansi mahlweni ka nhlengeletano hinkwayo ya vana va Israyele.' },
    { n: 6, text: 'Yoxuwa, n’wana wa Nuni, na Kalebe, n’wana wa Yefune, exikarhi ka lava va tlhasayeke tiko, va handzula tinguvu ta vona;' },
    { n: 7, text: 'va vulavula ni nhlengeletano hinkwayo ya vana va Israyele, va ku: “Tiko leri hi hundzeke eka rona ku ya ri tlhasiya i tiko rinene swinene.”' },
    { n: 8, text: '“Loko Yehovha a hi tsakela, u ta hi yisa etikweni leri, a hi nyika rona; tiko leri khulukaka ntswamba ni vulombe.”' },
    { n: 9, text: '“Ntsena mi nga pfukeli Yehovha, naswona mi nga chavi vanhu va tiko rero, hikuva i swinkwa swa hina; xisirelelo xa vona xi sukile eka vona, naswona Yehovha u na hina; mi nga va chavi!”' },
    { n: 10, text: 'Kambe nhlengeletano hinkwayo yi vula leswaku va fanele ku va khandla hi maribye. Kutani ku kwetsima ka Yehovha ku humelela etabernakeleni ya nhlanganiso eka vana hinkwavo va Israyele.' },
    { n: 11, text: 'Yehovha a ku eka Moxe: “Xana vanhu lava va ta hambeta va ndzi fularhela ku fikela rini? Xana va ta hambeta va nga ndzi tshembi ku fikela rini, hambi ku ri exikarhi ka swikombiso hinkwaswo leswi ndzi swi endleke exikarhi ka vona?”' },
    { n: 12, text: '“Ndzi ta va lwa hi khombo ra ntungu, ndzi va herisa, naswona ndzi ta ku endla wena u va nyimba leyikulu ni leyi nga ni matimba ku tlula vona.”' },
    { n: 13, text: 'Moxe a ku eka Yehovha: “Vaegipta va ta swi twa; hikuva u humese vanhu lava exikarhi ka vona hi matimba ya wena;”' },
    { n: 14, text: '“va ta swi rungulela vaaki va tiko leri. Va twile leswaku wena, Yehovha, u exikarhi ka vanhu lava, leswaku wena, Yehovha, u voniwa hi mahlomahlo, ni nuvem ya wena yi yimile ehenhla ka vona, ni leswaku u rhangela mahlweni ka vona hi nuvem ninhlikanhi ni hi ndzilo niusiku.”' },
    { n: 15, text: '“Loko u dlaye vanhu lava hinkwavo ku fana ni wanuna un’we, kutani matiko lawa ya tweke ndhuma ya wena ya ta vulavula, ya ku:”' },
    { n: 16, text: '“‘Hikwalaho ka ku kala Yehovha a nga swi kotanga ku yisa vanhu lava etikweni leri a va hlambanyeleke rona, u va dlayile emananga.’”' },
    { n: 17, text: '“Sweswi ndzi kombela leswaku matimba ya hosi yanga ya va lamakulu, hilaha u vuleke ha kona, u ku:”' },
    { n: 18, text: '“‘Yehovha u hlwela ku hlunduka, u tele tintswalo, u rivalela vuhlayi ni ku tsemeka ka nawu; kambe a nga tshiki nandzu wu nga ri na xigwevo, a tisa vuhlayi bya vatata ehenhla ka vana ku fikela eka xitukulwana xa vunharhu ni xa vumune.’”' },
    { n: 19, text: '“Ndzi kombela u rivalela vuhlayi bya vanhu lava hi ku landza vukulu bya tintswalo ya wena, hilaha u rivaleleke vanhu lava ku suka eEgipta ku fika sweswi.”' },
    { n: 20, text: 'Yehovha a ku: “Ndzi rivalele hi ku landza rito ra wena;”' },
    { n: 21, text: '“kambe hakunene, hilaha ndzi hanyaka ha kona, misava hinkwayo yi ta tala hi ku kwetsima ka Yehovha.”' },
    { n: 22, text: '“Hikuva vavanuna hinkwavo lava voneke ku kwetsima ka mina ni swikombiso swa mina leswi ndzi swi endleke eEgipta ni le mananga, kambe va ndzi ringeke makhume ya minkarhi lawa, va nga yingiseli rito ra mina;”' },
    { n: 23, text: '“hakunene a va nga nge ri voni tiko leri ndzi ri hlambanyeleke vatata wa vona, naswona hinkwavo lava va ndzi fularheleke a va nge ri voni.”' },
    { n: 24, text: '“Kambe nandza wa mina Kalebe, hikwalaho ka leswi a a ri ni moya wun’wana eka yena, a ndzi landzelerisaka hi mbilu hinkwayo, ndzi ta n’wi yisa etikweni leri a ngheneke eka rona, naswona vatukulu va yena va ta ri fuma.”' },
    { n: 25, text: '“Tanihi leswi Vaamaleke ni Vakanana va tshamaka enkoveni, mundzuku hundzulukani mi famba mi ya emananga hi ndlela ya Lwandle ro Tshuka.”' },
    { n: 26, text: 'Yehovha a vulavula na Moxe ni le ka Aroni, a ku:' },
    { n: 27, text: '“Ndzi ta hambeta ndzi tolerate nhlengeletano leyi yo biha leyi ndzi n’unun’utelaka ku fikela rini? Ndzi twile ku n’unun’uta loku vana va Israyele va ndzi n’unun’utelaka ha kona.”' },
    { n: 28, text: '“Byela vona u ku: ‘Hilaha ndzi hanyaka ha kona, ku vula Yehovha, hakunene hilaha mi vulavuleke ha kona etindleveni ta mina, ndzi ta endla tano eka n’wina;’”' },
    { n: 29, text: '“‘mintsumbu ya n’wina yi ta wela emananga lawa; naswona hinkwavo lava tsaleriweke eka n’wina, hi ku landza ntsengo wa n’wina hinkwawo, ku suka eka lava nga ni malembe ya makhume mambirhi ku ya ehenhla, lava va ndzi n’unun’uteleke;’”' },
    { n: 30, text: '“‘hakunene a mi nge ngheni etikweni leri ndzi tlakuseke voko ra mina ndzi hlambanya leswaku ndzi ta mi tshamisa eka rona, handle ka Kalebe, n’wana wa Yefune, na Yoxuwa, n’wana wa Nuni.’”' },
    { n: 31, text: '“‘Kasi vana va n’wina lava mi vuleke leswaku va ta va swivandzana, ndzi ta va nghenisa kwalaho, naswona va ta tiva tiko leri mi ri fularheleke.’”' },
    { n: 32, text: '“‘Kambe eka n’wina, mintsumbu ya n’wina yi ta wela emananga lawa.’”' },
    { n: 33, text: '“‘Vana va n’wina va ta va varisi emananga masiku ya makhume mune, va rhwala vugandzeri bya n’wina byo biha, ku fikela loko mintsumbu ya n’wina yi herisiwa emananga.’”' },
    { n: 34, text: '“‘Hi ku landza ntsengo wa masiku lawa mi tlhasayeke tiko ha kona, ku nga masiku ya makhume mune, siku rin’we ri emele lembe rin’we, mi ta rhwala vuhlayi bya n’wina malembe ya makhume mune, naswona mi ta tiva ku fularhela ka mina.’”' },
    { n: 35, text: '“‘Mina Yehovha ndzi vulavurile; hakunene ndzi ta endla tano eka nhlengeletano leyi hinkwayo yo biha leyi hlengeletaneke ku lwa na mina; va ta herisiwa emananga lawa, naswona hi lomu va nga ta fela kona.’”' },
    { n: 36, text: 'Vavanuna lava Moxe a va rhumeke ku ya tlhasiya tiko, lava vuyeke va n’unun’utisa nhlengeletano hinkwayo ku lwa na yena hi ku tisa rito ro biha ra tiko;' },
    { n: 37, text: 'vavanuna volavo lava tiseke rito ro biha ra tiko, va file hi khombo mahlweni ka Yehovha.' },
    { n: 38, text: 'Kambe Yoxuwa, n’wana wa Nuni, na Kalebe, n’wana wa Yefune, va ponile exikarhi ka vavanuna lava a va ye ku ya tlhasiya tiko.' },
    { n: 39, text: 'Moxe a byela vana hinkwavo va Israyele marito lawa; vanhu va rila ngopfu swinene.' },
    { n: 40, text: 'Va pfuka nimixo swinene, va tlhandluka va ya entshaveni, va ku: “Hi nava lava, hi ta tlhandluka hi ya endhawini yaleyo Yehovha a yi vuleke, hikuva hi dyohile.”' },
    { n: 41, text: 'Kambe Moxe a ku: “Hikwalaho ka yini mi tlula rileriso ra Yehovha sweswi? Swilo leswi a swi nge mi fambeli kahle.”' },
    { n: 42, text: '“Mi nga tlhandluki, hikuva Yehovha a nga exikarhi ka n’wina; leswaku mi nga dlayiwi mahlweni ka valala va n’wina.”' },
    { n: 43, text: '“Hikuva Vaamaleke ni Vakanana va kwalaho mahlweni ka n’wina, naswona mi ta fela hi fumu; tanihi leswi mi fularheleke Yehovha, Yehovha a nga nge vi na n’wina.”' },
    { n: 44, text: 'Kambe va fika va tikurisa va tlhandlukela ehenhla ka ntsandza; kambe areka ya xinawu xa Yehovha na Moxe a va sukanga exikarhi ka kampa.' },
    { n: 45, text: 'Kutani Vaamaleke ni Vakanana lava a va tshama entshaveni yaleyo va xika, va va lwa va va herisa ku fikela eHorma.' }
  ],
  15: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u ku eka vona: ‘Loko mi nghena etikweni ra vutshamo bya n’wina, leri ndzi nga ta mi nyika rona,’”' },
    { n: 3, text: '“‘naswona mi endla munyikelo hi ndzilo eka Yehovha, ku nga gandzelo ro hisiwa, kumbe gandzelo leri endliweke hi ku landza xihlambanyo lexi hlawulekeke, kumbe hi ku tirhandzela, kumbe hi minkarhi ya n’wina leyi vekiweke, leswaku mi endla risuna ro tsakisa eka Yehovha, ku suka ematshambini kumbe emitlhambini;’”' },
    { n: 4, text: '“‘kutani loyi a tisaka munyikelo wa yena u ta tisa eka Yehovha munyikelo wa mavele wa xiphemu xa khume xa efa ya fulawu leyinene, yi hlanganyisiwe ni xiphemu xa vumune xa hini ya mafurha;’”' },
    { n: 5, text: '“‘naswona u ta lulamisa vhinyo ya munyikelo wa swo nawa, ku nga xiphemu xa vumune xa hini, ehenhla ka gandzelo ro hisiwa kumbe ehenhla ka gandzelo, eka xinyimpfana xin’wana ni xin’wana.’”' },
    { n: 6, text: '“‘Kumbe eka khuna, u ta lulamisa munyikelo wa mavele wa swiphemu swimbirhi swa khume swa efa ya fulawu leyinene, yi hlanganyisiwe ni xiphemu xa vunharhu xa hini ya mafurha;’”' },
    { n: 7, text: '“‘naswona u ta tisa vhinyo ya munyikelo wa swo nawa, ku nga xiphemu xa vunharhu xa hini, tanihi risuna ro tsakisa eka Yehovha.’”' },
    { n: 8, text: '“‘Loko u lulamisa n’wana wa homu tanihi gandzelo ro hisiwa, kumbe gandzelo leri endliweke hi ku landza xihlambanyo lexi hlawulekeke, kumbe magandzelo ya ku rhula eka Yehovha;’”' },
    { n: 9, text: '“‘kutani u ta tisa ehenhla ka n’wana wa homu munyikelo wa mavele wa swiphemu swinharhu swa khume swa efa ya fulawu leyinene, yi hlanganyisiwe ni hafu ya hini ya mafurha;’”' },
    { n: 10, text: '“‘naswona u ta tisa vhinyo tanihi munyikelo wa swo nawa, ku nga hafu ya hini, tanihi munyikelo lowu endliweke hi ndzilo, wa risuna ro tsakisa eka Yehovha.’”' },
    { n: 11, text: '“‘Swi ta endliwa tano eka n’wana wa homu un’wana ni un’wana, kumbe eka khuna rin’wana ni rin’wana, kumbe eka xinyimpfana, kumbe eka ximburana.’”' },
    { n: 12, text: '“‘Hi ku landza ntsengo lowu mi nga ta wu lulamisa, mi ta endla tano eka un’wana ni un’wana hi ku landza ntsengo wa vona.’”' },
    { n: 13, text: '“‘Un’wana ni un’wana wa le kaya u ta endla swilo leswi hi ndlela leyi, loko a tisa munyikelo lowu endliweke hi ndzilo, wa risuna ro tsakisa eka Yehovha.’”' },
    { n: 14, text: '“‘Loko muhlaluhi o tshuka a tshama exikarhi ka n’wina, kumbe un’wana ni un’wana loyi a nga exikarhi ka n’wina hi ku landza tinxaka ta n’wina, a lava ku tisa munyikelo lowu endliweke hi ndzilo, wa risuna ro tsakisa eka Yehovha; hilaha mi endlaka ha kona, u ta endla tano na yena.’”' },
    { n: 15, text: '“‘Kuma nhlengeletano, ku ta va ni nawu wun’we eka n’wina ni le ka muhlaluhi loyi a tshamaka na n’wina; wu ta va nawu wa hilaha ku nga heriki hi ku landza tinxaka ta n’wina; mahlweni ka Yehovha muhlaluhi u ta fana na n’wina.’”' },
    { n: 16, text: '“‘Nawu wun’we ni xileriso xin’we swi ta va eka n’wina ni le ka muhlaluhi loyi a tshamaka na n’wina.’”' },
    { n: 17, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 18, text: '“Vulavula ni vana va Israyele, u ku eka vona: ‘Loko mi nghena etikweni leri ndzi mi yisaka eka rona,’”' },
    { n: 19, text: '“‘swi ta endleka leswaku, loko mi dya xinkwa xa tiko, mi ta tlakusela Yehovha munyikelo lowu tlakusiweke.’”' },
    { n: 20, text: '“‘Mi ta humesa xipapana xakwe xo sungula xa hlama ya n’wina tanihi munyikelo lowu tlakusiweke; hilaha mi endlaka ha kona hi munyikelo lowu tlakusiweke wa xivuyu, mi ta endla tano ha xona.’”' },
    { n: 21, text: '“‘Eka hlama ya n’wina yo sungula mi ta nyika Yehovha munyikelo lowu tlakusiweke hi ku landza tinxaka ta n’wina.’”' },
    { n: 22, text: '“‘Loko o tshuka mi dyohile handle ka vomu, mi nga landzi milawu leyi hinkwayo leyi Yehovha a yi vulavuleke na Moxe;’”' },
    { n: 23, text: '“‘hinkwaswo leswi Yehovha a mi leriseke swona hi voko ra Moxe, ku sukela hi siku leri Yehovha a leriseke ha rona, ni ku ya mahlweni hi ku landza tinxaka ta n’wina;’”' },
    { n: 24, text: '“‘kutani ku ta endleka leswaku, loko swi endliwile handle ka vomu, swi nga tiviwi hi nhlengeletano, nhlengeletano hinkwayo yi ta tisa n’wana wa homu un’we tanihi gandzelo ro hisiwa, ra risuna ro tsakisa eka Yehovha, ni munyikelo wa rona wa mavele, ni munyikelo wa rona wa swo nawa hi ku landza xileriso, ni ximburana xin’we xa mbuti tanihi gandzelo ra xidyoho.’”' },
    { n: 25, text: '“‘Muprista u ta endla ku tlhelisela xidyoho eka nhlengeletano hinkwayo ya vana va Israyele, naswona va ta rivaleriwa; hikuva a ku ri xidyoho xa handle ka vomu, naswona va tisele Yehovha munyikelo wa vona lowu endliweke hi ndzilo, ni gandzelo ra vona ra xidyoho mahlweni ka Yehovha hikwalaho ka xidyoho xa vona xa handle ka vomu;’”' },
    { n: 26, text: '“‘kutani nhlengeletano hinkwayo ya vana va Israyele yi ta rivaleriwa, ni muhlaluhi loyi a tshamaka exikarhi ka vona; hikuva vanhu hinkwavo a va ri exidyoheni xa handle ka vomu.’”' },
    { n: 27, text: '“‘Loko munhu un’we o tshuka a dyohile handle ka vomu, u ta tisa mbuti ya ntsandza ya lembe rin’we tanihi gandzelo ra xidyoho.’”' },
    { n: 28, text: '“‘Muprista u ta endla ku tlhelisela xidyoho mahlweni ka Yehovha eka munhu loyi a dyoheke handle ka vomu, loko a dyohile handle ka vomu, leswaku a tlhelisela xidyoho xa yena, naswona u ta rivaleriwa.’”' },
    { n: 29, text: '“‘Mi ta va ni nawu wun’we eka loyi a endlaka xidyoho xa handle ka vomu, eka munhu wa le kaya exikarhi ka vana va Israyele ni le ka muhlaluhi loyi a tshamaka exikarhi ka vona.’”' },
    { n: 30, text: '“‘Kambe munhu loyi a endlaka nchumu hi vomu, hambi i munhu wa le kaya kumbe muhlaluhi, munhu yoloye u sandza Yehovha; naswona munhu yoloye u ta dlayiwa exikarhi ka vanhu va ka vona;’”' },
    { n: 31, text: '“‘hikuva u fularhele rito ra Yehovha, naswona u tsemile rileriso ra yena; munhu yoloye u ta dlayiwa hakunene, naswona vuhlayi bya yena byi ta va ehenhla ka yena.’”' },
    { n: 32, text: 'Loko vana va Israyele va ha ri emananga, va kuma wanuna un’wana a hlengeleta tinhlanga hi siku ra Savata.' },
    { n: 33, text: 'Lava n’wi kumeke a hlengeleta tinhlanga va n’wi tisa eka Moxe, na Aroni, ni le ka nhlengeletano hinkwayo;' },
    { n: 34, text: 'va n’wi hlayisa khotsweni, hikuva a ku nga si tiveka leswi faneleke ku endliwa hi yena.' },
    { n: 35, text: 'Yehovha a ku eka Moxe: “Wanuna loyi u ta dlayiwa hakunene; nhlengeletano hinkwayo yi ta n’wi khandla hi maribye ehandle ka kampa.”' },
    { n: 36, text: 'Nhlengeletano hinkwayo yi n’wi humesela ehandle ka kampa, yi n’wi khandla hi maribye, a fa, hilaha Yehovha a leriseke Moxe ha kona.' },
    { n: 37, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 38, text: '“Vulavula ni vana va Israyele, u ku eka vona leswaku va tiendlela makumu emakumu ya tinguvu ta vona hi ku landza tinxaka ta vona, naswona va ta veka xintambana xa wasasi emakumini wun’wana ni wun’wana;”' },
    { n: 39, text: '“xona xi ta va makumu eka n’wina, leswaku mi xi languta, mi tsundzuka milawu hinkwayo ya Yehovha mi yi endla; naswona mi nga landzeleri timbilu ta n’wina ni mahlo ya n’wina, leswi mi tsendzelekaka ha swona;”' },
    { n: 40, text: '“leswaku mi tsundzuka mi endla milawu ya mina hinkwayo, naswona mi va lava kwetsimaka eka Xikwembu xa n’wina.”' },
    { n: 41, text: '“Hi mina Yehovha Xikwembu xa n’wina, loyi a mi humeseke etikweni ra Egipta leswaku ndzi va Xikwembu xa n’wina; hi mina Yehovha Xikwembu xa n’wina.”' }
  ],
  16: [
    { n: 1, text: 'Kora, n’wana wa Isari, n’wana wa Kohata, n’wana wa Levi, a ri na Datani na Abirami, vana va Eliyabu, na Oni, n’wana wa Peleti, vana va Ruveni, va dloha;' },
    { n: 2, text: 'va pfukela Moxe, va ri na vavanuna va vana va Israyele va makhume mambirhi na mambirhi na makhume ntlhanu, lava a va ri varhangeri va nhlengeletano, vavanuna va ndhuma lava vitaniwaka enhlengeletanweni;' },
    { n: 3, text: 'va hlengeletana ku lwa na Moxe na Aroni, va ku eka vona: “Swa mi ringana, hikuva nhlengeletano hinkwayo yi kwetsimile, un’wana ni un’wana wa vona, naswona Yehovha u exikarhi ka vona; hikwalaho ka yini mi titlakusa ehenhla ka nhlengeletano ya Yehovha?”' },
    { n: 4, text: 'Loko Moxe a swi twa, a tiwisela hi xikandza ehansi;' },
    { n: 5, text: 'a vulavula na Kora ni le ka ntshungu wa yena hinkwawo, a ku: “Mundzuku nimixo Yehovha u ta komba loyi a nga wa yena, ni loyi a kwetsimaka, naswona u ta n’wi tshineta eka yena; loyi a n’wi hlawuleke u ta n’wi tshineta eka yena.”' },
    { n: 6, text: '“Endlani leswi: Tekani switshatshari, wena Kora ni ntshungu wa wena hinkwawo;”' },
    { n: 7, text: '“mi veka ndzilo eka swona, mi veka ni murhi wa risuna eka swona mahlweni ka Yehovha mundzuku; kutani wanuna loyi Yehovha a nga ta n’wi hlawula u ta va loyi a kwetsimaka. Swa mi ringana, n’wina vana va Levi!”' },
    { n: 8, text: 'Moxe a ku eka Kora: “Ndzi kombela mi yingisa, n’wina vana va Levi:”' },
    { n: 9, text: '“Xana i nchumu lowutsongo eka n’wina leswi Xikwembu xa Israyele xi mi hlawuleke exikarhi ka nhlengeletano ya Israyele, xi mi tshineta eka xona leswaku mi endla vutireli bya tabernakela ya Yehovha, ni ku yima mahlweni ka nhlengeletano ku va tirhela?”' },
    { n: 10, text: '“Xana xi ku tshinete eka xona, wena ni vamakwenu hinkwavo vana va Levi na wena? Naswona xana mi lava ni vuprista na byona?”' },
    { n: 11, text: '“Hikwalaho wena ni ntshungu wa wena hinkwawo mi hlengeletanile ku lwa na Yehovha; hikuva Aroni i mani leswaku mi n’wi n’unun’utela?”' },
    { n: 12, text: 'Moxe a rhuma vanhu ku ya vitana Datani na Abirami, vana va Eliyabu; kambe va ku: “A hi nge tlhandluki;”' },
    { n: 13, text: '“xana i nchumu lowutsongo leswi u hi humeseke etikweni leri khulukaka ntswamba ni vulombe leswaku u hi dlayela emananga, leswaku u ta tlhela u tiendla hosi ehenhla ka hina?”' },
    { n: 14, text: '“Ku tlula sweswo, a u hi yisanga etikweni leri khulukaka ntswamba ni vulombe, kumbe ku hi nyika ndzhaka ya masimu ni vhinyo. Xana u ta xika mahlo ya vavanuna lava? A hi nge tlhandluki!”' },
    { n: 15, text: 'Moxe a hlunduka swinene, a ku eka Yehovha: “U nga languti munyikelo wa vona wa mavele; a ndzi tekanga hambi ku ri mbongolo yin’we eka vona, naswona a ndzi endlelanga hambi ku ri un’wana wa vona swo biha.”' },
    { n: 16, text: 'Moxe a ku eka Kora: “Wena ni ntshungu wa wena hinkwawo mi ta va mahlweni ka Yehovha mundzuku, wena, na vona, na Aroni;”' },
    { n: 17, text: '“un’wana ni un’wana u ta teka xitshatshari xa yena, a veka murhi wa risuna eka xona, naswona un’wana ni un’wana u ta tisa xitshatshari xa yena mahlweni ka Yehovha, ku nga switshatshari swa makhume mambirhi na mambirhi na makhume ntlhanu; na wena na Aroni, un’wana ni un’wana a ri ni xitshatshari xa yena.”' },
    { n: 18, text: 'Kutani un’wana ni un’wana a teka xitshatshari xa yena, va veka ndzilo eka swona, va veka ni murhi wa risuna eka swona, va yima enyangweni ya tabernakela ya nhlanganiso va ri na Moxe na Aroni.' },
    { n: 19, text: 'Kora a hlengeleta nhlengeletano hinkwayo ku lwa na vona enyangweni ya tabernakela ya nhlanganiso; kutani ku kwetsima ka Yehovha ku humelela eka nhlengeletano hinkwayo.' },
    { n: 20, text: 'Yehovha a vulavula na Moxe na Aroni, a ku:' },
    { n: 21, text: '“Tihambaniseni exikarhi ka nhlengeletano leyi, leswaku ndzi va herisa hi xitshuketa.”' },
    { n: 22, text: 'Va tiwisela hi swikandza ehansi, va ku: “Oho Xikwembu, Xikwembu xa mimoya ya nyama hinkwayo, xana loko wanuna un’we o dyoha, u ta hlundukela nhlengeletano hinkwayo xana?”' },
    { n: 23, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 24, text: '“Vulavula ni nhlengeletano, u ku: ‘Tshamelani ekule ni matitshamelo ya Kora, Datani na Abirami.’”' },
    { n: 25, text: 'Moxe a pfuka, a ya eka Datani na Abirami; vakulukumba va Israyele va n’wi landzela.' },
    { n: 26, text: 'A vulavula ni nhlengeletano, a ku: “Ndzi kombela mi suka emitendeni ya vavanuna lava va hombolokeke, naswona mi nga khumbi nchumu wa vona, leswaku mi nga herisiwi exidyohweni xa vona hinkwaswo.”' },
    { n: 27, text: 'Kutani va suka ematlhelo hinkwoho ya matitshamelo ya Kora, Datani na Abirami; Datani na Abirami va huma va yima enyangweni ya mitenda ya vona, va ri na vasati va vona, ni vana va vona, ni vana va vona lavatsongo.' },
    { n: 28, text: 'Moxe a ku: “Hi leswi mi nga ta tiva leswaku Yehovha u ndzi rhumile ku endla mintirho leyi hinkwayo, ni leswaku a yi humi embilwini ya mina:”' },
    { n: 29, text: '“‘Loko vavanuna lava va fela ku fana ni vanhu hinkwavo, kumbe loko va tiseriwa hi khombo leri welaka vanhu hinkwavo, kutani Yehovha a nga ndzi rhumanga.’”' },
    { n: 30, text: '“‘Kambe loko Yehovha o endla nchumu lowuntshwa, misava yi pfula nomu wa yona, yi va mita va ni hinkwaswo leswi nga swa vona, va xikela emunyameni va ha hanya, kutani mi ta tiva leswaku vavanuna lava va fularhele Yehovha.’”' },
    { n: 31, text: 'Kuteloko a hete ku vulavula marito lawa hinkwaswo, misava leyi a yi ri ehansi ka vona yi handzukanyana;' },
    { n: 32, text: 'misava yi pfula nomu wa yona, yi va mita na tiyindlu ta vona, ni vanhu hinkwavo va Kora, ni swilo hinkwaswo swa vona.' },
    { n: 33, text: 'Va xika va ha hanya na hinkwaswo leswi a swi ri swa vona emunyameni; misava yi va funengeta, va lahleka exikarhi ka nhlengeletano.' },
    { n: 34, text: 'Israyele hinkwayo leyi a yi ri ematlhelo ya vona va tsutsuma loko va twa mampfapfarhuta ya vona, hikuva va ku: “Hi nga tshuki hi miteriwa hi misava na hina.”' },
    { n: 35, text: 'Kutani ku huma ndzilo eka Yehovha, wu herisa vavanuna va makhume mambirhi na mambirhi na makhume ntlhanu lava a va tise murhi wa risuna.' },
    { n: 36, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 37, text: '“Byela Eliyazara, n’wana wa Aroni wa muprista, leswaku a teka switshatshari exikarhi ka ndzilo lowu pfurhaka, naswona u ta hangalasa ndzilo etlhelo, hikuva swi kwetsimile;”' },
    { n: 38, text: '“switshatshari swa vavanuna lava va dyoheleke mimoya ya vona. A va endle swiphemu swo andlala swa ku funengeta altari; hikuva va swi tise mahlweni ka Yehovha, hikwalaho swi kwetsimile; naswona swi ta va xikombiso eka vana va Israyele.”' },
    { n: 39, text: 'Eliyazara wa muprista a teka switshatshari swa nsuku leswi vavanuna lava hisiweke va swi tiseke, va swi fula swi va swiphemu swo andlala swa ku funengeta altari;' },
    { n: 40, text: 'leswaku swi va xitsundzuxo eka vana va Israyele, leswaku ku nga tshuki ku nghena munhu un’wana loyi a nga riki wa vatukulu va Aroni mahlweni ka Yehovha ku hisa murhi wa risuna, leswaku a nga fani na Kora ni ntshungu wa yena, hilaha Yehovha a n’wi byeleke ha kona hi voko ra Moxe.' },
    { n: 41, text: 'Hi siku leri landzeleke nhlengeletano hinkwayo ya vana va Israyele yi n’unun’utela Moxe na Aroni, yi ku: “N’wina mi dlayile vanhu va Yehovha.”' },
    { n: 42, text: 'Kuteloko nhlengeletano yi hlengeletanile ku lwa na Moxe na Aroni, va languta etabernakeleni ya nhlanganiso; kutani nuvem yi yi funengeta, naswona ku kwetsima ka Yehovha ku humelela.' },
    { n: 43, text: 'Moxe na Aroni va fika mahlweni ka tabernakela ya nhlanganiso.' },
    { n: 44, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 45, text: '“Sukani exikarhi ka nhlengeletano leyi, leswaku ndzi va herisa hi xitshuketa.” Va tiwisela hi swikandza ehansi.' },
    { n: 46, text: 'Moxe a ku eka Aroni: “Teka xitshatshari, u veka ndzilo eka xona wa le altari, u veka ni murhi wa risuna eka xona, u hatlisa u ya eka nhlengeletano, u va tlhelisela xidyoho; hikuva ku hlunduka ku humile mahlweni ka Yehovha; ntungu wu sungurile.”' },
    { n: 47, text: 'Aroni a teka xitshatshari hilaha Moxe a vuleke ha kona, a tsutsumela exikarhi ka nhlengeletano; kutani ntungu a wu sungurile exikarhi ka vanhu; a veka murhi wa risuna, a tlhelisela xidyoho eka vanhu.' },
    { n: 48, text: 'A yima exikarhi ka lava va feke ni lava va hanyaka, kutani ntungu wu miyela.' },
    { n: 49, text: 'Lava feke hi ntungu a va ri khume mune wa magidi na magidi ya nkombo, handle ka lava va feke hikwalaho ka mhaka ya Kora.' },
    { n: 50, text: 'Aroni a tlhelela eka Moxe enyangweni ya tabernakela ya nhlanganiso, kutani ntungu wu miyerile.' }
  ],
  17: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Vulavula ni vana va Israyele, u teka tinhonga eka vona, nhonga yin’we eka yindlu yin’wana ni yin’wana ya vatata, eka varhangeri va vona hinkwavo hi ku landza tiyindlu ya vatata wa vona, ku nga tinhonga ta khume na timbirhi; u ta tsala vito ra un’wana ni un’wana enhongeni ya yena.”' },
    { n: 3, text: '“U ta tsala vito ra Aroni enhongeni ya Levi; hikuva ku ta va ni nhonga yin’we eka nhloko ya yindlu ya vatata wa vona.”' },
    { n: 4, text: '“U ta ti veka etabernakeleni ya nhlanganiso mahlweni ka vumbhoni, lomu ndzi hlanganyelaka na n’wina kona.”' },
    { n: 5, text: '“Kutani nhonga ya wanuna loyi ndzi nga ta n’wi hlawula yi ta hluka; naswona ndzi ta herisa ku n’unun’uta loku vana va Israyele va mi n’unun’utelaka ha kona mahlweni ka mina.”' },
    { n: 6, text: 'Moxe a vulavula ni vana va Israyele, tinhloko ta vona hinkwato ti n’wi nyika tinhonga, nhonga yin’we eka murhangeri un’wana ni un’wana, hi ku landza tiyindlu ya vatata wa vona, ku nga tinhonga ta khume na timbirhi; naswona nhonga ya Aroni a yi ri exikarhi ka tinhonga ta vona.' },
    { n: 7, text: 'Moxe a veka tinhonga mahlweni ka Yehovha etabernakeleni ya vumbhoni.' },
    { n: 8, text: 'Hi siku leri landzeleke Moxe a nghena etabernakeleni ya vumbhoni; kutani nhonga ya Aroni ya yindlu ya Levi a yi hlukile, yi bumbula swiluva, yi humesa swiluva, yi dzwala amandza.' },
    { n: 9, text: 'Moxe a humesa tinhonga hinkwato mahlweni ka Yehovha a ti yisa eka vana hinkwavo va Israyele; va ti languta, un’wana ni un’wana a teka nhonga ya yena.' },
    { n: 10, text: 'Yehovha a ku eka Moxe: “Tlhela u veka nhonga ya Aroni mahlweni ka vumbhoni, yi ta hlayiseriwa ku va xikombiso eka vana va ku pfukela, leswaku u herisa ku n’unun’uta ka vona mahlweni ka mina, va nga fi.”' },
    { n: 11, text: 'Moxe a endla tano; hilaha Yehovha a n’wi leriseke ha kona, a endla tano.' },
    { n: 12, text: 'Vana va Israyele va vulavula na Moxe, va ku: “Hi nava lava, hi le ku feni, hi herisiwile, hinkwerhu ka hina hi herisiwile!”' },
    { n: 13, text: '“Un’wana ni un’wana loyi a tshinela, loyi a tshinela eka tabernakela ya Yehovha, u ta fa. Xana hi ta dlayiwa hinkwerhu ka hina ku fikela loko hi hela?”' }
  ],
  18: [
    { n: 1, text: 'Yehovha a ku eka Aroni: “Wena, ni vana va wena, ni yindlu ya tata wa wena na wena mi ta rwala vuhomboloki bya ndhawu yo kwetsima; naswona wena ni vana va wena na wena mi ta rwala vuhomboloki bya vuprista bya n’wina.”' },
    { n: 2, text: '“Kambe ni vamakwenu va nyimba ya Levi, ku nga nyimba ya tata wa wena, va tshinete na wena, leswaku va ku landzela va ku tirhela; kasi wena ni vana va wena na wena mi ta va mahlweni ka tabernakela ya vumbhoni.”' },
    { n: 3, text: '“Va ta hlayisa vutihlamuleri bya wena ni vutihlamuleri bya tabernakela hinkwayo; kambe va nga tshuki va tshinela eka swibya swa ndhawu yo kwetsima ni le ka altari, leswaku va nga fi, hambi va ri vona kumbe n’wina.”' },
    { n: 4, text: '“Va ta hlanganyela na wena, va hlayisa vutihlamuleri bya tabernakela ya nhlanganiso, ematireleni hinkwawo ya tabernakela; naswona munhu un’wana loyi a nga riki wa kona a nga ka a nga tshineli eka n’wina.”' },
    { n: 5, text: '“Mi ta hlayisa vutihlamuleri bya ndhawu yo kwetsima ni vutihlamuleri bya altari, leswaku ku nga ha humeleli vukarhi eka vana va Israyele.”' },
    { n: 6, text: '“Hi mina loyi a tekeke vamakwenu va Levita exikarhi ka vana va Israyele; i nyiko eka n’wina, va nyikiwile Yehovha, leswaku va endla vutireli bya tabernakela ya nhlanganiso.”' },
    { n: 7, text: '“Kutani wena ni vana va wena na wena mi ta hlayisa vuprista bya n’wina eka hinkwaswo leswi nga swa altari ni swa le ndzeni ka kortina; mi ta endla vutireli byebyo. Ndzi mi nyika vuprista tanihi vutireli bya nyiko; naswona muhlaluhi loyi a tshinelaka u ta dlayiwa.”' },
    { n: 8, text: 'Yehovha a vulavula na Aroni, a ku: “Hi mina loyi a ku nyikeke vutihlamuleri bya minyikelo ya mina leyi tlakusiweke, eka swilo hinkwaswo swo kwetsima swa vana va Israyele; ndzi swi nyike wena ni vana va wena ku va xiphemu xa n’wina, ku va nawu wa hilaha ku nga heriki.”' },
    { n: 9, text: '“Leswi swi ta va swa wena eka swilo swo kwetsima swinene, leswi nga si tswariwa hi ndzilo: minyikelo ya vona hinkwayo, ni minyikelo ya vona hinkwayo ya mavele, ni minyikelo ya vona hinkwayo ya xidyoho, ni minyikelo ya vona hinkwayo ya nandzu, leyi va nga ta yi buyisela eka mina, yi ta va nchumu lowu kwetsimaka swinene eka wena ni le ka vana va wena.”' },
    { n: 10, text: '“U ta swi dyela endhawuni yo kwetsima swinene; xinuna hinkwaxo xi ta swi dya; xi ta va nchumu wo kwetsima eka wena.”' },
    { n: 11, text: '“Leswi na swona i swa wena: nyiko ya minyikelo ya vona leyi tlakusiweke, xikan’we ni minyikelo hinkwayo leyi tsetseriweke ya vana va Israyele; ndzi swi nyike wena, ni vana va wena va majaha ni va vanhwanyana na wena, ku va nawu wa hilaha ku nga heriki; un’wana ni un’wana loyi a tengeke endlwini ya wena u ta swi dya.”' },
    { n: 12, text: '“Mafurha hinkwawo lamanene, ni vhinyo hinkwayo leyinene, ni mavele lamanene, ku nga swiluva swo sungula swa leswi va swi nyikaka Yehovha, ndzi swi nyike wena.”' },
    { n: 13, text: '“Switshuriwa swo sungula swo vupfa swa hinkwaswo leswi nga etikweni ra vona, leswi va nga ta swi tisa eka Yehovha, swi ta va swa wena; un’wana ni un’wana loyi a tengeke endlwini ya wena u ta swi dya.”' },
    { n: 14, text: '“Nchumu hinkwaswo lowu hlawuriweke eIsrayele wu ta va wa wena.”' },
    { n: 15, text: '“Un’wana ni un’wana loyi a pfulaka mbeleko wa nyama hinkwayo, lowu va nga ta wu tisa eka Yehovha, hambi i wa vanhu kumbe wa swifuwo, wu ta va wa wena; kambe u ta kutsula mativula ya vanhu hakunene, ni mativula ya swifuwo leswi nga tengeki u ta kutsula.”' },
    { n: 16, text: '“Lava faneleke ku kutsuriwa u ta va kutsula loko va ri ni n’hweti yin’we, hi ku landza ntsengo lowu u nga ta wu veka, ku nga tixekele ta ntlhanu ta silivhere, hi ku landza xekele ya ndhawu yo kwetsima, leyi nga ni magera ya makhume mambirhi.”' },
    { n: 17, text: '“Kambe u nga tshuki u kutsula tivula ra homu, kumbe tivula ra xinyimpfana, kumbe tivula ra mbuti; swi kwetsimile. U ta tsetsera ngati ya swona ealtari, naswona u ta hisa mafurha ya swona tanihi munyikelo lowu endliweke hi ndzilo, wa risuna ro tsakisa eka Yehovha.”' },
    { n: 18, text: '“Nyama ya swona yi ta va ya wena, ku fana ni xifuva xa ku tsetseriwa ni voko ra xinene, swi ta va swa wena.”' },
    { n: 19, text: '“Minyikelo hinkwayo leyi tlakusiweke ya swilo swo kwetsima, leyi vana va Israyele va yi tlakuselaka Yehovha, ndzi yi nyike wena, ni vana va wena va majaha ni va vanhwanyana na wena, ku va nawu wa hilaha ku nga heriki; i ntwanano wa munyu wa hilaha ku nga heriki mahlweni ka Yehovha eka wena ni le ka mbewu ya wena na wena.”' },
    { n: 20, text: 'Yehovha a ku eka Aroni: “A u nga vi ni ndzhaka etikweni ra vona, naswona a u nga vi ni xiphemu exikarhi ka vona; hi mina xiphemu xa wena ni ndzhaka ya wena exikarhi ka vana va Israyele.”' },
    { n: 21, text: '“Kasi eka vana va Levi, ndzi va nyike xiphemu xin’we xa khume eIsrayele ku va ndzhaka, hikwalaho ka vutireli bya vona lebyi va byi endlaka, ku nga vutireli bya tabernakela ya nhlanganiso.”' },
    { n: 22, text: '“Kutani vana va Israyele va nga ha tshuki va tshinela eka tabernakela ya nhlanganiso, leswaku va nga rwali xidyoho va fa.”' },
    { n: 23, text: '“Kambe va-Levita va ta endla vutireli bya tabernakela ya nhlanganiso, naswona va ta rwala vuhomboloki bya vona; wu ta va nawu wa hilaha ku nga heriki hi ku landza tinxaka ta n’wina; exikarhi ka vana va Israyele va nga ka va nga kumi ndzhaka.”' },
    { n: 24, text: '“Hikuva xiphemu xa khume xa vana va Israyele, lexi va xi tlakuselaka Yehovha tanihi munyikelo lowu tlakusiweke, ndzi xi nyike va-Levita ku va ndzhaka; hikwalaho ndzi vuleke eka vona ndzi ku: ‘A va nga kumi ndzhaka exikarhi ka vana va Israyele.’”' },
    { n: 25, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 26, text: '“U ta vulavula na va-Levita, u ku eka vona: ‘Loko mi teka eka vana va Israyele xiphemu xa khume lexi ndzi mi nyikeke xona ku suka eka vona ku va ndzhaka ya n’wina, kutani mi ta humesa eka xona munyikelo lowu tlakusiweke eka Yehovha, ku nga xiphemu xa khume xa xiphemu xa khume.’”' },
    { n: 27, text: '“‘Munyikelo wa n’wina lowu tlakusiweke mi ta hlayiseriwa wona ku fana ni mavele ya xivuyu ni ku fana ni ku tala ka xikamelo xa vhinyo.’”' },
    { n: 28, text: '“‘Hi ndlela yoleyo n’wina na mi ta humesela Yehovha munyikelo lowu tlakusiweke eka swiphemu hinkwaswo swa n’wina swa khume, leswi mi nga ta swi amukela eka vana va Israyele; naswona mi ta nyika Aroni wa muprista munyikelo lowu tlakusiweke wa Yehovha ku suka eka swona.’”' },
    { n: 29, text: '“‘Eka tinyiko hinkwato ta n’wina mi ta tlakusa munyikelo hinkwawo lowu tlakusiweke wa Yehovha, eka swilo hinkwaswo swo tsakisa swa rona, ku nga xiphemu xa rona xo kwetsima.’”' },
    { n: 30, text: '“‘Kutani u ta ku eka vona: “Loko mi tlakusa xiphemu xa rona xinene ku suka eka rona, kutani xi ta hlayiseriwa va-Levita ku fana ni ku humelela ka xivuyu ni ku fana ni ku humelela ka xikamelo xa vhinyo.”’”' },
    { n: 31, text: '“‘Mi ta xi dyela endhawuni yin’wana ni yin’wana, n’wina ni tiyindlu ta n’wina; hikuva i hakelo ya n’wina hikwalaho ka vutireli bya n’wina eka tabernakela ya nhlanganiso.’”' },
    { n: 32, text: '“‘Kutani a mi nga rwali xidyoho hikwalaho ka xona, loko mi tlakusa xiphemu xa rona xinene ku suka eka rona; naswona mi nga tshuki mi nyamisa swilo swo kwetsima swa vana va Israyele, leswaku mi nga fi.’”' }
  ],
  19: [
    { n: 1, text: 'Yehovha a vulavula na Moxe na Aroni, a ku:' },
    { n: 2, text: '“Lowu i nawu wa xileriso lexi Yehovha a xi leriseke, a ku: ‘Vulavula ni vana va Israyele leswaku va ku tisele novilha yo tshwuka leyi tengeke, leyi nga riki na xilema, leyi nga si tshamaka yi vekiwa joko;’”' },
    { n: 3, text: '“‘mi ta yi nyika Eliyazara wa muprista, naswona u ta yi humesela ehandle ka kampa, yi dlayiwa mahlweni ka yena;’”' },
    { n: 4, text: '“‘Eliyazara wa muprista u ta teka ngati ya yona hi ntiho wa yena, a tsetsera ngati ya yona mahlweni ka tabernakela ya nhlanganiso ka ntlhanu na kambirhi;’”' },
    { n: 5, text: '“‘kutani novilha yi ta hisiwa mahlweni ka mahlo ya yena; nhlonge ya yona, ni nyama ya yona, ni ngati ya yona, xikan’we ni ritsongo ra yona, swi ta hisiwa;’”' },
    { n: 6, text: '“‘muprista u ta teka rhavi ra kedari, ni hysopo, ni nguvu yo tshwuka, a swi lahlela exikarhi ka ku hisiwa ka novilha.’”' },
    { n: 7, text: '“‘Kutani muprista u ta hlantswa tinguvu ta yena, a hlamba nyama ya yena hi mati, endzhaku ka sweswo a nghena ekampeni; muprista u ta va la nga tengangiki ku fikela madyambu.’”' },
    { n: 8, text: '“‘Loyi a yi hiseke na yena u ta hlantswa tinguvu ta yena hi mati, a hlamba nyama ya yena hi mati, naswona u ta va la nga tengangiki ku fikela madyambu.’”' },
    { n: 9, text: '“‘Wanuna un’we loyi a tengeke u ta hlengeleta nkuma wa novilha, a wu veka ehandle ka kampa endhawuni leyi tengeke; wu ta hlayiseriwa nhlengeletano ya vana va Israyele leswaku ku endliwa mati ya ku tsemakanya; i gandzelo ra xidyoho.’”' },
    { n: 10, text: '“‘Loyi a hlengeleteke nkuma wa novilha u ta hlantswa tinguvu ta yena, a va la nga tengangiki ku fikela madyambu; lowu wu ta va nawu wa hilaha ku nga heriki eka vana va Israyele ni le ka muhlaluhi loyi a tshamaka exikarhi ka vona.’”' },
    { n: 11, text: '“‘Loyi a khumbaka ntsumbu wa munhu un’wana ni un’wana u ta va la nga tengangiki masiku ya nkombo.’”' },
    { n: 12, text: '“‘U ta tibasisa ha wona hi siku ra vunharhu, naswona hi siku ra vunkombo u ta va la tengeke; kambe loko a nga tibasisi hi siku ra vunharhu, kutani hi siku ra vunkombo a nga ka a nga tengi.’”' },
    { n: 13, text: '“‘Un’wana ni un’wana loyi a khumbaka ntsumbu wa munhu loyi a feke, a nga tibasisi, u nyamisa tabernakela ya Yehovha; munhu yoloye u ta tsemiwa eIsrayele; hikuva mati ya ku tsemakanya a ma tsetseriwanga ehenhla ka yena, u ta va la nga tengangiki; ku nga tengi ka yena ku ha ri ehenhla ka yena.’”' },
    { n: 14, text: '“‘Lowu i nawu loko munhu a fela etendeni: un’wana ni un’wana loyi a nghenaka etendeni, ni hinkwaswo leswi nga etendeni, swi ta va leswi nga tengangiki masiku ya nkombo.’”' },
    { n: 15, text: '“‘Xibya xin’wana ni xin’wana lexi pfulekeke, lexi nga riki na xipfalo lexi tsimbiweke eka xona, xi ta va xi nga tengangiki.’”' },
    { n: 16, text: '“‘Un’wana ni un’wana loyi a nga enhoveni a khumbaka loyi a dlayiweke hi banga, kumbe ntsumbu, kumbe rhambu ra munhu, kumbe sirha, u ta va la nga tengangiki masiku ya nkombo.’”' },
    { n: 17, text: '“‘Kutani hikwalaho ka loyi a nga tengangiki, va ta teka nkuma wa ku hisiwa ka gandzelo ra xidyoho, va chela mati lama tsemakanyaka eka wona exibyeni;’”' },
    { n: 18, text: '“‘wanuna un’we loyi a tengeke u ta teka hysopo, a yi peta ematini, a tsetsera yindlu, ni swibya hinkwaswo, ni mimoya leyi a yi ri kona, ni loyi a khumbeke rhambu, kumbe loyi a dlayiweke, kumbe ntsumbu, kumbe sirha;’”' },
    { n: 19, text: '“‘loyi a tengeke u ta tsetsera loyi a nga tengangiki hi siku ra vunharhu ni hi siku ra vunkombo; hi siku ra vunkombo u ta n’wi basisa, naswona u ta hlantswa tinguvu ta yena, a hlamba hi mati, a va la tengeke hi madyambu.’”' },
    { n: 20, text: '“‘Kambe munhu loyi a nga tengangiki, a nga tibasisi, munhu yoloye u ta tsemiwa exikarhi ka nhlengeletano, hikuva u nyamise ndhawu yo kwetsima ya Yehovha; mati ya ku tsemakanya a ma tsetseriwanga ehenhla ka yena; u nga tenganga.’”' },
    { n: 21, text: '“‘Wu ta va nawu wa hilaha ku nga heriki eka vona; loyi a tsetseraka mati ya ku tsemakanya u ta hlantswa tinguvu ta yena; naswona loyi a khumbaka mati ya ku tsemakanya u ta va la nga tengangiki ku fikela madyambu.’”' },
    { n: 22, text: '“‘Nchumu hinkwaswo lowu khumbiwaka hi loyi a nga tengangiki wu ta va lowu nga tengangiki; naswona moya lowu wu khumbaka wu ta va lowu nga tengangiki ku fikela madyambu.’”' }
  ],
  20: [
    { n: 1, text: 'Vana va Israyele, ku nga nhlengeletano hinkwayo, va fika emananga ya Zini hi n’hweti yo sungula; vanhu va tshama eKadeve. Miriyama a fela kwalaho, a lahliwa kwalaho.' },
    { n: 2, text: 'Kambe a ku nga ri na mati ya nhlengeletano; va hlengeletana ku lwa na Moxe na Aroni.' },
    { n: 3, text: 'Vanhu va holova na Moxe, va vulavula va ku: “Inge hi file loko vamakwerhu va file mahlweni ka Yehovha!”' },
    { n: 4, text: '“Hikwalaho ka yini mi tisele nhlengeletano ya Yehovha emananga lawa, leswaku hina ni swifuwo swa hina hi fela kona?”' },
    { n: 5, text: '“Hikwalaho ka yini mi hi humeseke etikweni ra Egipta leswaku mi hi tisa endhawuni leyi yo biha? Ndhawu leyi a yi na mavele, kumbe makuwa, kumbe vhinyo, kumbe magalana; naswona a ku na mati yo nwa!”' },
    { n: 6, text: 'Moxe na Aroni va suka mahlweni ka nhlengeletano va ya enyangweni ya tabernakela ya nhlanganiso; va tiwisela hi swikandza ehansi; kutani ku kwetsima ka Yehovha ku humelela eka vona.' },
    { n: 7, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 8, text: '“Teka nhonga, u hlengeleta nhlengeletano, wena na Aroni makwenu, naswona mi vulavula ni ribye mahlweni ka mahlo ya vona leswaku ri humesa mati ya rona; u ta va humesela mati eribyeni, u nyika nhlengeletano ni swifuwo swa vona leswaku va nwa.”' },
    { n: 9, text: 'Moxe a teka nhonga mahlweni ka Yehovha, hilaha a n’wi leriseke ha kona.' },
    { n: 10, text: 'Moxe na Aroni va hlengeleta nhlengeletano mahlweni ka ribye; a ku eka vona: “Ndzi kombela mi yingisa, n’wina vapfukeli: xana hi fanele ku mi humesela mati eribyeni leri xana?”' },
    { n: 11, text: 'Moxe a tlakusa voko ra yena, a ba ribye kambirhi hi nhonga ya yena; mati yo tala ma huma, nhlengeletano ni swifuwo swa vona va nwa.' },
    { n: 12, text: 'Kambe Yehovha a ku eka Moxe na Aroni: “Hikwalaho ka leswi mi nga ndzi tshembangiki, leswaku mi ndzi kwetsimisa mahlweni ka vana va Israyele, hikwalaho a mi nga yi nghenisi nhlengeletano leyi etikweni leri ndzi nga ta va nyika rona.”' },
    { n: 13, text: 'Lawa i mati ya Meriba, hikuva vana va Israyele va holovile na Yehovha, naswona u tikombise a kwetsimile exikarhi ka vona.' },
    { n: 14, text: 'Moxe a rhuma varhumi ku suka eKadeve ku ya eka hosi ya Edome, a ku: “Hi leswi makwenu Israyele a swi vulaka: ‘U tiva maxangu hinkwaswo lawa hi weleke;’”' },
    { n: 15, text: '“‘hilaha vatata va hina va xikeleke eEgipta, hi tshama eEgipta masiku yo tala; va-Egipta va hi hoxerile, hina ni vatata va hina;’”' },
    { n: 16, text: '“‘loko hi rilela Yehovha, u twile rito ra hina, a rhuma ntsumi, a hi humesa eEgipta; kutani hi lava eKadeve, muti lowu nga emakungeto ya ndzilakana wa wena;’”' },
    { n: 17, text: '“‘ndzi kombela u hi pfumelela hi hundza etikweni ra wena; a hi nge hundzi hi le masimwini kumbe hi le mirhini ya vhinyo, naswona a hi nge nwi mati ya swihlovo; hi ta famba hi ndlela ya hosi, a hi nge hambukeli exinene kumbe eximatsini ku fikela loko hi hundzile ndzilakana wa wena.’”' },
    { n: 18, text: 'Kambe Edome a ku eka yena: “U nga tshuki u hundza hi le ka mina, hikuva ndzi ta huma ku ku pfuka hi banga.”' },
    { n: 19, text: 'Vana va Israyele va ku eka yena: “Hi ta tlhandluka hi ndlela leyikulu; naswona loko hina ni swifuwo swa hina hi nwa mati ya wena, ndzi ta hakela hakunene; a ndzi lavi nchumu un’wana, ndzi lava ntsena ku hundza hi milenge.”' },
    { n: 20, text: 'Kambe a ku: “A u nga hundzi.” Edome a huma ku ya lwa na yena a ri ni vuthu lerikulu ni voko ra matimba.' },
    { n: 21, text: 'Hi ndlela yoleyo Edome a ala ku pfumelela Israyele ku hundza hi le ndzilakaneni wa yena; kutani Israyele a hambana na yena.' },
    { n: 22, text: 'Vana va Israyele, ku nga nhlengeletano hinkwayo, va suka eKadeve, va fika entshaveni ya Hore.' },
    { n: 23, text: 'Yehovha a vulavula na Moxe na Aroni entshaveni ya Hore, emakungeto ya tiko ra Edome, a ku:' },
    { n: 24, text: '“Aroni u ta hlengeletiwa eka vanhu va ka vona; hikuva a nga ka a nga ngheni etikweni leri ndzi nga ta nyika vana va Israyele rona, hikuva mi pfukele rileriso ra mina ematini ya Meriba.”' },
    { n: 25, text: '“Teka Aroni na Eliyazara n’wana wa yena, u va tlhandlusela entshaveni ya Hore;”' },
    { n: 26, text: '“u ta hula Aroni tinguvu ta yena, u tiambexela Eliyazara n’wana wa yena; Aroni u ta hlengeletiwa a fela kwalaho.”' },
    { n: 27, text: 'Moxe a endla hilaha Yehovha a n’wi leriseke ha kona; va tlhandlukela entshaveni ya Hore mahlweni ka nhlengeletano hinkwayo.' },
    { n: 28, text: 'Moxe a hula Aroni tinguvu ta yena, a tiambexela Eliyazara n’wana wa yena; Aroni a fela kwalaho ehenhla ka ntsjava; kutani Moxe na Eliyazara va xika ku suka entshaveni.' },
    { n: 29, text: 'Loko nhlengeletano hinkwayo yi vona leswaku Aroni u file, yindlu hinkwayo ya Israyele yi rila Aroni masiku ya makhume manharhu.' }
  ],
  21: [
    { n: 1, text: 'Loko Mukanana, hosi ya Aradi, loyi a a tshama le dzongeni, a twa leswaku Israyele wa ta hi ndlela ya Atarimi, a lwa na Israyele, a khoma van’wana va vona va va makhumbi.' },
    { n: 2, text: 'Kutani Israyele a endla xihlambanyo eka Yehovha, a ku: “Loko mo nyiketa vanhu lava evokweni ra mina, ndzi ta herisa miti ya vona hilaha ku heleleke.”' },
    { n: 3, text: 'Yehovha a yingisa rito ra Israyele, a nyiketa Vakanana; va va herisa hinkwavo xikan’we ni miti ya vona. Hikwalaho ndhawu yoleyo va yi thya vito ra Horoma.' },
    { n: 4, text: 'Va suka entshaveni ya Hore hi ndlela ya Lwandle ro Tshwuka, leswaku va rhendzeleka tiko ra Edome; kutani mimoya ya vanhu yi hela mbilu swinene endleleni.' },
    { n: 5, text: 'Vanhu va vulavula swo biha ku lwa na Xikwembu ni ku lwa na Moxe, va ku: “Hikwalaho ka yini mi hi humeseke eEgipta leswaku hi ta fela emananga? Hikuva a ku na xinkwa, naswona a ku na mati; naswona mimoya ya hina yi nyenya xinkwa lexi xi nga riki na nchumu.”' },
    { n: 6, text: 'Kutani Yehovha a rhuma tinyoka leti tlhavelaka exikarhi ka vanhu; ti luma vanhu, va-Israyele vo tala va fa.' },
    { n: 7, text: 'Vanhu va ta eka Moxe, va ku: “Hi dyohe hi ku vulavula swo biha ku lwa na Yehovha ni ku lwa na wena; khongelela eka Yehovha leswaku a susa tinyoka leti eka hina.” Kutani Moxe a khongelela vanhu.' },
    { n: 8, text: 'Yehovha a ku eka Moxe: “Tiendlele nyoka yo tlhabela, u yi veka ehenhla ka mhandzi; naswona ku ta endleka leswaku un’wana ni un’wana loyi a lumiweke, loko a yi languta, u ta hanya.”' },
    { n: 9, text: 'Moxe a endla nyoka ya nsuku, a yi veka ehenhla ka mhandzi; kutani swi endleka leswaku, loko nyoka yi lume munhu, a languta nyoka ya nsuku, a hanya.' },
    { n: 10, text: 'Vana va Israyele va suka va ya gwimba eOboti.' },
    { n: 11, text: 'Va suka eOboti, va ya gwimba eIye-Abarimi, emananga lama nga mahlweni ka Mowabu, hi tlhelo ra ku huma ka dyambu.' },
    { n: 12, text: 'Va suka kwalaho, va ya gwimba enkoveni wa Zerede.' },
    { n: 13, text: 'Va suka kwalaho, va ya gwimba hi tlhelo lerin’wana ra Arnoni, leri nga emananga lama humaka endzilakaneni wa Vaamori; hikuva Arnoni i ndzilakana wa Mowabu, exikarhi ka Mowabu ni Vaamori.' },
    { n: 14, text: 'Hikwalaho swi tsariwile ebukwini ya Tinyimpi ta Yehovha: “Vahebe eSufa, ni minkova ya Arnoni,”' },
    { n: 15, text: '“ni ntsengeleko wa minkova lowu yaka ematshamelo ya Ari, lowu tshegamelaka endzilakaneni wa Mowabu.”' },
    { n: 16, text: 'Kona va suka va ya eBeri; lowu hi wona xihlovo lexi Yehovha a xi vuleke eka Moxe, a ku: “Hlengeleta vanhu, ndzi va nyika mati.”' },
    { n: 17, text: 'Kutani Israyele a yimbelela risimu leri: “Phuphuma, wena xihlovo! Xi yimbeleleni;”' },
    { n: 18, text: '“xihlovo lexi ceriweke hi tihosi, lexi ceriweke hi vakulukumba va vanhu, hi nhonga ya ku fuma ni hi tinhonga ta vona.” Kutani va suka emananga va ya eMatana;' },
    { n: 19, text: 'va suka eMatana va ya eNahaliyele; va suka eNahaliyele va ya eBamoti;' },
    { n: 20, text: 'va suka eBamoti va ya enkoveni lowu nga emabaleni ya Mowabu, ehenhla ka Pisga, leyi langutaneke ni lemananga.' },
    { n: 21, text: 'Israyele a rhuma varhumi eka Sihoni, hosi ya Vaamori, a ku:' },
    { n: 22, text: '“Ndzi pfumelele ndzi hundza etikweni ra wena; a hi nge hambukeli emanyatleni kumbe emasini ya vhinyo; a hi nge nwi mati ya swihlovo; hi ta famba hi ndlela ya hosi ku fikela loko hi hundzile ndzilakana wa wena.”' },
    { n: 23, text: 'Kambe Sihoni a nga pfumelelanga Israyele ku hundza hi le ndzilakaneni wa yena; Sihoni a hlengeleta vanhu va yena hinkwavo, a huma ku ya lwa na Israyele emananga, a fika eYahasi, a lwa na Israyele.' },
    { n: 24, text: 'Israyele a n’wi dlaya hi banga, a teka tiko ra yena ku sukela eArnoni ku ya eYaboki, ku fikela eka vana va Amoni; hikuva ndzilakana wa vana va Amoni a wu tiyile.' },
    { n: 25, text: 'Israyele a teka miti leyi hinkwayo; kutani Israyele a tshama emiti hinkwayo ya Vaamori, eHaxiboni ni le swin’wanini hinkwaswo swa rona.' },
    { n: 26, text: 'Hikuva Haxiboni a a ri muti wa Sihoni, hosi ya Vaamori, loyi a a lwarile ni hosi yo sungula ya Mowabu, a teka tiko ra yena hinkwaxo evokweni ra yena ku fikela eArnoni.' },
    { n: 27, text: 'Hikwalaho lava vulavulaka hi swiphato va ku: “Tanani eHaxiboni, a wu akiwe, muti wa Sihoni a wu tiyisiwe;”' },
    { n: 28, text: '“hikuva ndzilo wu humile eHaxiboni, langavi ri humile emutini wa Sihoni; wu herise Ari wa Mowabu, ni vini va tindhawu ta le henhla ta Arnoni.”' },
    { n: 29, text: '“Khombo eka wena, Mowabu! U lovisiwile, wena tiko ra Kemoxi! U nyikete vana va yena va majaha tanihi vanyandzuri, ni vana va yena va vanhwanyana emakhumbini eka Sihoni, hosi ya Vaamori.”' },
    { n: 30, text: '“Hi va hoxile hi ku thya; Haxiboni u lovisiwile ku fikela eDiboni, naswona hi va herisile ku fikela eNofa, lowu fikelelahaka ku ya eMedeba.”' },
    { n: 31, text: 'Hi ndlela yoleyo Israyele a tshama etikweni ra Vaamori.' },
    { n: 32, text: 'Moxe a rhuma vanhu ku ya tiva Yazere; va teka swin’wana swa rona, va hlongola Vaamori lava a va ri kwalaho.' },
    { n: 33, text: 'Kutani va hundzuluka va tlhandluka hi ndlela ya Baxani; Oge, hosi ya Baxani, a huma ku ya lwa na vona, yena ni vanhu va yena hinkwavo, eEdreyi.' },
    { n: 34, text: 'Yehovha a ku eka Moxe: “U nga n’wi chavi; hikuva ndzi n’wi nyiketile evokweni ra wena, ni vanhu va yena hinkwavo, ni tiko ra yena; u ta endla eka yena hilaha u endleke hakona eka Sihoni, hosi ya Vaamori, loyi a a tshama eHaxiboni.”' },
    { n: 35, text: 'Va n’wi dlaya, yena ni vana va yena, ni vanhu va yena hinkwavo, ku fikela loko ku nga salanga na un’we wa yena; naswona va teka tiko ra yena.' }
  ],
  22: [
    { n: 1, text: 'Vana va Israyele va suka va ya gwimba emabaleni ya Mowabu, entsengeleko wa Yordani, ku langutana na Yeriko.' },
    { n: 2, text: 'Balaka, n’wana wa Siporo, a vona hinkwaswo leswi Israyele a swi endleke eka Vaamori.' },
    { n: 3, text: 'Mowabu a chava vanhu lava swinene, hikuva a va ri va tala; naswona Mowabu a a ri ni gome hikwalaho ka vana va Israyele.' },
    { n: 4, text: 'Mowabu a ku eka vakulukumba va Midiyane: “Sweswi ntshungu lowu wu ta n’antswa hinkwaswo leswi hi rhendzeleke, ku fana ni homu leyi n’antswaka mabyanyi ya nhova.” Balaka, n’wana wa Siporo, a a ri hosi ya Mowabu hi nkarhi woloye.' },
    { n: 5, text: 'A rhuma varhumi eka Balama, n’wana wa Beori, ePetore, leri nga ekusuhi ni Nambu etikweni laha vana va vanhu va ka vona a va tshama kona, ku ya n’wi vitana, a ku: “Waswivo, ku na vanhu lava humeke eEgipta; va funengetile xikandza xa misava, naswona va tshame mahlweni ka mina;”' },
    { n: 6, text: '“sweswi hikwalaho ndzi kombela u ta, u ndzi rhukana vanhu lava; hikuva va ni matimba ku tlula mina; kumbexana ndzi nga swi kota ku va hlula, hi va hlongola etikweni; hikuva ndza swi tiva leswaku loyi u n’wi katekisaka wa katekisiwa, naswona loyi u n’wi rhukanaka wa rhukaniwa.”' },
    { n: 7, text: 'Vakulukumba va Mowabu ni vakulukumba va Midiyane va suka va khome hakelo ya vungoma ezandleni ta vona; va fika eka Balama, va n’wi byela marito ya Balaka.' },
    { n: 8, text: 'A ku eka vona: “Tshamani laha vusiku lebyi, ndzi ta mi tlhantlhela hilaha Yehovha a nga ta vulavula na mina hakona.” Kutani varhangeri va Mowabu va tshama na Balama.' },
    { n: 9, text: 'Xikwembu xi ta eka Balama, xi ku: “I vamani vavanuna lava va nga na wena?”' },
    { n: 10, text: 'Balama a ku eka Xikwembu: “Balaka, n’wana wa Siporo, hosi ya Mowabu, u rhumile eka mina, a ku:”' },
    { n: 11, text: '“‘Waswivo, vanhu lava humeke eEgipta va funengetile xikandza xa misava; sweswi ta, u ndzi rhukana vona; kumbexana ndzi nga swi kota ku lwa na vona, ndzi va hlongola.’”' },
    { n: 12, text: 'Xikwembu xi ku eka Balama: “U nga fambi na vona; u nga tshuki u rhukana vanhu lava, hikuva va katekisiwile.”' },
    { n: 13, text: 'Balama a pfuka nimixo, a ku eka varhangeri va Balaka: “Yanani etikweni ra n’wina; hikuva Yehovha u arile ku ndzi pfumelela ku famba na n’wina.”' },
    { n: 14, text: 'Varhangeri va Mowabu va pfuka, va ya eka Balaka, va ku: “Balama u arile ku ta na hina.”' },
    { n: 15, text: 'Balaka a tlhela a rhuma varhangeri va van’wana, va tala naswona va ri va ndhuma ku tlula lavo sungula.' },
    { n: 16, text: 'Va fika eka Balama, va ku eka yena: “Hi leswi Balaka, n’wana wa Siporo, a swi vulaka: ‘Ndzi kombela u nga tshuki u pfumela ku sivela ku ta eka mina;’”' },
    { n: 17, text: '“‘hikuva ndzi ta ku hlonipha swinene, naswona hinkwaswo leswi u nga ta swi vula eka mina ndzi ta swi endla; ndzi kombela u ta, u ndzi rhukana vanhu lava.’”' },
    { n: 18, text: 'Balama a hlamula, a ku eka malandza ya Balaka: “Hambiloko Balaka o ndzi nyika yindlu ya yena yi tele hi silivhere ni nsuku, a ndzi nga swi koti ku tlula rito ra Yehovha Xikwembu xa mina, ku endla nchumu lowutsongo kumbe lowukulu.”' },
    { n: 19, text: '“Sweswi, ndzi kombela mi sala na n’wina laha vusiku lebyi, leswaku ndzi tiva leswi Yehovha a nga ta tlhela a vulavula na mina swona.”' },
    { n: 20, text: 'Xikwembu xi ta eka Balama nivusiku, xi ku eka yena: “Loko vavanuna lava va tele ku ku vitana, pfuka, u famba na vona; kambe ntsena rito leri ndzi nga ta ku byela rona, hi rona leri u nga ta ri endla.”' },
    { n: 21, text: 'Balama a pfuka nimixo, a panela mbongolo ya yena, a famba ni varhangeri va Mowabu.' },
    { n: 22, text: 'Kambe vukarhi ka Xikwembu ku pfurha hikuva a fambile; ntsumi ya Yehovha yi yima endleleni ku n’wi sivela. A a khade mbongolo ya yena, a ri na malandza ya yena mambirhi.' },
    { n: 23, text: 'Mbongolo yi vona ntsumi ya Yehovha yi yimile endleleni yi khome banga leri tsemaka evokweni ra yona; mbongolo yi hambukela etlhelo ka ndlela, yi nghena enhoveni. Balama a ba mbongolo leswaku a yi hundzuluxela endleleni.' },
    { n: 24, text: 'Kutani ntsumi ya Yehovha yi yima endleleni yo khuma ya masimu ya vhinyo, ku ri ni rirangu hi tlhelo leri ni rirangu hi tlhelo leri.' },
    { n: 25, text: 'Loko mbongolo yi vona ntsumi ya Yehovha, yi titshembelela erirangwini, yi fula nenge wa Balama erirangwini; kutani a tlhela a yi ba.' },
    { n: 26, text: 'Ntsumi ya Yehovha yi tlhela yi ya mahlweni, yi yima endhawuni yo khuma, laha a ku nga ri na ndlela yo hambukela exinene kumbe eximatsini.' },
    { n: 27, text: 'Loko mbongolo yi vona ntsumi ya Yehovha, yi ntsongomana ehansi ka Balama; kutani vukarhi bya Balama byi pfurha, a ba mbongolo hi nhonga.' },
    { n: 28, text: 'Yehovha a pfula nomu wa mbongolo, yi ku eka Balama: “Ndzi ku endle yini, leswi u ndzi weke kanharhu hi ku ba?”' },
    { n: 29, text: 'Balama a ku eka mbongolo: “Hikuva u ndzi endle xiphukuphuku; inge ku ri ni banga evokweni ra mina, sweswi inge ndzi ku dlayile!”' },
    { n: 30, text: 'Mbongolo yi ku eka Balama: “Xana a ndzi mbongolo ya wena, leyi u tshamaka u famba hi yona ku sukela khale ku fikela namuntlha? Xana ndzi tshinye ndzi ku endlela swilo swo tano?” A ku: “E-e.”' },
    { n: 31, text: 'Kutani Yehovha a pfula mahlo ya Balama, a vona ntsumi ya Yehovha yi yimile endleleni yi khome banga leri tsemaka evokweni ra yona; a khotama, a tiwisela hi xikandza ehansi.' },
    { n: 32, text: 'Ntsumi ya Yehovha yi ku eka yena: “Hikwalaho ka yini u beke mbongolo ya wena kanharhu xana? Waswivo, ndzi humile ku ku sivela, hikuva ndlela ya wena yi hoxekile mahlweni ka mina;”' },
    { n: 33, text: '“mbongolo yi ndzi vonile, yi hambukela mahlweni ka mina kanharhu; loko yi nga hambukelanga mahlweni ka mina, hakunene sweswi inge ndzi ku dlayile, kambe yona inge ndzi yi tshike yi hanya.”' },
    { n: 34, text: 'Balama a ku eka ntsumi ya Yehovha: “Ndzi dyohe; hikuva a ndzi nga swi tivi leswaku u yimile endleleni ku lwa na mina; sweswi, loko swi ri swo biha ematshweni ya wena, ndzi ta tlhela.”' },
    { n: 35, text: 'Ntsumi ya Yehovha yi ku eka Balama: “Famba ni vavanuna lava; kambe ntsena rito leri ndzi nga ta ku byela rona, hi rona leri u nga ta ri vulavula.” Kutani Balama a famba ni varhangeri va Balaka.' },
    { n: 36, text: 'Loko Balaka a twa leswaku Balama u fika, a huma ku ya hlangana na yena emutini wa Mowabu, lowu nga endzilakaneni wa Arnoni, lowu nga emakungeto ya ndzilakana.' },
    { n: 37, text: 'Balaka a ku eka Balama: “Xana a ndzi rhumanga hi ku hatlisa ku ya ku vitana xana? Hikwalaho ka yini u nga tanga eka mina? Xana hakunene a ndzi swi koti ku ku hlonipha?”' },
    { n: 38, text: 'Balama a ku eka Balaka: “Waswivo, ndzi tile eka wena; xana sweswi ndzi ni matimba yo vulavula nchumu xana? Rito leri Xikwembu xi nga ta ri veka enomwini wa mina, hi rona leri ndzi nga ta ri vulavula.”' },
    { n: 39, text: 'Balama a famba na Balaka, va fika eKiriyata-Husoti.' },
    { n: 40, text: 'Balaka a tlhabela tihomu ni tinyimpfu, a rhumela eka Balama ni le ka varhangeri lava a va ri na yena.' },
    { n: 41, text: 'Hi siku leri landzeleke nimixo, Balaka a teka Balama, a n’wi tlhandlusela eBamoti-Bali, leswaku a vona xiphemu xa vanhu va Israyele ku sukela kwalaho.' }
  ],
  23: [
    { n: 1, text: 'Balama a ku eka Balaka: “Ndzi ahele tialtari ta nkombo laha, u ndzi lulamisela ni tihomu ta nkombo ni makhuna ya nkombo.”' },
    { n: 2, text: 'Balaka a endla hilaha Balama a vuleke ha kona; kutani Balaka na Balama va hisa n’wana wa homu ni khuna ealtari yin’wana ni yin’wana.' },
    { n: 3, text: 'Balama a ku eka Balaka: “Yima ekusuhi ni gandzelo ra wena ro hisiwa, ndzi ta famba; kumbexana Yehovha u ta hlangana na mina, naswona hinkwaswo leswi a nga ta ndzi komba swona ndzi ta ku byela.” Kutani a ya endhawuni leyi tlakuseke.' },
    { n: 4, text: 'Xikwembu xi hlangana na Balama, a ku eka xona: “Ndzi lulamisile tialtari ta nkombo, naswona ndzi hisile n’wana wa homu ni khuna ealtari yin’wana ni yin’wana.”' },
    { n: 5, text: 'Yehovha a veka rito enomwini wa Balama, a ku: “Tlhela eka Balaka, u ya vula leswi.”' },
    { n: 6, text: 'A tlhela eka yena, kutani waswivo, a a yimile ekusuhi ni gandzelo ra rona ro hisiwa, yena ni varhangeri hinkwavo va Mowabu.' },
    { n: 7, text: 'A sungula xivuriso xa yena, a ku: “Balaka u ndzi tise ku suka eArami, hosi ya Mowabu ku suka entshaveni ya le vuxeni, a ku: ‘Ta, u ndzi rhukana Yakobe, naswona ta, u seketela ku herisiwa ka Israyele.’”' },
    { n: 8, text: '“Ndzi nga n’wi rhukanisa ku yini loyi Xikwembu xi nga n’wi rhukanangiki? Naswona ndzi nga n’wi sandza njhani loyi Yehovha a nga n’wi sandzangiki?”' },
    { n: 9, text: '“Hikuva ku suka ehenhla ka maribye ndza n’wi vona, naswona ku suka ehenhla ka swintshabyana ndza n’wi languta; waswivo, i vanhu lava tshamaka va ri voxe, naswona exikarhi ka matiko a va hlayiwi.”' },
    { n: 10, text: '“I mani loyi a nga hlayaka ntsuri wa Yakobe, kumbe ntsengo wa xiphemu xa vumune xa Israyele? Inge moya wa mina wu nga fela rifu ra lava lulameke, naswona makumu ya mina ya fana ni ya yena!”' },
    { n: 11, text: 'Balaka a ku eka Balama: “U ndzi endle yini xana? Ndzi ku tisele ku rhukana valala va mina, kambe waswivo, u va katekise swinene!”' },
    { n: 12, text: 'A hlamula, a ku: “Xana a ndzi fanelanga ku hlayisa ni ku vulavula leswi Yehovha a swi vekeke enomwini wa mina?”' },
    { n: 13, text: 'Balaka a ku eka yena: “Ndzi kombela u ta na mina endhawuni yin’wana, laha u nga ta va vona kona; u ta vona ntsena xiphemu xa vona, kambe a u nga va voni hinkwavo; u ndzi rhukana vona u ri kwalaho.”' },
    { n: 14, text: 'A n’wi yisa emabaleni ya Zofimi, ehenhla ka Pisga, a aha tialtari ta nkombo, a hisa n’wana wa homu ni khuna ealtari yin’wana ni yin’wana.' },
    { n: 15, text: 'A ku eka Balaka: “Yima laha ekusuhi ni gandzelo ra wena ro hisiwa, kasi mina ndzi ya hlangana na Yehovha halahaya.”' },
    { n: 16, text: 'Yehovha a hlangana na Balama, a veka rito enomwini wa yena, a ku: “Tlhela eka Balaka, u ya vula leswi.”' },
    { n: 17, text: 'A ta eka yena, kutani waswivo, a a yimile ekusuhi ni gandzelo ra yena ro hisiwa, ku ri ni varhangeri va Mowabu na yena. Balaka a ku eka yena: “Yehovha u vule yini xana?”' },
    { n: 18, text: 'A sungula xivuriso xa yena, a ku: “Pfuka, wena Balaka, u yingisa; yingisela eka mina, wena n’wana wa Siporo:”' },
    { n: 19, text: '“Xikwembu a hi munhu leswaku xi nga vulavula mavunwa, hambi ku ri n’wana wa munhu leswaku xi nga hundzuka; xana xi vurile, kutani xi nga ka xi nga endli? Kumbe xi vulavurile, kutani xi nga ka xi nga xi tiyisi?”' },
    { n: 20, text: '“Waswivo, ndzi amukele rileriso ro katekisa; xi katekise, naswona a ndzi nge swi koti ku swi hundzuluxa.”' },
    { n: 21, text: '“A nga vonanga vuhomboloki eka Yakobe, naswona a nga vonanga maxangu eIsrayele; Yehovha Xikwembu xa yena u na yena, naswona ntsako wa hosi wu exikarhi ka vona.”' },
    { n: 22, text: '“Xikwembu xi va humese eEgipta; xi ni matimba ku fana ni rimhondzo ra mhelembe.”' },
    { n: 23, text: '“Hikuva a ku na vungoma eka Yakobe, naswona a ku na ku vhumbha eIsrayele; sweswi swi ta vuriwa hi Yakobe ni hi Israyele: ‘Tshukani, waswivo leswi Xikwembu xi swi endleke!’”' },
    { n: 24, text: '“Waswivo, vanhu va pfuka ku fana ni nghala ya xisati, naswona va titlakusa ku fana ni nghala; a va nge titsandzi va nga si dya swakudya, va nwa ni ngati ya lava dlayiweke.”' },
    { n: 25, text: 'Balaka a ku eka Balama: “U nga va rhukani hambi ku ri ku va katekisa!”' },
    { n: 26, text: 'Kambe Balama a hlamula, a ku eka Balaka: “Xana a ndzi ku byelanga ndzi ku: ‘Hinkwaswo leswi Yehovha a nga ta swi vula, hi swona ndzi faneleke ku swi endla’?”' },
    { n: 27, text: 'Balaka a ku eka Balama: “Ta, ndzi ta ku yisa endhawuni yin’wana; kumbexana swi ta vuriwa swi lulame eka Xikwembu leswaku u ndzi rhukana vona u ri kwalaho.”' },
    { n: 28, text: 'Balaka a teka Balama, a n’wi yisa ehenhla ka Peori, lowu langutaneke ni lemananga.' },
    { n: 29, text: 'Balama a ku eka Balaka: “Ndzi ahele tialtari ta nkombo laha, u ndzi lulamisela ni tihomu ta nkombo ni makhuna ya nkombo.”' },
    { n: 30, text: 'Balaka a endla hilaha Balama a vuleke ha kona, a hisa n’wana wa homu ni khuna ealtari yin’wana ni yin’wana.' }
  ],
  24: [
    { n: 1, text: 'Loko Balama a vona leswaku swi tsakisa Yehovha ku katekisa Israyele, a nga fambanga ku fana ni minkarhi leyin’wana ku ya lava vungoma, kambe a rhandza ku langutisa etlhelo ra mananga.' },
    { n: 2, text: 'Balama a tlakusa mahlo xa yena, a vona Israyele a gwimbile hi ku landza tinyimba ta yena; kutani Moya wa Xikwembu wu fika ehenhla ka yena.' },
    { n: 3, text: 'A sungula xivuriso xa yena, a ku: “Rito ra Balama, n’wana wa Beori, rito ra munhu loyi mahlo xa yena ma pfuliweke;”' },
    { n: 4, text: '“rito ra loyi a yingisaka marito ya Xikwembu, loyi a vonaka xivono xa Lwatinkulu, a pfuriwa mahlo loko a tiwiserile ehansi:”' },
    { n: 5, text: '“Swo saseka swonghasi matende ya wena, Yakobe, ni matshamelo ya wena, Israyele!”' },
    { n: 6, text: '“Ma anamile ku fana ni minkova, ku fana ni masimu ya vhinyo ekusuhi ni nambu, ku fana ni mihlala leyi Yehovha a yi tseleke, ku fana ni mikedari ekusuhi ni mati.”' },
    { n: 7, text: '“Mati ma ta khuluka emakhubyini ya yena, naswona mbewu ya yena yi ta va ematini yo tala; hosi ya yena yi ta tlakuka ku tlula Agaga, naswona ku fuma ka yena ku ta tlakusiwa.”' },
    { n: 8, text: '“Xikwembu xi n’wi humesile eEgipta; xi ni matimba ku fana ni rimhondzo ra mhelembe. U ta dya matiko lama nga valala va yena, a thleketla marambu ya vona, a va tlhava hi maseve ya yena.”' },
    { n: 9, text: '“U khotamile, u pfundzalerile ku fana ni nghala, ni ku fana ni nghala ya xisati; i mani loyi a nga ta n’wi pfuxa? Lave ku katekisaka va katekisiwile, naswona lave ku rhukanaka va rhukaniwile.”' },
    { n: 10, text: 'Kuni vukarhi bya Balaka byi pfurhela Balama, a handla mavoko ya yena; Balaka a ku eka Balama: “Ndzi ku vitanile ku ta rhukana valala va mina, kambe waswivo, u va katekise swinene kanharhu hinkwako!”' },
    { n: 11, text: '“Sweswi, tsutsumela endhawuni ya wena; a ndzi vurile ndzi ku ndzi ta ku hlonipha swinene, kambe waswivo, Yehovha u ku tsonile ku hloniphiwa loku.”' },
    { n: 12, text: 'Balama a ku eka Balaka: “Xana a ndzi vulavulanga ni varhumi va wena lava u va rhumeke eka mina, ndzi ku:”' },
    { n: 13, text: '“‘Hambiloko Balaka o ndzi nyika yindlu ya yena yi tele hi silivhere ni nsuku, a ndzi nga swi koti ku tlula rileriso ra Yehovha, ku endla leswinene kumbe leswo biha hi mbilu ya mina; leswi Yehovha a nga ta swi vula, hi swona ndzi nga ta swi vulavula’?”' },
    { n: 14, text: '“Sweswi, waswivo, ndzi ya eka vanhu va mina; ta, ndzi ku tivisa leswi vanhu lava va nga ta endla swona eka vanhu va wena emikandzweni ya le ndzhaku.”' },
    { n: 15, text: 'A sungula xivuriso xa yena, a ku: “Rito ra Balama, n’wana wa Beori, rito ra munhu loyi mahlo xa yena ma pfuliweke;”' },
    { n: 16, text: '“rito ra loyi a yingisaka marito ya Xikwembu, loyi a tivaka vutivi bya Lowu nge Henhla-henhla, loyi a vonaka xivono xa Lwatinkulu, a pfuriwa mahlo loko a tiwiserile ehansi:”' },
    { n: 17, text: '“Ndzi n’wi vona sweswi, kambe ku nga ri sweswi; ndzi n’wi languta, kambe ku nga ri ekusuhi; nyeleti yi ta huma eka Yakobe, naswona nhonga ya vuhosi yi ta huma eIsrayele; yi ta faya tiko ra Mowabu, yi lovisa hinkwavo vana va Seti.”' },
    { n: 18, text: '“Edome u ta va tiko ra ku tekiwa, Seiri na yena u ta va tiko ra ku tekiwa hi valala va yena; kasi Israyele u ta endla swiendlo swa matimba.”' },
    { n: 19, text: '“Loyi a nga ta fuma u ta huma eka Yakobe, a lovisa lava saleke emutini.”' },
    { n: 20, text: 'Loko a vona Amaleke, a sungula xivuriso xa yena, a ku: “Amaleke a a ri wo sungula exikarhi ka matiko, kambe makumu ya yena ku ta va ku lova hinkwako.”' },
    { n: 21, text: 'Loko a vona Vakenene, a sungula xivuriso xa yena, a ku: “Matshamelo ya wena ma tiyile, naswona xisaka xa wena xi vekiwile eribyeni;”' },
    { n: 22, text: '“kambe hakunene Kayini u ta tswhiwa, ku fikela loko Asiriya a ku teka u ri khumbi.”' },
    { n: 23, text: 'A tlhela a sungula xivuriso xa yena, a ku: “Khombo! I mani loyi a nga ta hanya loko Xikwembu xi endla leswi?”' },
    { n: 24, text: '“Kambe swikepe swi ta huma etlhelo ra Kitimi, swi xanisa Asiriya, swi xanisa na Eberi; kambe na yena u ta fika eku loveni hinkwako.”' },
    { n: 25, text: 'Kutani Balama a pfuka, a famba a tlhelela endhawuni ya yena; na yena Balaka a famba hi ndlela ya yena.' }
  ],
  25: [
    { n: 1, text: 'Israyele a tshama eSitimi; kutani vanhu va sungula ku endla vumbhisa ni vana va vanhwanyana va Mowabu.' },
    { n: 2, text: 'Va vitana vanhu emagandzelweni ya swikwembu swa vona; kutani vanhu va dya, va khotamela swikwembu swa vona.' },
    { n: 3, text: 'Israyele a tiyisa vuxaka na Bali-Peori; kutani vukarhi bya Yehovha byi pfurhela Israyele.' },
    { n: 4, text: 'Yehovha a ku eka Moxe: “Teka hinkwavo varhangeri va vanhu, u va hayeka mahlweni ka Yehovha ku langutana ni dyambu, leswaku vukarhi byi pfurhaka bya Yehovha byi suka eka Israyele.”' },
    { n: 5, text: 'Moxe a ku eka vaavanyisi va Israyele: “Un’wana ni un’wana wa n’wina a a dlaye vanhu va yena lava namarheleke Bali-Peori.”' },
    { n: 6, text: 'Kutani waswivo, un’we wa vana va Israyele a ta, a tisa wansati wa le Midiyane eka vamakwavo, mahlweni ka mahlo ya Moxe ni mahlweni ka mahlo ya nhlengeletano hinkwayo ya vana va Israyele, loko va ri karhi va rila enyangweni ya tende ra nhlengeletano.' },
    { n: 7, text: 'Loko Finiyasi, n’wana wa Eliyazara, n’wana wa Aroni lowu nga muprisita, a vona leswi, a pfuka exikarhi ka nhlengeletano, a teka fumu evokweni ra yena;' },
    { n: 8, text: 'a landzela wanuna loyi wa Israyele endzeni ka tende, a va tlhava hinkwavo vambirhi, wanuna wa Israyele ni wansati loyi ekhurini ra yena. Kutani ntungu wu sanyisiwa exikarhi ka vana va Israyele.' },
    { n: 9, text: 'Lava feke hi ntungu a va ri makume mambirhi mune wa magidi.' },
    { n: 10, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 11, text: '“Finiyasi, n’wana wa Eliyazara, n’wana wa Aroni lowu nga muprisita, u suserile vukarhi bya mina eka vana va Israyele, hikuva u kombisile ku hiseka kukulu hikwalaho ka mina exikarhi ka vona, leswaku ndzi nga herisi vana va Israyele hi ku hovha ka mina.”' },
    { n: 12, text: '“Hikwalaho vula u ku: ‘Waswivo, ndzi n’wi nyika ntwanano wa mina wa ku rhula;’”' },
    { n: 13, text: '“‘naswona wu ta va eka yena ni mbewu ya yena endzhaku ka yena, ntwanano wa vuprisita lebyi nga heriki; hikuva u kombisile ku hiseka hikwalaho ka Xikwembu xa yena, a endla ku rivaleriwa ka swidyoho swa vana va Israyele.’”' },
    { n: 14, text: 'Vito ra wanuna wa Israyele loyi a dlayiweke, loyi a dlayiweke ni wansati wa le Midiyane, a a ri Zimri, n’wana wa Salu, ndhuna ya yindlu ya vatata va nyimba ya Simiyoni.' },
    { n: 15, text: 'Naswona vito ra wansati loyi wa le Midiyane loyi a dlayiweke a a ri Kozbi, n’wana wa Suri; a a ri nhloko ya vana va yindlu ya vatata exikarhi ka Va-Midiyane.' },
    { n: 16, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 17, text: '“Xanisani Va-Midiyane, mi va dlaya;”' },
    { n: 18, text: '“hikuva va mi xanisile hi mano ya vona lawa va mi hoxeke ha wona emhakeni ya Peori, ni le mhakeni ya Kozbi, n’wana wa nhloko ya Midiyane, wanhwanyana wa ka vona, loyi a dlayiweke hi siku ra ntungu lowu teke hikwalaho ka Peori.”' }
  ],
  26: [
    { n: 1, text: 'Endzhaku ka ntungu woloye, Yehovha a ku eka Moxe ni eka Eliyazara, n’wana wa Aroni lowu nga muprisita:' },
    { n: 2, text: '“Tekani ntsengo wa nhlengeletano hinkwayo ya vana va Israyele, ku sukela eka lava nga ni malembe ya makume mambirhi ku ya ehenhla, hi ku landza tiyindlu ta vatata va vona, hinkwavo lava nga kotaka ku ya enyimpini eIsrayele.”' },
    { n: 3, text: 'Moxe ni muprisita Eliyazara va vulavula na vona emabaleni ya Mowabu, ekusuhi ni Yordani ku langutana na Yeriko, va ku:' },
    { n: 4, text: '“Tekani ntsengo wa vanhu ku sukela eka lava nga ni malembe ya makume mambirhi ku ya ehenhla, hilaha Yehovha a n’wi leriseke hakona Moxe ni vana va Israyele lava humeke etikweni ra Egipta.”' },
    { n: 5, text: 'Rubeni, mativula ya Israyele; vana va Rubeni: hi Hanoki, ndyangu wa Vahanoki; hi Palu, ndyangu wa Vapalu;' },
    { n: 6, text: 'hi Hesroni, ndyangu wa Vahesroni; hi Karmi, ndyangu wa Vakarmi.' },
    { n: 7, text: 'Loyi i mindyangu ya Varubeni; naswona ntsengo wa vona a wu ri makume mune na nharhu wa magidi na ntsengo wa nkombo wa madzana na makume manharhu.' },
    { n: 8, text: 'Vana va Palu: i Eliyaba.' },
    { n: 9, text: 'Vana va Eliyaba: i Nemuele, Datani ni Abirami. Lava hi vona Datani ni Abirami, vakulukumba va nhlengeletano, lava kaneteke Moxe na Aroni exikarhi ka vatshegami va Kora, loko va kaneta Yehovha;' },
    { n: 10, text: 'naswona misava yi pfula nomu wa yona, yi va mita xikan’we na Kora, loko ntshengandzele lowu u feke, hi nkarhi lowu ndzilo wu heriseke vavanuna va madzana mambirhi na makume ntlhanu; va va xikombiso.' },
    { n: 11, text: 'Kambe vana va Kora a va fanga.' },
    { n: 12, text: 'Vana va Simiyoni hi ku landza mindyangu ya vona: hi Nemuele, ndyangu wa Vanemuele; hi Yamini, ndyangu wa Vayamini; hi Yakini, ndyangu wa Vayakini;' },
    { n: 13, text: 'hi Zera, ndyangu wa Vazera; hi Saulo, ndyangu wa Vasaulo.' },
    { n: 14, text: 'Loyi i mindyangu ya Vasimiyoni, makume mambirhi mambirhi wa magidi na madzana mambirhi.' },
    { n: 15, text: 'Vana va Gadi hi ku landza mindyangu ya vona: hi Sefoni, ndyangu wa Vasefoni; hi Hagi, ndyangu wa Vahagi; hi Suni, ndyangu wa Vasuni;' },
    { n: 16, text: 'hi Ozni, ndyangu wa Vaozni; hi Eri, ndyangu wa Vaeri;' },
    { n: 17, text: 'hi Arodi, ndyangu wa Vaarodi; hi Areli, ndyangu wa Vaareli.' },
    { n: 18, text: 'Loyi i mindyangu ya vana va Gadi hi ku landza ntsengo wa vona, makume mune wa magidi na madzana ya ntlhanu.' },
    { n: 19, text: 'Vana va Yuda: i Ere na Onani; kambe Ere na Onani va fela etikweni ra Kanana.' },
    { n: 20, text: 'Vana va Yuda hi ku landza mindyangu ya vona: hi Sela, ndyangu wa Vasela; hi Peresi, ndyangu wa Vaperesi; hi Zera, ndyangu wa Vazera.' },
    { n: 21, text: 'Vana va Peresi a va ri: hi Hesroni, ndyangu wa Vahesroni; hi Hamule, ndyangu wa Vahamule.' },
    { n: 22, text: 'Loyi i mindyangu ya Yuda hi ku landza ntsengo wa vona, ntlhanu wa makume na nkombo wa magidi na madzana ya tsevu.' },
    { n: 23, text: 'Vana va Isakara hi ku landza mindyangu ya vona: hi Tola, ndyangu wa Vatola; hi Puva, ndyangu wa Vapuva;' },
    { n: 24, text: 'hi Yasubu, ndyangu wa Vayasubu; hi Simroni, ndyangu wa Vasimroni.' },
    { n: 25, text: 'Loyi i mindyangu ya Isakara hi ku landza ntsengo wa vona, tsevu wa makume na mune wa magidi na madzana ya nharhu.' },
    { n: 26, text: 'Vana va Zebuloni hi ku landza mindyangu ya vona: hi Seredi, ndyangu wa Vaseredi; hi Eloni, ndyangu wa Vaeloni; hi Yahalele, ndyangu wa Vayahalele.' },
    { n: 27, text: 'Loyi i mindyangu ya Vazebuloni hi ku landza ntsengo wa vona, tsevu wa makume wa magidi na madzana ya ntlhanu.' },
    { n: 28, text: 'Vana va Yosefa hi ku landza mindyangu ya vona: i Manase na Efraimi.' },
    { n: 29, text: 'Vana va Manase: hi Makiri, ndyangu wa Vamakiri; naswona Makiri a tswala Giliyadi; hi Giliyadi, ndyangu wa Vagiliyadi.' },
    { n: 30, text: 'Lava i vana va Giliyadi: hi Iyezere, ndyangu wa Vaiyezere; hi Heleke, ndyangu wa Vaheleke;' },
    { n: 31, text: 'hi Asriyele, ndyangu wa Vaasriyele; hi Sikeme, ndyangu wa Vasikeme;' },
    { n: 32, text: 'hi Semida, ndyangu wa Vasemida; hi Heferi, ndyangu wa Vaheferi.' },
    { n: 33, text: 'Selofehadi, n’wana wa Heferi, a nga tswalanga vana va majaha, kambe a tswala vana va vanhwanyana ntsena; naswona mavito va vana va vanhwanyana va Selofehadi a a ri Mahela, Nowa, Hogila, Milka na Tirsa.' },
    { n: 34, text: 'Loyi i mindyangu ya Manase; naswona ntsengo wa vona a wu ri ntlhanu wa makume mambirhi wa magidi na madzana ya ntlhanu.' },
    { n: 35, text: 'Lava i vana va Efraimi hi ku landza mindyangu ya vona: hi Sutela, ndyangu wa Vasutela; hi Bekere, ndyangu wa Vabekere; hi Tahani, ndyangu wa Vatahani.' },
    { n: 36, text: 'Lava i vana va Sutela: hi Erani, ndyangu wa Vaerani.' },
    { n: 37, text: 'Loyi i mindyangu ya vana va Efraimi hi ku landza ntsengo wa vona, nharhu wa makume mambirhi wa magidi na madzana ya ntlhanu. Lava i vana va Yosefa hi ku landza mindyangu ya vona.' },
    { n: 38, text: 'Vana va Benjamini hi ku landza mindyangu ya vona: hi Bela, ndyangu wa Vabela; hi Axibele, ndyangu wa Vaaxibele; hi Ahirami, ndyangu wa Vaahirami;' },
    { n: 39, text: 'hi Sufami, ndyangu wa Vasufami; hi Hufami, ndyangu wa Vahufami.' },
    { n: 40, text: 'Vana va Bela a va ri Arde na Namani: hi Arde, ndyangu wa Vaarde; hi Namani, ndyangu wa Vanamani.' },
    { n: 41, text: 'Lava i vana va Benjamini hi ku landza mindyangu ya vona; naswona ntsengo wa vona a wu ri mune wa makume na ntlhanu wa magidi na madzana ya tsevu.' },
    { n: 42, text: 'Lava i vana va Dani hi ku landza mindyangu ya vona: hi Suhami, ndyangu wa Vasuhami. Lava i mindyangu ya Dani hi ku landza mindyangu ya vona.' },
    { n: 43, text: 'Ntsengo hinkwaswo wa mindyangu ya Vasuhami, hi ku landza ntsengo wa vona, a wu ri tsevu wa makume na mune wa magidi na madzana ya mune.' },
    { n: 44, text: 'Vana va Axere hi ku landza mindyangu ya vona: hi Imna, ndyangu wa Vaimna; hi Isvi, ndyangu wa Vaisvi; hi Beriya, ndyangu wa Vaberiya.' },
    { n: 45, text: 'Eka vana va Beriya: hi Hebere, ndyangu wa Vahebere; hi Malkiyele, ndyangu wa Vamalkiyele.' },
    { n: 46, text: 'Naswona vito ra n’wana wa wanhwanyana wa Axere a a ri Sera.' },
    { n: 47, text: 'Loyi i mindyangu ya vana va Axere hi ku landza ntsengo wa vona, ntlhanu wa makume na nharhu wa magidi na madzana ya mune.' },
    { n: 48, text: 'Vana va Neftali hi ku landza mindyangu ya vona: hi Yahasele, ndyangu wa Vayahasele; hi Guni, ndyangu wa Vaguni;' },
    { n: 49, text: 'hi Yesere, ndyangu wa Vayesere; hi Sileme, ndyangu wa Vasileme.' },
    { n: 50, text: 'Loyi i mindyangu ya Neftali hi ku landza mindyangu ya vona; naswona ntsengo wa vona a wu ri mune wa makume na ntlhanu wa magidi na madzana ya mune.' },
    { n: 51, text: 'Loyi i ntsengo wa vana va Israyele hinkwavo, madzana ya tsevu wa magidi na gidi rin’we na ntsengo wa madzana ya nkombo na makume nharhu.' },
    { n: 52, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 53, text: '“Eka lava, tiko ri fanele ku aviwa ku va ndzhaka hi ku landza ntsengo wa mavito.”' },
    { n: 54, text: '“Eka lava va taleke u ta va nyika ndzhaka leyikulu, naswona eka lava va nga va tsongo u ta va nyika ndzhaka leyitsongo; un’wana ni un’wana u ta nyikiwa ndzhaka ya yena hi ku landza ntsengo wa loyi a hlayiweke.”' },
    { n: 55, text: '“Kambe tiko ri ta aviwa hi vuhlolotara; hi ku landza mavito ya tinyimba ta vatata va vona va ta amukela ndzhaka.”' },
    { n: 56, text: '“Hi ku landza vuhlolotara, ndzhaka ya rona yi ta aviwa exikarhi ka lavo tala ni lavo tsongo.”' },
    { n: 57, text: 'Lava i Valevi lava hlayiweke hi ku landza mindyangu ya vona: hi Gerisoni, ndyangu wa Vagerisoni; hi Kohata, ndyangu wa Vakohata; hi Merari, ndyangu wa Vamerari.' },
    { n: 58, text: 'Lava i mindyangu ya Valevi: ndyangu wa Valibni, ndyangu wa Vahebroni, ndyangu wa Vamahli, ndyangu wa Vamuxi, ndyangu wa Vakora. Kohata a tswala Amrami.' },
    { n: 59, text: 'Vito ra wansati wa Amrami a a ri Yokebedi, n’wana wa wanhwanyana wa Levhi, loyi a tswaleriweke Levhi eEgipta; a tswalla Amrami: Aroni, Moxe na Miriyama vamakwavo.' },
    { n: 60, text: 'Aroni a tswala Nadaba, Abihu, Eliyazara na Itamara.' },
    { n: 61, text: 'Kambe Nadaba na Abihu va fa loko va humesa ndzilo lowu nga riki wa xilawulo mahlweni ka Yehovha.' },
    { n: 62, text: 'Ntsengo wa vona hinkwavo wa vavanuna a wu ri mambirhi nharhu wa magidi, ku sukela eka n’hweti yin’we ku ya ehenhla; hikuva a va hlayiwanga exikarhi ka vana va Israyele, hi ku va va nga nyikiwangiki ndzhaka exikarhi ka vana va Israyele.' },
    { n: 63, text: 'Lava i lava hlayiweke hi Moxe ni muprisita Eliyazara, lava hlayeke vana va Israyele emabaleni ya Mowabu, ekusuhi ni Yordani ku langutana na Yeriko.' },
    { n: 64, text: 'Kambe exikarhi ka lava ku nga na wanuna un’we loyi a hlayiweke hi Moxe na Aroni lowu nga muprisita, loko va hlaya vana va Israyele emananga ya Sinayi;' },
    { n: 65, text: 'hikuva Yehovha a a vurile eka vona a ku: “Hakunene va ta fela emananga.” Kutani ku nga sali na un’we wa vona, loko ku nga ri Kalebhe, n’wana wa Yefune, na Yoxuwa, n’wana wa Nuni.' }
  ],
  27: [
    { n: 1, text: 'Kutani ku tshinela vana va vanhwanyana va Selofehadi, n’wana wa Heferi, n’wana wa Giliyadi, n’wana wa Makiri, n’wana wa Manase, wa mindyangu ya Manase, n’wana wa Yosefa; naswona lawa a a ri mavito ya vona: Mahela, Nowa, Hogila, Milka na Tirsa.' },
    { n: 2, text: 'Va yima mahlweni ka Moxe, ni mahlweni ka muprisita Eliyazara, ni mahlweni ka tindhuna ni nhlengeletano hinkwayo, enyangweni ya tende ra nhlengeletano, va ku:' },
    { n: 3, text: '“Tata wa hina u fele emananga, kambe a a nga ri exikarhi ka ntshengandzele wa lava tlhanganeke ku kaneta Yehovha eka ntshengandzele wa Kora; hikuva u fele xidyoho xa yena n’winyi, naswona a a nga ri na vana va majaha.”' },
    { n: 4, text: '“Hikwalaho ka yini vito ra tata wa hina ri fanele ku herisiwa exikarhi ka ndyangu wa yena hi ku va a nga ri na n’wana wa jaha? Hi nyike ndzhaka exikarhi ka vamakwavo va tata wa hina.”' },
    { n: 5, text: 'Moxe a tisa mhaka ya vona mahlweni ka Yehovha.' },
    { n: 6, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 7, text: '“Vana va vanhwanyana va Selofehadi va vulavula ntiyiso; hakunene u fanele ku va nyika ndzhaka exikarhi ka vamakwavo va tata va vona, u hundzisela ndzhaka ya tata va vona eka vona.”' },
    { n: 8, text: '“Naswona u ta vulavula ni vana va Israyele, u ku: ‘Loko munhu a fa a nga ri na n’wana wa jaha, mi ta hundzisela ndzhaka ya yena eka n’wana wa yena wa wanhwanyana.’”' },
    { n: 9, text: '“‘Loko a nga ri na n’wana wa wanhwanyana, mi ta nyika ndzhaka ya yena eka vamakwavo va yena va majaha.’”' },
    { n: 10, text: '“‘Loko a nga ri na vamakwavo va majaha, mi ta nyika ndzhaka ya yena eka vamakwavo va tata wa yena.’”' },
    { n: 11, text: '“‘Loko tata wa yena a nga ri na vamakwavo, mi ta nyika ndzhaka ya yena eka maxaka ya yena ya le kusuhi swinene exikarhi ka ndyangu wa yena, leswaku a yi teka; naswona leswi swi ta va xileriso xa nawu eka vana va Israyele, hilaha Yehovha a n’wi leriseke hakona Moxe.’”' },
    { n: 12, text: 'Yehovha a ku eka Moxe: “Ghandla ehenhla ka ntshava leyi ya Abarimi, u langutisa tiko leri ndzi nga ta va nyika rona vana va Israyele.”' },
    { n: 13, text: '“Loko u ri vonile, na wena u ta hlengeletiwa eka vanhu va wena, hilaha Aroni makwenu a hlengeletiweke hakona;”' },
    { n: 14, text: '“hikuva mi tlurile rileriso ra mina emananga ya Zin, emhakeni ya ku holova ka nhlengeletano, loko mi nga ndzi kwetsimisangiki ematini mahlweni ka mahlo ya vona.” (Lawa i mati ya Meriba eKadesi, emananga ya Zin).' },
    { n: 15, text: 'Moxe a vulavula na Yehovha, a ku:' },
    { n: 16, text: '“Yehovha, Xikwembu xa mimoya ya nyama hinkwayo, a a veke munhu ehenhla ka nhlengeletano leyi,”' },
    { n: 17, text: '“loyi a nga ta huma mahlweni ka vona, a nghena mahlweni ka vona, loyi a nga ta va rhangela ku huma ni ku nghena; leswaku nhlengeletano ya Yehovha yi nga vi ku fana ni tinyimpfu leti nga riki na murisi.”' },
    { n: 18, text: 'Yehovha a ku eka Moxe: “Teka Yoxuwa, n’wana wa Nuni, wanuna loyi a nga ni Moya endzeni ka yena, u veka voko ra wena ehenhla ka yena;”' },
    { n: 19, text: '“u n’wi yimisa mahlweni ka muprisita Eliyazara, ni mahlweni ka nhlengeletano hinkwayo, u n’wi nyika vutihlamuleri mahlweni ka mahlo ya vona.”' },
    { n: 20, text: '“U ta veka xiphemu xa vuhosi bya wena ehenhla ka yena, leswaku nhlengeletano hinkwayo ya vana va Israyele yi n’wi yingisa.”' },
    { n: 21, text: '“U ta yima mahlweni ka muprisita Eliyazara, loyi a nga ta n’wi vutisela xiboho xa Urimi mahlweni ka Yehovha; hi rito ra yena va ta huma, naswona hi rito ra yena va ta nghena, yena ni vana va Israyele hinkwavo xikan’we na yena, nhlengeletano hinkwayo.”' },
    { n: 22, text: 'Moxe a endla hilaha Yehovha a n’wi leriseke hakona; a teka Yoxuwa, a n’wi yimisa mahlweni ka muprisita Eliyazara ni mahlweni ka nhlengeletano hinkwayo;' },
    { n: 23, text: 'a veka mavoko ya yena ehenhla ka yena, a n’wi nyika vutihlamuleri, hilaha Yehovha a vuleke hakona hi nomu wa Moxe.' }
  ],
  28: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Lerisa vana va Israyele, u ku eka vona: ‘Nyiko ya mina, na swakudya swa mina swa mitshegeto ya mina leyi endliweke hi ndzilo, swa risuna ro tsakisa eka mina, mi ta tivonela ku swi tisa eka mina hi nkarhi wa swona lowu vekiweke.’”' },
    { n: 3, text: '“U ta ku eka vona: ‘Leyi i nyiko leyi endliweke hi ndzilo leyi mi nga ta yi tisa eka Yehovha: swinyimpfana swimbirhi swa lembe rin’we leswi nga riki na vusolopoti, siku ni siku, ku va gandzelo ro tswhiwa ra nkarhi hinkwaswo.’”' },
    { n: 4, text: '“‘Xinyimpfana xin’we u ta xi humesa nampundhu, kasi xinyimpfana xa vumbirhi u ta xi humesa madyambu;’”' },
    { n: 5, text: '“‘xikan’we ni xiphemu xa khume xa efa ya chefu ya mapa yo thleketliwa hi xiphemu xa mune xa hini ya mafurha yo hluteka.’”' },
    { n: 6, text: '“‘I gandzelo ro tswhiwa ra nkarhi hinkwaswo, leri endliweke eNtshaveni ya Sinayi, ri va risuna ro tsakisa, nyiko leyi endliweke hi ndzilo eka Yehovha.’”' },
    { n: 7, text: '“‘Kasi gandzelo ra rona ra swakunwa ri ta va xiphemu xa mune xa hini eka xinyimpfana xin’we; endhawuni yo kwetsima u ta chulula gandzelo ra swakunwa swa vhinyo yo tiya eka Yehovha.’”' },
    { n: 8, text: '“‘Xinyimpfana xa vumbirhi u ta xi humesa madyambu; u ta xi humesa xikan’we ni gandzelo ra mapa ni gandzelo ra swakunwa swo fana ni swa nampundhu; i nyiko leyi endliweke hi ndzilo, ya risuna ro tsakisa eka Yehovha.’”' },
    { n: 9, text: '“‘Kambe hi siku ra Savata, mi ta humesa swinyimpfana swimbirhi swa lembe rin’we leswi nga riki na vusolopoti, ni swiphemu swimbirhi swa khume swa mapa yo saseka yo thleketliwa hi mafurha ku va gandzelo ra mapa, xikan’we ni gandzelo ra rona ra swakunwa;’”' },
    { n: 10, text: '“‘leri i gandzelo ro tswhiwa ra Savata yin’wana ni yin’wana, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo ni gandzelo ra rona ra swakunwa.’”' },
    { n: 11, text: '“‘Naswona ematsungulweni ya tinhweti ta n’wina mi ta humesa gandzelo ro tswhiwa eka Yehovha: swinkunzana swimbirhi, khonzi yin’we, ni swinyimpfana swa nkombo swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 12, text: '“‘ni swiphemu swinharhu swa khume swa mapa yo saseka yo thleketliwa hi mafurha ku va gandzelo ra mapa eka nkunzana yin’we; ni swiphemu swimbirhi swa khume swa mapa yo saseka yo thleketliwa hi mafurha ku va gandzelo ra mapa eka khonzi;’”' },
    { n: 13, text: '“‘ni xiphemu xin’we xa khume xa mapa yo saseka yo thleketliwa hi mafurha ku va gandzelo ra mapa eka xinyimpfana xin’we; i gandzelo ro tswhiwa ra risuna ro tsakisa, nyiko leyi endliweke hi ndzilo eka Yehovha.’”' },
    { n: 14, text: '“‘Naswona magandzelo ya swona ra swakunwa ku ta va hafu ya hini ya vhinyo eka nkunzana, ni xiphemu xa nharhu xa hini eka khonzi, ni xiphemu xa mune xa hini eka xinyimpfana; leri i gandzelo ro tswhiwa ra n’hweti ni n’hweti ya lembe.’”' },
    { n: 15, text: '“‘Naswona ku ta humesiwa xiphongo xin’we ku va gandzelo ra xidyoho eka Yehovha, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo ni gandzelo ra rona ra swakunwa.’”' },
    { n: 16, text: '“‘Hi n’hweti yo sungula, hi siku ra khume mune ra n’hweti, ku ta va ni Páscoa ya Yehovha.’”' },
    { n: 17, text: '“‘Naswona hi siku ra khume ntlhanu ra n’hweti leyi ku ta va ni nkhuvo; masiku ya nkombo ku ta dyiwa swinkwa leswi nga riki na nchivirisi.’”' },
    { n: 18, text: '“‘Hi siku ro sungula ku ta va ni nhlengeletano yo kwetsima; mi nga tshuki mi endla ntirho ni un’we wa ku tiseletela.’”' },
    { n: 19, text: '“‘Kambe mi ta humesa nyiko leyi endliweke hi ndzilo, yi va gandzelo ro tswhiwa eka Yehovha: swinkunzana swimbirhi, khonzi yin’we, ni swinyimpfana swa nkombo swa lembe rin’we; swi fanele ku va leswi nga riki na vusolopoti.’”' },
    { n: 20, text: '“‘Naswona gandzelo ra swona ra mapa ku ta va mapa yo saseka yo thleketliwa hi mafurha: swiphemu swinharhu swa khume mi ta swi humesela nkunzana, ni swiphemu swimbirhi swa khume eka khonzi;’”' },
    { n: 21, text: '“‘u ta humesa xiphemu xin’we xa khume eka xinyimpfana xin’we, ku fika eka swinyimpfana hinkwaswo swa nkombo;’”' },
    { n: 22, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ku endla ku rivaleriwa ka n’wina.’”' },
    { n: 23, text: '“‘Mi ta humesa leswi ehenhla ka gandzelo ro tswhiwa ra nampundhu, leri nga gandzelo ro tswhiwa ra nkarhi hinkwaswo.’”' },
    { n: 24, text: '“‘Hi mukhuva lowu mi ta humesa siku ni siku, ku ringana masiku ya nkombo, swakudya swa nyiko leyi endliweke hi ndzilo, swa risuna ro tsakisa eka Yehovha; swi ta humesiwa ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo, ni gandzelo ra rona ra swakunwa.’”' },
    { n: 25, text: '“‘Naswona hi siku ra vunkombo mi ta va ni nhlengeletano yo kwetsima; mi nga tshuki mi endla ntirho ni un’we wa ku tiseletela.’”' },
    { n: 26, text: '“‘Hi siku ra swilulamiselo swo sungula, loko mi tisa nyiko ya mapa leyintshwa eka Yehovha, ematshan’wini ya nkhuvo wa n’wina wa mavhiki, mi ta va ni nhlengeletano yo kwetsima; mi nga tshuki mi endla ntirho ni un’we wa ku tiseletela;’”' },
    { n: 27, text: '“‘kambe mi ta humesa gandzelo ro tswhiwa ra risuna ro tsakisa eka Yehovha: swinkunzana swimbirhi, khonzi yin’we, ni swinyimpfana swa nkombo swa lembe rin’we;’”' },
    { n: 28, text: '“‘ni gandzelo ra swona ra mapa ra mapa yo saseka yo thleketliwa hi mafurha: swiphemu swinharhu swa khume eka nkunzana yin’we, swiphemu swimbirhi swa khume eka khonzi;’”' },
    { n: 29, text: '“‘xiphemu xin’we xa khume eka xinyimpfana xin’we, ku fika eka swinyimpfana hinkwaswo swa nkombo;’”' },
    { n: 30, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ku endla ku rivaleriwa ka n’wina.’”' },
    { n: 31, text: '“‘Mi ta swi humesa swi nga ri na vusolopoti, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo ni gandzelo ra rona ra mapa, xikan’we ni magandzelo ya swona ra swakunwa.’”' }
  ],
  29: [
    { n: 1, text: '“‘Hi n’hweti ya vunkombo, hi siku ro sungula ra n’hweti, mi ta va ni nhlengeletano yo kwetsima; mi nga tshuki mi endla ntirho ni un’we wa ku tiseletela; ku ta va siku ra ku tlhava garingani ra timhondzo eka n’wina.’”' },
    { n: 2, text: '“‘Mi ta humesa gandzelo ro tswhiwa ra risuna ro tsakisa eka Yehovha: nkunzana yin’we, khonzi yin’we, ni swinyimpfana swa nkombo swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 3, text: '“‘ni gandzelo ra swona ra mapa ra mapa yo saseka yo thleketliwa hi mafurha: swiphemu swinharhu swa khume eka nkunzana, swiphemu swimbirhi swa khume eka khonzi;’”' },
    { n: 4, text: '“‘ni xiphemu xin’we xa khume eka xinyimpfana xin’we, ku fika eka swinyimpfana hinkwaswo swa nkombo;’”' },
    { n: 5, text: '“‘xikan’we ni xiphongo xin’we ku va gandzelo ra xidyoho, ku endla ku rivaleriwa ka n’wina;’”' },
    { n: 6, text: '“‘ehenhla ka gandzelo ro tswhiwa ra n’hweti ni gandzelo ra rona ra mapa, ni gandzelo ro tswhiwa ra nkarhi hinkwaswo ni gandzelo ra rona ra mapa, ni magandzelo ya swona ra swakunwa, hi ku landza nawu wa swona, ma va risuna ro tsakisa, nyiko leyi endliweke hi ndzilo eka Yehovha.’”' },
    { n: 7, text: '“‘Hi siku ra khume ra n’hweti leyi ya vunkombo, mi ta va ni nhlengeletano yo kwetsima; mi ta tixanisa mimoya ya n’wina, naswona mi nga tshuki mi endla ntirho ni un’we;’”' },
    { n: 8, text: '“‘kambe mi ta humesa gandzelo ro tswhiwa eka Yehovha ku va risuna ro tsakisa: nkunzana yin’we, khonzi yin’we, ni swinyimpfana swa nkombo swa lembe rin’we; mi fanele ku tivonela leswaku swi nga ri na vusolopoti;’”' },
    { n: 9, text: '“‘ni gandzelo ra swona ra mapa ra mapa yo saseka yo thleketliwa hi mafurha: swiphemu swinharhu swa khume eka nkunzana, swiphemu swimbirhi swa khume eka khonzi;’”' },
    { n: 10, text: '“‘xiphemu xin’we xa khume eka xinyimpfana xin’we, ku fika eka swinyimpfana hinkwaswo swa nkombo;’”' },
    { n: 11, text: '“‘xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ra xidyoho ra ku rivaleriwa, ni gandzelo ro tswhiwa ra nkarhi hinkwaswo, ni gandzelo ra rona ra mapa, xikan’we ni magandzelo ya swona ra swakunwa.’”' },
    { n: 12, text: '“‘Hi siku ra khume ntlhanu ra n’hweti ya vunkombo, mi ta va ni nhlengeletano yo kwetsima; mi nga tshuki mi endla ntirho ni un’we wa ku tiseletela, naswona mi ta endla nkhuvo eka Yehovha ku ringana masiku ya nkombo.’”' },
    { n: 13, text: '“‘Mi ta humesa gandzelo ro tswhiwa, nyiko leyi endliweke hi ndzilo, ya risuna ro tsakisa eka Yehovha: swinkunzana swa khume nharhu, sikhonzi swimbirhi, ni swinyimpfana swa khume mune swa lembe rin’we; swi fanele ku va leswi nga riki na vusolopoti;’”' },
    { n: 14, text: '“‘ni gandzelo ra swona ra mapa ra mapa yo saseka yo thleketliwa hi mafurha: swiphemu swinharhu swa khume eka nkunzana yin’wana ni yin’wana ya swinkunzana swa khume nharhu, swiphemu swimbirhi swa khume eka khonzi yin’wana ni yin’wana ya sikhonzi swimbirhi;’”' },
    { n: 15, text: '“‘ni xiphemu xin’we xa khume eka xinyimpfana xin’wana ni yin’wana ya swinyimpfana swa khume mune;’”' },
    { n: 16, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo, gandzelo ra rona ra mapa ni gandzelo ra rona ra swakunwa.’”' },
    { n: 17, text: '“‘Hi siku ra vumbirhi: swinkunzana swa khume mambirhi, sikhonzi swimbirhi, ni swinyimpfana swa khume mune swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 18, text: '“‘ni gandzelo ra swona ra mapa ni magandzelo ya swona ra swakunwa eka swinkunzana, eka sikhonzi ni eka swinyimpfana, hi ku landza ntsengo wa swona, hilaha swi lerisiweke hakona;’”' },
    { n: 19, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo ni gandzelo ra rona ra mapa, xikan’we ni magandzelo ya swona ra swakunwa.’”' },
    { n: 20, text: '“‘Hi siku ra vunharhu: swinkunzana swa khume n’we, sikhonzi swimbirhi, ni swinyimpfana swa khume mune swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 21, text: '“‘ni gandzelo ra swona ra mapa ni magandzelo ya swona ra swakunwa eka swinkunzana, eka sikhonzi ni eka swinyimpfana, hi ku landza ntsengo wa swona, hilaha swi lerisiweke hakona;’”' },
    { n: 22, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo, ni gandzelo ra rona ra mapa, xikan’we ni gandzelo ra rona ra swakunwa.’”' },
    { n: 23, text: '“‘Hi siku ra vumune: swinkunzana va khume, sikhonzi swimbirhi, ni swinyimpfana swa khume mune swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 24, text: '“‘gandzelo ra swona ra mapa ni magandzelo ya swona ra swakunwa eka swinkunzana, eka sikhonzi ni eka swinyimpfana, hi ku landza ntsengo wa swona, hilaha swi lerisiweke hakona;’”' },
    { n: 25, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo, gandzelo ra rona ra mapa ni gandzelo ra rona ra swakunwa.’”' },
    { n: 26, text: '“‘Hi siku ra vuntlhanu: swinkunzana swa nkombo-mbirhi, sikhonzi swimbirhi, ni swinyimpfana swa khume mune swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 27, text: '“‘ni gandzelo ra swona ra mapa ni magandzelo ya swona ra swakunwa eka swinkunzana, eka sikhonzi ni eka swinyimpfana, hi ku landza ntsengo wa swona, hilaha swi lerisiweke hakona;’”' },
    { n: 28, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo, ni gandzelo ra rona ra mapa, xikan’we ni gandzelo ra rona ra swakunwa.’”' },
    { n: 29, text: '“‘Hi siku ra vutsevu: swinkunzana swa tsevu-mune, sikhonzi swimbirhi, ni swinyimpfana swa khume mune swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 30, text: '“‘ni gandzelo ra swona ra mapa ni magandzelo ya swona ra swakunwa eka swinkunzana, eka sikhonzi ni eka swinyimpfana, hi ku landza ntsengo wa swona, hilaha swi lerisiweke hakona;’”' },
    { n: 31, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo, gandzelo ra rona ra mapa ni magandzelo ya swona ra swakunwa.’”' },
    { n: 32, text: '“‘Hi siku ra vunkombo: swinkunzana swa nkombo, sikhonzi swimbirhi, ni swinyimpfana swa khume mune swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 33, text: '“‘ni gandzelo ra swona ra mapa ni magandzelo ya swona ra swakunwa eka swinkunzana, eka sikhonzi ni eka swinyimpfana, hi ku landza ntsengo wa swona, hilaha swi lerisiweke hakona;’”' },
    { n: 34, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo, ni gandzelo ra rona ra mapa, xikan’we ni gandzelo ra rona ra swakunwa.’”' },
    { n: 35, text: '“‘Hi siku ra vuntlhanu-nharhu ku ta va ni nhlengeletano yo hlawuleka eka n’wina; mi nga tshuki mi endla ntirho ni un’we wa ku tiseletela;’”' },
    { n: 36, text: '“‘kambe mi ta humesa gandzelo ro tswhiwa, nyiko leyi endliweke hi ndzilo, ya risuna ro tsakisa eka Yehovha: nkunzana yin’we, khonzi yin’we, ni swinyimpfana swa nkombo swa lembe rin’we leswi nga riki na vusolopoti;’”' },
    { n: 37, text: '“‘gandzelo ra swona ra mapa ni magandzelo ya swona ra swakunwa eka nkunzana, eka khonzi ni eka swinyimpfana, hi ku landza ntsengo wa swona, hilaha swi lerisiweke hakona;’”' },
    { n: 38, text: '“‘xikan’we ni xiphongo xin’we xa gandzelo ra xidyoho, ehenhla ka gandzelo ro tswhiwa ra nkarhi hinkwaswo, ni gandzelo ra rona ra mapa, xikan’we ni gandzelo ra rona ra swakunwa.’”' },
    { n: 39, text: '“‘Mi ta endla swileswi eka Yehovha eminkhuvweni ya n’wina leyi vekiweke, ehenhla ka switshembiso swa n’wina ni ku tinyikela ka n’wina ku fana ni magandzelo ya n’wina yo tswhiwa, ni magandzelo ya n’wina ya mapa, ni magandzelo ya n’wina ya swakunwa, ni magandzelo ya n’wina ya ku khongela.’”' },
    { n: 40, text: 'Moxe a tivisa vana va Israyele hinkwavaswo leswi Yehovha a n’wi leriseke hakona.' }
  ],
  30: [
    { n: 1, text: 'Moxe a vulavula ni tinhloko ta tinyimba ta vana va Israyele, a ku: “Leyi i mhaka leyi Yehovha a yi leriseke:”' },
    { n: 2, text: '“Loko wanuna a endla xitshembiso eka Yehovha, kumbe a hlambanya hi xihambano lexi n’wi bohahaka moya wa yena, a nga tshuki a tlula rito ra yena; u ta endla hinkwaswo leswi humeke enon’wini wa yena.”' },
    { n: 3, text: '“Loko wanhwanyana a endla xitshembiso eka Yehovha, kumbe a tiboha hi xiboho a ha ri endlwini ya tata wa yena, evuntshweni bya yena,”' },
    { n: 4, text: '“kutani tata wa yena a twa xitshembiso xa yena, ni xiboho lexi a tibopheke ha xona, kambe tata wa yena a nga n’wi kaneti, switshembiso swa yena hinkwaswo swi ta yima, na xiboho xin’wana ni xin’wana lexi a tibopheke ha xona xi ta yima.”' },
    { n: 5, text: '“Kambe loko tata wa yena a n’wi kaneta hi siku leri a swi twaka ha rona, ku hava xitshembiso xa yena, kumbe xiboho xa yena lexi a tibopheke ha xona, lexi nga ta yima; naswona Yehovha u ta n’wi rivalela, hikuva tata wa yena u n’wi kanetile.”' },
    { n: 6, text: '“Loko o kala a tekiwa hi wanuna, a ha ri ni switshembiso swa yena ehenhla ka yena, kumbe xivulavuriwa xa nchumu xo huma emilombyeni ya yena, lexi a tibopheke ha xona;”' },
    { n: 7, text: '“kutani nuna wa yena a swi twa, kambe a nga n’wi kaneti hi siku leri a swi twaka ha rona, switshembiso swa yena swi ta yima, ni swiboho swa yena leswi a tibopheke ha xona swi ta yima.”' },
    { n: 8, text: '“Kambe loko nuna wa yena a n’wi kaneta hi siku leri a swi twaka ha rona, u ta herisa xitshembiso xa yena lexi a a ri na xona ehenhla ka yena, ni xivulavuriwa xa nchumu xo huma emilombyeni ya yena, lexi a tibopheke ha xona; naswona Yehovha u ta n’wi rivalela.”' },
    { n: 9, text: '“Kambe xitshembiso xa noni kumbe leyi dlayiweke vukati, hinkwaswo leswi a tibopheke ha xona swi ta yima ehenhla ka yena.”' },
    { n: 10, text: '“Loko a endle xitshembiso endlwini ya nuna wa yena, kumbe a tibophe hi xihambano hi ku hlambanya,”' },
    { n: 11, text: '“kutani nuna wa yena a swi twa, kambe a nga n’wi kaneti, naswona a nga n’wi yaleli, switshembiso swa yena hinkwaswo swi ta yima, ni xiboho xin’wana ni xin’wana lexi a tibopheke ha xona xi ta yima.”' },
    { n: 12, text: '“Kambe loko nuna wa yena a swi herisile hi ku helela hi siku leri a swi twaka ha rona, ku hava nchumu lowu humeke emilombyeni ya yena, lowu nga switshembiso swa yena kumbe swiboho swa moya wa yena, lowu nga ta yima; nuna wa yena u swi herisile, naswona Yehovha u ta n’wi rivalela.”' },
    { n: 13, text: '“Xitshembiso xin’wana ni xin’wana, ni xihambano xin’wana ni xin’wana lexi hlambanyeriweke ku tshanisa moya, nuna wa yena a nga xi yimisa, kumbe nuna wa yena a nga xi herisa.”' },
    { n: 14, text: '“Kambe loko nuna wa yena a miyele hi ku helela siku ni siku, u yimisa switshembiso swa yena hinkwaswo, kumbe swiboho bya yena hinkwabyo lebyi nga ehenhla ka yena; u swi yimisile, hikuva a nga n’wi kanetanga hi siku leri a swi tweke ha rona.”' },
    { n: 15, text: '“Kambe loko o swi herisa endzhaku ka nkarhi lowu a swi tweke ha rona, u ta rhwala vubihi bya yena.”' },
    { n: 16, text: 'Lawa i milawu leyi Yehovha a yi leriseke Moxe, exikarhi ka wanuna ni nsati wa yena, ni le xikarhi ka tatana ni n’wana wa yena wa wanhwanyana evuntshweni bya yena, a ha ri endlwini ya tata wa yena.' }
  ],
  31: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Rihisela vana va Israyele eka Vamidiyani; endzhaku ka sweswo u ta hlengeletiwa eka vanhu va wena.”' },
    { n: 3, text: 'Moxe a vulavula ni vanhu, a ku: “Hlomisani vavanuna exikarhi ka n’wina va ya enyimpfini, leswaku va lwa ni Midiyani, va tisa ku rihiselela ka Yehovha eka Midiyani.”' },
    { n: 4, text: '“Mi ta rhuma vanhu va gidi eka nyimba yin’wana ni yin’wana, eka tinyimba hinkwato ta Israyele, va ya enyimpfini.”' },
    { n: 5, text: 'Kutani ku hlawuriwa gidi eka nyimba yin’wana ni yin’wana eka timiliyoni ta Israyele, vavanuna va khume-mbirhi wa magidi lava hlomiseriweke nyimpfa.' },
    { n: 6, text: 'Moxe a va rhuma enyimpfini, gidi eka nyimba yin’wana ni yin’wana, na Pinehasi n’wana wa muprisita Eliyazara enyimpfini, a ri ni swibya swo kwetsima ni timhondzo to tlhava garingani evokweni xa yena.' },
    { n: 7, text: 'Va lwa ni Midiyani, hilaha Yehovha a n’wi leriseke hakona Moxe, va dlaya vavanuna hinkwavo.' },
    { n: 8, text: 'Va dlaya tihosi ta Midiyani xikan’we ni lava dlayiweke: Evi, Rekeme, Suru, Huri na Reba, tihosi ta ntlhanu ta Midiyani; naswona va dlaya na Balama n’wana wa Beori hi banga.' },
    { n: 9, text: 'Vana va Israyele va teka vavasati va Midiyani ni vana va vona va ri makhumbi, va phangha ni swifuwo swa vona hinkwaswo, ni mitlhambi ya vona hinkwayo, ni rufuwo ra vona hinkwaro.' },
    { n: 10, text: 'Va tshivela hi ndzilo miti ya vona hinkwayo lomu a va tshama kona, ni mixaxa ya vona hinkwayo.' },
    { n: 11, text: 'Va teka swo phanghiwa hinkwaswo, ni swilo hinkwaswo leswi phanghiweke, vavanuna ni swifuwo.' },
    { n: 12, text: 'Va tisa makhumbi, ni leswi phanghiweke, ni swo tekiwa, eka Moxe ni ka muprisita Eliyazara, ni le ka nhlengeletano ya vana va Israyele, emixaxeni ya le rivaleni ra Mowabu, leri nga kusuhi ni Jordano eYeriko.' },
    { n: 13, text: 'Moxe, ni muprisita Eliyazara, ni tindhuna hinkwato ta nhlengeletano va huma va ya va hlangabeza ehandle ka mixaxa.' },
    { n: 14, text: 'Moxe a hlundzukela tindhuna ta vuthu, tikhambidari ta magidi ni tikhambidari ta madzana, leti a ti vuya hi le nyimpfini.' },
    { n: 15, text: 'Moxe a ku eka vona: “Xana mi tshike vavasati hinkwavo va hanya?”' },
    { n: 16, text: '“Waswivo, hi vona lava nga endla leswaku vana va Israyele, hi xitsundzuxo xa Balama, va dyohela Yehovha emhakeni ya Peori, kutani ku va ni ntungu exikarhi ka nhlengeletano ya Yehovha.”' },
    { n: 17, text: '“Hikwalaho, dlayani vana va majaha hinkwavo exikarhi ka vana, naswona dlayani wansati hinkwayo loyi a tiveke wanuna hi ku etlela na yena.”' },
    { n: 18, text: '“Kambe vana hinkwavo va vanhwanyana, lava nga tivangiki wanuna hi ku etlela na yena, mi va tshika va hanya leswaku ku va va n’wina.”' },
    { n: 19, text: '“Kasi n’wina, tshamani ehandle ka mixaxa ku ringana masiku ya nkombo; un’wana ni un’wana loyi a dlayeke munhu, ni un’wana ni un’wana loyi a khumbeke loyi a dlayiweke, u ta tibasisa hi siku ra vunharhu ni hi siku ra vunkombo, n’wina ni makhumbi ya n’wina.”' },
    { n: 20, text: '“Mi ta basisa nguvu yin’wana ni yin’wana, ni xilo xin’wana ni xin’wana xa xikhumba, ni hinkwaswo leswi endliweke hi voya bya timbuti, ni xibya xin’wana ni xin’wana xa ntsandza.”' },
    { n: 21, text: 'Muprisita Eliyazara a ku eka vavanuna va nyimpfi lava yeke enyimpfini: “Leri i xileriso xa nawu lowu Yehovha a n’wi leriseke wona Moxe:”' },
    { n: 22, text: '“‘ntsena nsuku, ni silivhere, ni kopa, ni ntsimbi, ni tinti, ni vurhandze,’”' },
    { n: 23, text: '“‘nchumu hinkwaro lowu tiyiselaka ndzilo, mi ta wu hundzisa hi ndzilo, kutani wu ta basa; kambe wu ta basisiwa ni hi mati ya ku tsuvula; naswona hinkwaswo leswi nga tiyiseliki ndzilo mi ta swi hundzisa hi mati.’”' },
    { n: 24, text: '“‘Mi ta hlantswa tinguvu ta n’wina hi siku ra vunkombo, mi ta basa; kutani endzhaku ka sweswo mi nga nghena emixaxeni.’”' },
    { n: 25, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 26, text: '“Hlaya ntsengo wa swo phanghiwa leswi tekiweke, vavanuna ni swifuwo, wena, ni muprisita Eliyazara, ni tinhloko ta mindyangu ta nhlengeletano;”' },
    { n: 27, text: '“u avelana swo phanghiwa hi swiphemu swimbirhi: exikarhi ka vavanuna va nyimpfi lava yeke enyimpfini, ni le xikarhi ka nhlengeletano hinkwayo.”' },
    { n: 28, text: '“U ta hlengeletela Yehovha mutsengo eka vavanuna va nyimpfi lava yeke enyimpfini: nchumu wun’we eka madzana ya ntlhanu, eka vanhu, ni le ka tihomu, ni le ka timbhongolo, ni le ka timfutsu;”' },
    { n: 29, text: '“mi ta swi teka eka hafu ya vona, u swi nyika muprisita Eliyazara, swi va nyiko yo tlakusiwa eka Yehovha.”' },
    { n: 30, text: '“Kambe eka hafu ya vana va Israyele u ta teka nchumu wun’we eka makume ya ntlhanu, eka vanhu, eka tihomu, eka timbhongolo, ni le ka timfutsu, eka swifuwo hinkwaswo, u swi nyika Valevhi, lava hlayisaka vutihlamuleri bya tabernakela ya Yehovha.”' },
    { n: 31, text: 'Moxe ni muprisita Eliyazara va endla hilaha Yehovha a n’wi leriseke hakona Moxe.' },
    { n: 32, text: 'Swo phanghiwa leswi seleke eka leswi phanghiweke hi vavanuna va nyimpfi, a ku ri: tinyimpfu ta tsevu wa madzana ni makume ya nkombo na ntlhanu wa magidi,' },
    { n: 33, text: 'ni tihomu ta makume ya nkombo na timbirhi wa magidi,' },
    { n: 34, text: 'ni timbhongolo ta makume ya tsevu ni xin’we wa magidi,' },
    { n: 35, text: 'ni vanhu, ku nga vavasati lava nga tivangiki wanuna hi ku etlela na yena, hinkwavo a va ri makume ya nharhu na mambirhi wa magidi.' },
    { n: 36, text: 'Hafu, ku nga xiavelo xa lava yeke enyimpfini, ntsengo wa swona a ku ri tinyimpfu ta madzana manharhu ni makume ya nharhu na nkombo wa magidi ni magidi ya ntlhanu;' },
    { n: 37, text: 'mutsengo wa tinyimpfu eka Yehovha a a ri tsevu wa madzana ni makume ya nkombo na ntlhanu;' },
    { n: 38, text: 'homu a ti ri makume ya nharhu na tsevu wa magidi; mutsengo wa tona eka Yehovha a a ri makume ya nkombo na timbirhi;' },
    { n: 39, text: 'timbhongolo a ti ri makume ya nharhu wa magidi ni magidi ya ntlhanu; mutsengo wa tona eka Yehovha a a ri makume ya tsevu ni xin’we;' },
    { n: 40, text: 'ni vanhu a va ri khume-tsevu wa magidi; mutsengo wa vona eka Yehovha a a ri vanhu va makume ya nharhu na mambirhi.' },
    { n: 41, text: 'Moxe a nyika muprisita Eliyazara mutsengo wa nyiko yo tlakusiwa eka Yehovha, hilaha Yehovha a n’wi leriseke hakona Moxe.' },
    { n: 42, text: 'Eka hafu ya vana va Israyele, leyi Moxe a yi hambanyiseke ni ya vavanuna va nyimpfi,' },
    { n: 43, text: '(hafu ya nhlengeletano a a ri tinyimpfu ta madzana manharhu ni makume ya nharhu na nkombo wa magidi ni magidi ya ntlhanu,' },
    { n: 44, text: 'ni tihomu ta makume ya nharhu na tsevu wa magidi,' },
    { n: 45, text: 'ni timbhongolo ta makume ya nharhu wa magidi ni magidi ya ntlhanu,' },
    { n: 46, text: 'ni vanhu va khume-tsevu wa magidi);' },
    { n: 47, text: 'eka hafu leyi ya vana va Israyele, Moxe a teka nchumu wun’we eka makume ya ntlhanu, eka vanhu ni le ka swifuwo, a swi nyika Valevhi, lava hlayisaka vutihlamuleri bya tabernakela ya Yehovha, hilaha Yehovha a n’wi leriseke hakona Moxe.' },
    { n: 48, text: 'Kutani tindhuna leti a ti ri ehenhla ka magidi ya vuthu, tikhambidari ta magidi ni tikhambidari ta madzana va tshinela eka Moxe;' },
    { n: 49, text: 'va ku eka Moxe: “Malandza va wena va hlayile ntsengo wa vavanuna va nyimpfi lava nga ehansi ka vutihlamuleri bya hina, naswona ku hava wanuna ni un’we loyi a pfumalekaka eka hina.”' },
    { n: 50, text: '“Hi tisele nyiko eka Yehovha, leswi wanuna un’wana ni un’wana a swi kumeke, swilo swa nsuku: swijini, ni swivindzi, ni swingwavila, ni swipfalo swa tindleve, ni switende, ku endla ku rivaleriwa ka mimoya ya hina mahlweni ka Yehovha.”' },
    { n: 51, text: 'Moxe ni muprisita Eliyazara va amukela nsuku eka vona, swilo hinkwaswo leswi endliweke.' },
    { n: 52, text: 'Nsuku hinkwaro wa nyiko yo tlakusiwa lowu va wu humeseke eka Yehovha, lowu humeke eka tikhambidari ta magidi ni tikhambidari ta madzana, a wu fika khume-tsevu wa magidi ni madzana ya nkombo na makume ya ntlhanu wa tixekele.' },
    { n: 53, text: '(Hikuva vavanuna va nyimpfi a va phanghile, un’wana ni un’wana a ri ni leswi phanghiweke hi yena n’winyi).' },
    { n: 54, text: 'Moxe ni muprisita Eliyazara va teka nsuku lowu eka tikhambidari ta magidi ni ta madzana, va wu nghenisa etendeni ra nhlengeletano, ku va xitsundzuxo xa vana va Israyele mahlweni ka Yehovha.' }
  ],
  32: [
    { n: 1, text: 'Vana va Ruben ni vana va Gadi a va ri ni swifuwo swo tala swinene; va vona tiko ra Yazere ni tiko ra Giliyadi, waswivo, ndhawu leyi a a ri ndhawu yo fanelekela swifuwo.' },
    { n: 2, text: 'Vana va Gadi ni vana va Ruben va ta, va vulavula na Moxe, ni ka muprisita Eliyazara, ni ka tindhuna ta nhlengeletano, va ku:' },
    { n: 3, text: '“Ataroti, Diboni, Yazere, Nimra, Hexiboni, Eliyale, Sebama, Nebo na Beyoni,”' },
    { n: 4, text: '“tiko leri Yehovha a ri weleke mahlweni ka nhlengeletano ya Israyele, i tiko ra swifuwo, naswona malandza ya wena ma ni swifuwo.”' },
    { n: 5, text: 'Va ku: “Loko hi kumile tintswalo emantlhanyeni ya wena, tiko leri a ri nyikiwe malandza ya wena ku va ndzhaka; u nga hi hundzisi Jordano.”' },
    { n: 6, text: 'Moxe a ku eka vana va Gadi ni ka vana va Ruben: “Xana vamakwenu va ta ya enyimpfini, kasi n’wina mi tshama laha?”' },
    { n: 7, text: '“Hikwalaho ka yini mi heta matimba vana va Israyele leswaku va nga hundzeli ematiko lawa Yehovha a va nyikeke wona?”' },
    { n: 8, text: '“Hi swona leswi vata va n’wina va nga swi endla, loko ndzi va rhuma va suka eKadesi-barinea ku ya langutisa tiko.”' },
    { n: 9, text: '“Loko va tlhandlukile va fika exinkoveni xa Exikolo, va langutisa tiko, va hete matimba vana va Israyele, leswaku va nga ngheni ematikweni lawa Yehovha a va nyikeke wona.”' },
    { n: 10, text: '“Kutani vukari bya Yehovha byi pfuka hi siku rero, a hlambanya, a ku:”' },
    { n: 11, text: '“‘Hakunene ku hava wanuna eka lava tlhandlukeke va suka eEgipta, ku sukela eka makume mambirhi ya malembe ni ku tlhandluka, loyi a nga ta vona tiko leri ndzi nga hlambanyela Abrahama, Isaka na Yakobo ku va nyika rona; hikuva a va ndzi landzelelanga hi ku helela;’”' },
    { n: 12, text: '“‘handle ka Kalebe n’wana wa Yefune wa Mukeni, na Yoxuwa n’wana wa Nuni; hikuva va landzelele Yehovha hi ku helela.’”' },
    { n: 13, text: '“Vukari bya Yehovha byi pfukela Israyele, a va endla leswaku va rhendzeleka emananga ku ringana makume ya mune wa malembe, ku fika lomu xitukulwana hinkwaxo lexi endleke vubihi emihlweni ya Yehovha xi herisiweke.”' },
    { n: 14, text: '“Kutani waswivo, n’wina mi pfukile ematshan’wini ya vata va n’wina, mi ri ku hlengeletana ka vadyohi, ku engetela vukari byo hisa bya Yehovha eka Israyele.”' },
    { n: 15, text: '“Loko mi tlhela mi tshika ku n’wi landzela, u ta tlhela a va siya emananga, kutani mi ta herisa vanhu lava hinkwavo.”' },
    { n: 16, text: 'Kutani va tshinela eka yena, va ku: “Hi ta aka swivala swa timbuti swa swifuwo swa hina laha, ni miti ya vana va hina;”' },
    { n: 17, text: '“kambe hina hi ta hlomisa swiendlisinkulu mahlweni ka vana va Israyele, ku fika lomu hi nga ta va tisa endhawuni ya vona; kasi vana va hina va ta tshama emitini leyi rhendzeriweke hi makhumbi hikwalaho ka vaaki va tiko.”' },
    { n: 18, text: '“A hi nga tlheli emitini ya hina ku fika lomu vana va Israyele va nga amukela un’wana ni un’wana ndzhaka ya yena.”' },
    { n: 19, text: '“Hikuva a hi nga amukeli ndzhaka na vona entsungeni wa Jordano ni le mahlweni; hikuva ndzhaka ya hina yi wele eka hina entsungeni wa Jordano hi le vuxeni.”' },
    { n: 20, text: 'Moxe a ku eka vona: “Loko mi endla mhaka leyi, loko mi hlomela nyimpfi mahlweni ka Yehovha;”' },
    { n: 21, text: '“kutani un’wana ni un’wana wa n’wina loyi a hlomeke a hundza Jordano mahlweni ka Yehovha, ku fika lomu a nga ta va a hlongorile valala va yena mahlweni ka yena,”' },
    { n: 22, text: '“ni tiko ri endliwa leri nga ehansi ka Yehovha; endzhaku ka sweswo mi nga vuya, mi nga vi na vutihlamuleri mahlweni ka Yehovha ni mahlweni ka Israyele; kutani tiko leri ri ta va ndzhaka ya n’wina mahlweni ka Yehovha.”' },
    { n: 23, text: '“Kambe loko mi nga endli swona, waswivo, mi dyohele Yehovha; naswona tivani leswaku xidyoho xa n’wina xi ta mi kuma.”' },
    { n: 24, text: '“Akati miti ya vana va n’wina, ni swivala swa tinyimpfu ta n’wina; kambe endli hinkwaswo leswi humeke emilombyeni ya n’wina.”' },
    { n: 25, text: 'Vana va Gadi ni vana va Ruben va vulavula na Moxe, va ku: “Malandza ya wena ma ta endla hilaha n’winyi wa mina a leriseke hakona.”' },
    { n: 26, text: '“Vana va hina, ni vavasati va hina, ni mitlhambi ya hina, ni swifuwo hinkwaswo swa hina swi ta sala laha, emitini ya Giliyadi;”' },
    { n: 27, text: '“kambe malandza ya wena ma ta hundza, un’wana ni un’wana loyi a hlomeleke nyimpfa, mahlweni ka Yehovha ku ya enyimpfini, hilaha n’winyi wa mina a vuleke hakona.”' },
    { n: 28, text: 'Kutani Moxe a va vekela vutihlamuleri eka muprisita Eliyazara, ni le ka Yoxuwa n’wana wa Nuni, ni le ka tinhloko ta tinyimba ta vana va Israyele;' },
    { n: 29, text: 'Moxe a ku eka vona: “Loko vana va Gadi ni vana va Ruben va hundza na n’wina Jordano, un’wana ni un’wana loyi a hlomeleke nyimpfa mahlweni ka Yehovha, kutani tiko ri endliwa leri nga ehansi ka n’wina, mi ta va nyika tiko ra Giliyadi ku va ndzhaka;”' },
    { n: 30, text: '“kambe loko va nga hundzi na n’wina va hlomile, va ta amukela ndzhaka exikarhi ka n’wina etikweni ra Kanana.”' },
    { n: 31, text: 'Vana va Gadi ni vana va Ruben va hlamula, va ku: “Leswi Yehovha a swi vuleke eka malandza ya wena, hi ta endla swona.”' },
    { n: 32, text: '“Hi ta hundza hi hlomile mahlweni ka Yehovha etikweni ra Kanana, leswaku ndzhaka ya hina entsungeni wa Jordano yi va ya hina.”' },
    { n: 33, text: 'Kutani Moxe a va nyika, vana va Gadi, ni vana va Ruben, ni le ka ntshengandzele wa nyimba ya Manase n’wana wa Yosefa, mfumo wa Sihoni hosi ya Vaamori, ni mfumo wa Ogo hosi ya Baxani, tiko leri ri nga ni miti ya rona ni mindzilakana ya miti ya tiko hinkwaro.' },
    { n: 34, text: 'Vana va Gadi va aka Diboni, Ataroti na Aroere;' },
    { n: 35, text: 'na Atroti-sofani, Yazere ni Yogbeha;' },
    { n: 36, text: 'na Beta-nimra ni Beta-harani, miti leyi rhendzeriweke hi makhumbi, ni swivala swa tinyimpfu.' },
    { n: 37, text: 'Vana va Ruben va aka Hexiboni, Eliyale na Kiriyatayimi;' },
    { n: 38, text: 'na Nebo, na Baala-meyoni (mavito ya tona ma hundzuriwa), na Sibma; va nyika mavito mambe emitini leyi va yi akeke.' },
    { n: 39, text: 'Vana va Makiri n’wana wa Manase va ya eGiliyadi, va yi teka, va hlongola Vaamori lava a va ri endzeni ka yona.' },
    { n: 40, text: 'Moxe a nyika Giliyadi eka Makiri n’wana wa Manase; a tshama endzeni ka yona.' },
    { n: 41, text: 'Yayire n’wana wa Manase a ya, a teka swimitana swa rona, a swi vitana Havoti-yayire.' },
    { n: 42, text: 'Noba a ya, a teka Kenati ni swimitana swa rona, a swi vitana Noba, hi vito ra yena n’winyi.' }
  ],
  33: [
    { n: 1, text: 'Lawa i maendzo ya vana va Israyele, lava humeke etikweni ra Egipta hi masocha ya vona, ehansi ka vutiyiseki bya Moxe na Aroni.' },
    { n: 2, text: 'Moxe a tsala matshalelo ya ku suka ka vona hi ku landza maendzo ya vona, hi ku lerisa ka Yehovha; naswona lawa i maendzo ya vona hi ku landza matshalelo ya vona.' },
    { n: 3, text: 'Va suka eRamesese hi n’hweti yo sungula, hi siku ra khume ntlhanu ra n’hweti yo sungula; hi siku leri landzelaka ra Páscoa, vana va Israyele va huma hi voko leri tlakukeke mahlweni ka mahlo ya Vaegipta hinkwavo,' },
    { n: 4, text: 'loko Vaegipta va ri karhi va lahla hinkwavo mativula ya vona, lava Yehovha a va dlayeke exikarhi ka vona; naswona Yehovha a tisa swigwevo ehenhla ka swikwembu swa vona.' },
    { n: 5, text: 'Vana va Israyele va suka eRamesese, va gwimba eSukoti.' },
    { n: 6, text: 'Va suka eSukoti, va gwimba eEtami, leri nga emundzilakanini wa mananga.' },
    { n: 7, text: 'Va suka eEtami, va tlhela va kongoma ePi-hahiroti, leri nga mahlweni ka Baala-sefoni; va gwimba mahlweni ka Migidoli.' },
    { n: 8, text: 'Va suka mahlweni ka Pi-hahiroti, va hundza exikarhi ka lwandle va nghena emananga; va famba pfhuka wa masiku manharhu emananga ya Etami, va gwimba eMara.' },
    { n: 9, text: 'Va suka eMara, va fika eElimi; eElimi a ku ri ni swihlovo swa mati swa khume-mbirhi ni mincindzu ya makume ya nkombo; kutani va gwimba kona.' },
    { n: 10, text: 'Va suka eElimi, va gwimba ekusuhi ni Lwandle lwo Tshwuka.' },
    { n: 11, text: 'Va suka ekusuhi ni Lwandle lwo Tshwuka, va gwimba emananga ya Sini.' },
    { n: 12, text: 'Va suka emananga ya Sini, va gwimba eDofka.' },
    { n: 13, text: 'Va suka eDofka, va gwimba eAluxi.' },
    { n: 14, text: 'Va suka eAluxi, va gwimba eRefidimi, lomu vanhu va nga pfumalaka mati yo nwa kona.' },
    { n: 15, text: 'Va suka eRefidimi, va gwimba emananga ya Sinayi.' },
    { n: 16, text: 'Va suka emananga ya Sinayi, va gwimba eKibroti-hatava.' },
    { n: 17, text: 'Va suka eKibroti-hatava, va gwimba eHaseroti.' },
    { n: 18, text: 'Va suka eHaseroti, va gwimba eRitma.' },
    { n: 19, text: 'Va suka eRitma, va gwimba eRimoni-peresi.' },
    { n: 20, text: 'Va suka eRimoni-peresi, va gwimba eLibna.' },
    { n: 21, text: 'Va suka eLibna, va gwimba eRisa.' },
    { n: 22, text: 'Va suka eRisa, va gwimba eKehelata.' },
    { n: 23, text: 'Va suka eKehelata, va gwimba eNtshaveni ya Seferi.' },
    { n: 24, text: 'Va suka eNtshaveni ya Seferi, va gwimba eHarada.' },
    { n: 25, text: 'Va suka eHarada, va gwimba eMakeloti.' },
    { n: 26, text: 'Va suka eMakeloti, va gwimba eTahati.' },
    { n: 27, text: 'Va suka eTahati, va gwimba eTera.' },
    { n: 28, text: 'Va suka eTera, va gwimba eMitka.' },
    { n: 29, text: 'Va suka eMitka, va gwimba eHasmona.' },
    { n: 30, text: 'Va suka eHasmona, va gwimba eMoseroti.' },
    { n: 31, text: 'Va suka eMoseroti, va gwimba eBane-yakani.' },
    { n: 32, text: 'Va suka eBane-yakani, va gwimba eHoro-hagidgadi.' },
    { n: 33, text: 'Va suka eHoro-hagidgadi, va gwimba eYotbata.' },
    { n: 34, text: 'Va suka eYotbata, va gwimba eAbrona.' },
    { n: 35, text: 'Va suka eAbrona, va gwimba eEsiyoni-gebere.' },
    { n: 36, text: 'Va suka eEsiyoni-gebere, va gwimba emananga ya Zin, ku nga Kadesi.' },
    { n: 37, text: 'Va suka eKadesi, va gwimba eNtshaveni ya Hore, emundzilakanini wa tiko ra Edome.' },
    { n: 38, text: 'Muprisita Aroni a tlhandluka eNtshaveni ya Hore hi ku lerisa ka Yehovha, a fela kona hi lembe ra vumune-khume endzhaku ka loko vana va Israyele va humile etikweni ra Egipta, hi n’hweti ya vuntlhanu, hi siku ro sungula ra n’hweti.' },
    { n: 39, text: 'Aroni a a ri ni malembe ya madzana ni makume mambirhi na nharhu loko a fela eNtshaveni ya Hore.' },
    { n: 40, text: 'Kutani hosi ya Aradi, lowu a a ri Mukanana a tshama hi le dzongeni wa tiko ra Kanana, a twa ku fika ka vana va Israyele.' },
    { n: 41, text: 'Va suka eNtshaveni ya Hore, va gwimba eSalmoma.' },
    { n: 42, text: 'Va suka eSalmoma, va gwimba ePunoni.' },
    { n: 43, text: 'Va suka ePunoni, va gwimba eOboti.' },
    { n: 44, text: 'Va suka eOboti, va gwimba eIye-abarimi, emundzilakanini wa Mowabu.' },
    { n: 45, text: 'Va suka eIyiye, va gwimba eDiboni-gadi.' },
    { n: 46, text: 'Va suka eDiboni-gadi, va gwimba eAlmoni-diblata-yimi.' },
    { n: 47, text: 'Va suka eAlmoni-diblata-yimi, va gwimba etintshaveni ta Abarimi, mahlweni ka Nebo.' },
    { n: 48, text: 'Va suka etintshaveni ta Abarimi, va gwimba emabaleni ya Mowabu ekusuhi ni Yordani ku langutana na Yeriko.' },
    { n: 49, text: 'Va gwimba ekusuhi ni Yordani, ku sukela eBeta-yesimoti ku ya fika eAbela-sitimi, emabaleni ya Mowabu.' },
    { n: 50, text: 'Yehovha a vulavula na Moxe emabaleni ya Mowabu, ekusuhi ni Yordani ku langutana na Yeriko, a ku:' },
    { n: 51, text: '“Vulavula ni vana va Israyele, u ku eka vona: ‘Loko mi hundza Yordani mi nghena etikweni ra Kanana,’”' },
    { n: 52, text: '“‘mi fanele ku hlongola vaaki hinkwavo va tiko mahlweni ka n’wina, mi faya swifaniso swa vona hinkwaswo swa maribye, ni swifaniso swa vona hinkwaswo swa n’simbi leswi n’tshekisiweke, mi lovisa na tindhawu ta vona hinkwato leti tlakukeke;’”' },
    { n: 53, text: '“‘mi ta teka tiko leri, mi tshama endzeni ka rona, hikuva ndzi mi nyikile tiko leri ku va rona ndzhaka ya n’wina.’”' },
    { n: 54, text: '“‘Mi ta avelana tiko hi vuhlolotara hi ku landza mindyangu ya n’wina; eka laba va taleke mi ta va nyika ndzhaka leyikulu, naswona eka laba va nga va tsongo mi ta va nyika ndzhaka leyitsongo; lomu vuhlolotara byi nga ta wela un’wana ni un’wana kona, ku ta va ndzhaka ya yena; mi ta amukela ndzhaka hi ku landza tinyimba ta vata va n’wina.’”' },
    { n: 55, text: '“‘Kambe loko mi nga hlongoli vaaki va tiko mahlweni ka n’wina, vambirhi va lava mi nga ta va siya va ta va ku fana ni mintlhontlho emihlweni ya n’wina ni mitlhari etlhelo ra n’wina, naswona va ta mi xanisa etikweni leri mi nga ta tshama endzeni ka rona.’”' },
    { n: 56, text: '“‘Kutani swi ta endleka leswaku, hilaha a ndzi anakanya ku endla eka vona, ndzi ta endla swona eka n’wina.’”' }
  ],
  34: [
    { n: 1, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 2, text: '“Lerisa vana va Israyele, u ku eka vona: ‘Loko mi nghena etikweni ra Kanana (leri i tiko leri nga ta wela eka n’wina ku va ndzhaka, ku nga tiko ra Kanana hi ku landza mindzilakana ya rona),’”' },
    { n: 3, text: '“‘kutani tlhelo ra n’wina ra le dzongeni ri ta sukela emananga ya Zin ku famba hi tlhelo ra Edome; naswona ndzilakana wa n’wina wa le dzongeni wa le vuxeni wu ta va ku sukela emakumu ya Lwandle ra Munyu;’”' },
    { n: 4, text: '“‘ndzilakana wa n’wina wu ta jika hi le dzongeni wu ya eku tlhandlukeni ka Akrabimi, wu hundza eZin, naswona ku huma ka wona ku ta va hi le dzongeni wa Kadesi-barnea; wu ta ya eHasari-adara, wu hundza eAsmona;’”' },
    { n: 5, text: '“‘ndzilakana wu ta jika ku sukela eAsmona ku ya fika enambyeni wa Egipta, naswona ku huma ka wona ku ta va eLwandleni.’”' },
    { n: 6, text: '“‘Kasi ndzilakana wa n’wina wa le vupela-dyambu, mi ta va ni Lwandle Lwentshwa ni ndzilakana wa rona; lowu wu ta va ndzilakana wa n’wina wa le vupela-dyambu.’”' },
    { n: 7, text: '“‘Naswona lowu wu ta va ndzilakana wa n’wina wa le n’walungwini: ku sukela eLwandleni Lwentshwa mi ta tikhonza ndzilakana ku ya fika eNtshaveni ya Hore;’”' },
    { n: 8, text: '“‘ku sukela eNtshaveni ya Hore mi ta tikhonza ndzilakana ku ya fika eku ngheneni ka Hamati; naswona ku huma ka ndzilakana ku ta va eSedada;’”' },
    { n: 9, text: '“‘ndzilakana wu ta ya eSifroni, naswona ku huma ka wona ku ta va eHasari-enani; lowu wu ta va ndzilakana wa n’wina wa le n’walungwini.’”' },
    { n: 10, text: '“‘Kasi ndzilakana wa n’wina wa le vuxeni mi ta tikhonza wona ku sukela eHasari-enani ku ya eSefama;’”' },
    { n: 11, text: '“‘ndzilakana wu ta xika ku sukela eSefama ku ya eRibla, hi le vuxeni bya Ayini; ndzilakana wu ta xika wu fika etlhelo ra lwandle ra Kinereti hi le vuxeni;’”' },
    { n: 12, text: '“‘ndzilakana wu ta xika ku ya fika eyordani, naswona ku huma ka wona ku ta va eLwandleni ra Munyu; leri ri ta va tiko ra n’wina hi ku landza mindzilakana ya rona hinkwayo hinkwako.’”' },
    { n: 13, text: 'Moxe a lerisa vana va Israyele, a ku: “Leri i tiko leri mi nga ta ri teka ku va ndzhaka hi vuhlolotara, leri Yehovha a leriseke ku nyika tinyimba ta kume-nharhu ni hafu ya nyimba;”' },
    { n: 14, text: '“hikuva nyimba ya vana va Ruben hi ku landza tiyindlu ta vata va vona, ni nyimba ya vana va Gadi hi ku landza tiyindlu ta vata va vona, va amukele ndzhaka ya vona; na hafu ya nyimba ya Manase yi amukele ndzhaka ya yona;”' },
    { n: 15, text: '“tinyimba leti mambirhi ni hafu ya nyimba va amukele ndzhaka ya vona entsungeni wa Jordani ekusuhi ni Yeriko hi le vuxeni, eku humeni ka dyambu.”' },
    { n: 16, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 17, text: '“Mavito ya vavanuna lava nga ta mi avela tiko ku va ndzhaka hi lawa: muprisita Eliyazara, na Yoxuwa n’wana wa Nuni.”' },
    { n: 18, text: '“Naswona mi ta teka ndhuna yin’we eka nyimba yin’wana ni yin’wana, ku avelana tiko ku va ndzhaka.”' },
    { n: 19, text: '“Mavito ya vavanuna hi lawa: eka nyimba ya Yuda: i Kalebe n’wana wa Yefune;”' },
    { n: 20, text: '“eka nyimba ya vana va Simiyoni: i Semuele n’wana wa Amihudu;”' },
    { n: 21, text: '“eka nyimba ya Benjamini: i Elidade n’wana wa Kisloni;”' },
    { n: 22, text: '“eka nyimba ya vana va Dani, ndhuna: i Buki n’wana wa Yogli;”' },
    { n: 23, text: '“eka vana va Yosefa: eka nyimba ya vana va Manase, ndhuna: i Haniyela n’wana wa Efodi;”' },
    { n: 24, text: '“eka nyimba ya vana va Efraimi, ndhuna: i Kemuele n’wana wa Siftani;”' },
    { n: 25, text: '“eka nyimba ya vana va Zebuloni, ndhuna: i Elisafani n’wana wa Parnaki;”' },
    { n: 26, text: '“eka nyimba ya vana va Isakara, ndhuna: i Paltiyela n’wana wa Azana;”' },
    { n: 27, text: '“eka nyimba ya vana va Axere, ndhuna: i Ahihudu n’wana wa Selomi;”' },
    { n: 28, text: '“eka nyimba ya vana va Neftali, ndhuna: i Pedahile n’wana wa Amihudu.”' },
    { n: 29, text: 'Lava hi vona lava Yehovha a va leriseke ku avela vana va Israyele ndzhaka etikweni ra Kanana.' }
  ],
  35: [
    { n: 1, text: 'Yehovha a vulavula na Moxe emabaleni ya Mowabu, ekusuhi ni Yordani ku langutana na Yeriko, a ku:' },
    { n: 2, text: '“Lerisa vana va Israyele leswaku, eka ndzhaka ya ku tekiwa ka vona, va nyika Valevhi miti yo tshama endzeni ka yona; naswona mi ta nyika Valevhi ni madyelo ya miti leyi rhendzeleke miti hinkwayo.”' },
    { n: 3, text: '“Miti yi ta va ya vona leswaku va tshama endzeni ka yona; kasi madyelo ya yona ya ta va ya swifuwo swa vona, ni ya swilaveko swa vona, ni ya swiharhi swa vona hinkwaswo.”' },
    { n: 4, text: '“Madyelo ya miti, lawa mi nga ta va nyika wona Valevhi, ya ta sukela emakhubyini ya muti ku famba hi le handle ku ringana gidi ra tixekele ku rhendzela hinkwako.”' },
    { n: 5, text: '“Mi ta pima hi le handle ka muti tlhelo ra le vuxeni gidi mambirhi ya tixekele, ni tlhelo ra le dzongeni gidi mambirhi ya tixekele, ni tlhelo ra le vupela-dyambu gidi mambirhi ya tixekele, ni tlhelo ra le n’walungwini gidi mambirhi ya tixekele, muti wu ri exikarhi; lawa ya ta va madyelo ya miti ya vona.”' },
    { n: 6, text: '“Exikarhi ka miti leyi mi nga ta nyika wona Valevhi, ku ta va ni miti ya ntlhanu-xin’we ya ku tumbela, leyi mi nga ta yi veka leswaku mudlayi a nga tumbela endzeni ka yona; naswona ehenhla ka yona mi ta engetela miti ya makume mune ni mambirhi.”' },
    { n: 7, text: '“Miti hinkwayo leyi mi nga ta yi nyika Valevhi yi ta va makume mune na nharhu, yona xikan’we ni madyelo ya yona.”' },
    { n: 8, text: '“Kasi miti leyi mi nga ta yi nyika ku sukela eka leswi tekiweke swa vana va Israyele: eka lowu nga ni swo tala mi ta teka swo tala, kasi eka lowu nga ni switsongo mi ta teka switsongo; un’wana ni un’wana u ta nyika Valevhi miti ya yena hi ku landza ndzhaka ya yena leyi a yi amukeleke.”' },
    { n: 9, text: 'Yehovha a vulavula na Moxe, a ku:' },
    { n: 10, text: '“Vulavula ni vana va Israyele, u ku eka vona: ‘Loko mi hundza Yordani mi nghena etikweni ra Kanana,’”' },
    { n: 11, text: '“‘mi ta tihlawulela miti leyi nga ta va miti ya n’wina ya ku tumbela, leswaku mudlayi loyi a dlayeke munhu hi xihoxo a nga balekela kona.’”' },
    { n: 12, text: '“‘Miti leyi yi ta va xitumbelo eka n’wina eka mukhutisi wa ku rihisela, leswaku mudlayi a nga fi ku fika lomu a yimaka mahlweni ka nhlengeletano ku avanyisiwa.’”' },
    { n: 13, text: '“‘Kasi miti leyi mi nga ta yi nyika, ku ta va miti ya ntlhanu-xin’we ya ku tumbela.’”' },
    { n: 14, text: '“‘Mi ta nyika miti ya nharhu entsungeni wa Jordani, ni miti ya nharhu mi ta yi nyika etikweni ra Kanana; yi ta va miti ya ku tumbela.’”' },
    { n: 15, text: '“‘Miti leyi ya ntlhanu-xin’we yi ta va xitumbelo eka vana va Israyele, ni le ka muhluri, ni le ka mupfhumba loyi a tshamaka exikarhi ka vona, leswaku un’wana ni un’wana loyi a dlayeke munhu hi xihoxo a nga balekela kona.’”' },
    { n: 16, text: '“‘Kambe loko a n’wi tlhava hi xibya xa ntsimbi lerova a fa, i mudlayi; mudlayi yoloye u fanele ku dlayiwa hakunene.’”' },
    { n: 17, text: '“‘Loko a n’wi tlhava hi ribye leri nga evokweni leri nga n’wi dlayaka lerova a fa, i mudlayi; mudlayi yoloye u fanele ku dlayiwa hakunene.’”' },
    { n: 18, text: '“‘Kumbe loko a n’wi tlhava hi xibya xa ntsandza leri nga evokweni leri nga n’wi dlayaka lerova a fa, i mudlayi; mudlayi yoloye u fanele ku dlayiwa hakunene.’”' },
    { n: 19, text: '“‘Mukhutisi wa ngati hi yena a nga ta dlaya mudlayi; loko a hlangana na yena, u ta n’wi dlaya.’”' },
    { n: 20, text: '“‘Kambe loko a n’wi susumeta hi rivengo, kumbe a n’wi hoxela nchumu hi ku tlhantlheka lerova a fa;’”' },
    { n: 21, text: '“‘kumbe a n’wi tlhava hi voko ra yena hi vulala lerova a fa; loyi a tlhaveke u fanele ku dlayiwa hakunene, hikuva i mudlayi; mukhutisi wa ngati u ta dlaya mudlayi loko a hlangana na yena.’”' },
    { n: 22, text: '“‘Kambe loko a n’wi susumeta hi xitshuketa ku nga ri hi vulala, kumbe a n’wi hoxela nchumu un’wana ni un’wana ku nga ri hi ku tlhantlheka;’”' },
    { n: 23, text: '“‘kumbe hi ribye rin’wana ni rin’wana leri nga n’wi dlayaka, a nga n’wi vonanga, ri wela ehenhla ka yena lerova a fa, kasi a a nga ri nala wa yena naswona a a nga lavi ku n’wi endla swo biha;’”' },
    { n: 24, text: '“‘kutani nhlengeletano yi ta avanyisa exikarhi ka loyi a tlhaveke ni mukhutisi wa ngati hi ku landza milawu leyi;’”' },
    { n: 25, text: '“‘nhlengeletano yi ta ponisa mudlayi evokweni ra mukhutisi wa ngati, naswona nhlengeletano yi ta n’wi vuyisela emutini wa yena wa ku tumbela lomu a balekeleke kona; u ta tshama endzeni ka wona ku fika eku feni ka muprisita lonkulu, loyi a totiweke hi mafurha yo kwetsima.’”' },
    { n: 26, text: '“‘Kambe loko mudlayi o tshuka a huma ehandle ka ndzilakana wa muti wa yena wa ku tumbela, lomu a balekeleke kona;’”' },
    { n: 27, text: '“‘naswona mukhutisi wa ngati a n’wi kuma ehandle ka ndzilakana wa muti wa yena wa ku tumbela, kutani mukhutisi wa ngati a dlaya mudlayi yoloye, mukhutisi a nga nga vi na nandzu wa ngati;’”' },
    { n: 28, text: '“‘hikuva mudlayi a a fanele ku tshama emutini wa yena wa ku tumbela ku fika eku feni ka muprisita lonkulu; kambe endzhaku ka ku fa ka muprisita lonkulu, mudlayi a nga tlhela etikweni ra ndzhaka ya yena.’”' },
    { n: 29, text: '“‘Swilo leswi swi ta va xileriso xa nawu eka n’wina ematikweni hinkwako ya n’wina, emixaxeni ya n’wina hinkwayo.’”' },
    { n: 30, text: '“‘Un’wana ni un’wana loyi a dlayaka munhu, mudlayi u ta dlayiwa hi ku landza vumbhoni bya timbhoni; kambe vumbhoni bya mbhoni yin’we a byi nga pfumeleriwi ku dlaya munhu.’”' },
    { n: 31, text: '“‘Naswona mi nga tshuki mi amukela nkutsulo hikwalaho ka vutomi bya mudlayi loyi a nga ni nandzu wa ku dlayiwa; hikuva u fanele ku dlayiwa hakunene.’”' },
    { n: 32, text: '“‘Naswona mi nga tshuki mi amukela nkutsulo eka loyi a balekeleke emutini wa yena wa ku tumbela, leswaku a tlhela a tshama etikweni mahlweni ka ku fa ka muprisita.’”' },
    { n: 33, text: '“‘Mi nga tshuki mi nyamisa tiko leri mi nga endzeni ka rona; hikuva ngati yi nyamisa tiko, naswona ku hava ku rivaleriwa leri nga endliwaka eka tiko hikwalaho ka ngati leyi chuluriweke endzeni ka rona, handle ka hi ngati ya loyi a yi chululeke.’”' },
    { n: 34, text: '“‘Mi nga tshuki mi nyamisa tiko leri mi tshamaka endzeni ka rona, lomu ndzi tshamaka kona; hikuva mina Yehovha ndzi tshama exikarhi ka vana va Israyele.’”' }
  ],
  36: [
    { n: 1, text: 'Kuni tinhloko ta mindyangu ta ndyangu wa vana va Giliyadi, n’wana wa Makiri, n’wana wa Manase, wa mindyangu ya vana va Yosefa, ti tshinela, ti vulavula mahlweni ka Moxe ni mahlweni ka tindhuna, tinhloko ta vata va vana va Israyele;' },
    { n: 2, text: 'va ku: “Yehovha u lerise n’winyi wa mina ku nyika tiko ku va ndzhaka hi vuhlolotara eka vana va Israyele; naswona n’winyi wa mina u lerisiwe hi Yehovha ku nyika ndzhaka ya Selofehadi makwerhu eka vana va yena va vanhwanyana.”' },
    { n: 3, text: '“Loko o kala va tekiwa hi un’we wa vana va tinyimba tin’wana ta vana va Israyele, kutani ndzhaka ya vona yi ta tekiwa eka ndzhaka ya vata va hina, yi engeteriwa eka ndzhaka ya nyimba leyi va nga ta wela eka yona; kutani yi ta tekiwa eka ndzhaka ya vuhlolotara bya hina.”' },
    { n: 4, text: '“Naswona loko ku fika Jubilele wa vana va Israyele, kutani ndzhaka ya vona yi ta engeteriwa eka ndzhaka ya nyimba leyi va nga ta wela eka yona; kutani ndzhaka ya vona yi ta tekiwa eka ndzhaka ya nyimba ya vata va hina.”' },
    { n: 5, text: 'Moxe a lerisa vana va Israyele hi ku landza rito ra Yehovha, a ku: “Nyimba ya vana va Yosefa yi vulavula ntiyiso.”' },
    { n: 6, text: '“Leyi i mhaka leyi Yehovha a yi leriseke eka vana va vanhwanyana va Selofehadi, a ku: ‘Va nga tekiwa hi loyi a rhandzekaka emihlweni ya vona; ntsena va fanele ku tekiwa endzeni ka ndyangu wa nyimba ya tata va vona.’”' },
    { n: 7, text: '“‘Leswaku ndzhaka ya vana va Israyele yi nga hundzi ku sukela eka nyimba yin’wana ku ya eka nyimba yin’wana; hikuva un’wana ni un’wana wa vana va Israyele u ta namarhela ndzhaka ya nyimba ya vata va yena.’”' },
    { n: 8, text: '“‘Naswona n’wana un’wana ni un’wana wa wanhwanyana, loyi a nga ni ndzhaka eka nyimba yin’wana ni yin’wana ya vana va Israyele, u fanele ku tekiwa hi un’we wa ndyangu wa nyimba ya tata wa yena, leswaku vana va Israyele va nga dya un’wana ni un’wana ndzhaka ya vata va yena.’”' },
    { n: 9, text: '“‘Kasi ndzhaka yi nga tshuki yi hundza ku sukela eka nyimba yin’wana ku ya eka nyimba yin’wana; hikuva tinyimba ta vana va Israyele un’wana ni un’wana u ta namarhela ndzhaka ya yena n’winyi.’”' },
    { n: 10, text: 'Vana va vanhwanyana va Selofehadi va endla hilaha Yehovha a n’wi leriseke hakona Moxe;' },
    { n: 11, text: 'hikuva Mahela, Tirsa, Hogila, Milka na Nowa, vana va vanhwanyana va Selofehadi, va tekiwa hi vana va vamakwavo va tata va vona.' },
    { n: 12, text: 'Va tekiwa endzeni ka mindyangu ya vana va Manase, n’wana wa Yosefa; naswona ndzhaka ya vona yi sala eka nyimba ya ndyangu wa tata va vona.' },
    { n: 13, text: 'Lawa i swileriso ni swiboho leswi Yehovha a swi leriseke hi voko ra Moxe eka vana va Israyele, emabaleni ya Mowabu, ekusuhi ni Yordani ku langutana na Yeriko.' }
  ]
};
